window.MINNA_LESSONS = [{"l":1,"t":"N₁ といえば、N₂","de":"Apropos N₁ — typischerweise denkt man an N₂","slots":[{"text":"N₁","role":"obj","label":"Stichwort"},{"text":"といえば、","role":"actor","label":"apropos"},{"text":"N₂","role":"subj","label":"Assoziation"},{"text":"だ/です","role":"plain"}],"gloss":"»Wenn man N₁ sagt, denkt man an N₂.« — nennt das, was einem zu einem Thema sofort einfällt (allgemein bekannt). Auch: というと / といったら.","ex":{"jp":"<ruby>京都<rt>きょうと</rt></ruby><b>といえば</b>、お<ruby>寺<rt>てら</rt></ruby>ですね。","de":"Apropos Kyoto — Tempel, oder?"},"simpel":"Greift ein Stichwort auf und nennt die typische Assoziation dazu — einfach <b>といえば</b> ans Nomen hängen.<br><span class=\"jp\"><ruby>京都<rt>きょうと</rt></ruby>といえば、お<ruby>寺<rt>てら</rt></ruby></span> = „Apropos Kyoto — Tempel“","rule":"Drückt eine typische, geteilte Assoziation aus. Sprecher A nennt N₁ als Stichwort, und N₂ ist das, was den meisten Menschen dazu sofort einfällt. Sehr häufige Konversationseröffnung — »wenn von X die Rede ist, dann …«."},{"l":1,"t":"<ruby>数量<rt>すうりょう</rt></ruby> + も (überraschende Menge)","de":"sogar / ganze … (Menge ist erstaunlich groß)","slots":[{"text":"Subjekt は/が","role":"subj"},{"text":"<ruby>数量<rt>すうりょう</rt></ruby>","role":"time","label":"Zahl + Zähler"},{"text":"も","role":"actor","label":"sogar"},{"text":"V","role":"verb"}],"gloss":"»sogar/ganze … viel.« — der Sprecher findet die Menge erstaunlich groß. Muster: 数量 + も + V (z. B. 5回も). Gegenteil: しか + Vない (zu wenig).","ex":{"jp":"<ruby>毎朝<rt>まいあさ</rt></ruby> 2<ruby>時間<rt>じかん</rt></ruby><b>も</b> <ruby>電車<rt>でんしゃ</rt></ruby>に <ruby>乗<rt>の</rt></ruby>って います。","de":"Ich fahre jeden Morgen ganze 2 Stunden Bahn."},"simpel":"<b>も</b> hinter eine Mengenangabe heißt »so viel!« — Überraschung über eine große Menge.<br><span class=\"jp\">3<ruby>時間<rt>じかん</rt></ruby>も <ruby>待<rt>ま</rt></ruby>った</span> = „Ich habe ganze 3 Stunden gewartet“","rule":"も nach einer Zahlenangabe drückt aus, dass die Menge den Sprecher überrascht — »so viel/lang/oft!«. Hervorhebend, oft mit emotionalem Unterton (beeindruckt oder genervt). NICHT zu verwechseln mit dem も als »auch«."},{"l":1,"t":"N は 〜こと、〜こと(だ)","de":"X besteht aus: erstens …, zweitens … (Aufzählung)","slots":[{"text":"<ruby>大切<rt>たいせつ</rt></ruby>なのは、","role":"subj","label":"Wichtig ist:"},{"text":"[Inhalt 1]","role":"cond"},{"text":"こと、","role":"actor","label":"Punkt 1"},{"text":"[Inhalt 2]","role":"cond"},{"text":"ことだ","role":"plain","label":"Punkt 2 (Ende)"}],"gloss":"»Wichtig ist: erstens …, zweitens …« — zählt Punkte auf, je こと dahinter, am Ende こと + だ/です. Nach Verb (辞書形/ない形) und Adjektiv (い-Adj + こと, な-Adj + な + こと).","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>のために <ruby>大切<rt>たいせつ</rt></ruby>なのは、<ruby>食事<rt>しょくじ</rt></ruby>に <ruby>気<rt>き</rt></ruby>を つける<b>こと</b>、<ruby>運動<rt>うんどう</rt></ruby>する<b>ことだ</b>。","de":"Für die Gesundheit ist wichtig: auf die Ernährung achten und Sport treiben."},"simpel":"<b>こと</b> macht Sätze zu zählbaren Punkten zum Aufzählen — der letzte Punkt bekommt <b>だ/です</b>.<br><span class=\"jp\"><ruby>大切<rt>たいせつ</rt></ruby>なのは、あきらめない<b>ことだ</b></span> = „Wichtig ist, nicht aufzugeben“","rule":"こと nominalisiert ganze Sätze zu zählbaren »Punkten«. Sehr nützlich, um Definitionen zu geben oder Punkte aufzulisten — typisch für Essays und formelle Erklärungen. Der letzte こと-Punkt bekommt だ/です."},{"l":1,"t":"Vマス-Stamm + <ruby>始<rt>はじ</rt></ruby>める / <ruby>終<rt>お</rt></ruby>わる","de":"anfangen zu V / fertig sein mit V","slots":[{"text":"Subjekt は/が","role":"subj"},{"text":"(Objekt を)","role":"obj"},{"text":"V-マス-Stamm","role":"verb","label":"Hauptverb"},{"text":"<ruby>始<rt>はじ</rt></ruby>めた / <ruby>終<rt>お</rt></ruby>わった","role":"actor","label":"Aspekt"}],"gloss":"»fängt an / hört auf zu V.« — Aspekt-Wort hängt am ます-Stamm: 始める (anfangen), 終わる (fertig werden). Unregelmäßig: 来始める, し始める.","ex":{"jp":"<ruby>赤<rt>あか</rt></ruby>ちゃんが <ruby>歩<rt>ある</rt></ruby>き<b><ruby>始<rt>はじ</rt></ruby>めた</b>。","de":"Das Baby hat angefangen zu laufen."},"simpel":"ます-Stamm + <b><ruby>始<rt>はじ</rt></ruby>める</b> (anfangen) oder <b><ruby>終<rt>お</rt></ruby>わる</b> (fertig sein) — klebt direkt am Stamm.<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べ<ruby>始<rt>はじ</rt></ruby>める</span> = „anfangen zu essen“","rule":"Zwei Hilfsverben, die den <b>Aspekt</b> einer Handlung markieren: 始める (anfangen) oder 終わる (zu Ende kommen). Sie hängen direkt an den ます-Stamm des Hauptverbs — wie ein Wort zusammenwachsen."},{"l":2,"t":"〜のでしょうか","de":"wohl …? / dürfte es wohl …? (höfliche Vermutungsfrage)","slots":[{"text":"Inhalt","role":"verb","label":"in Plain-Form"},{"text":"(な)","role":"plain","label":"nur bei N/な-Adj"},{"text":"のでしょうか","role":"actor","label":"wohl?"}],"gloss":"»Ist das wohl …?« — höfliche, vorsichtige Nachfrage. Muster: 普通形 + のでしょうか (な-Adj/N + な + のでしょうか). Direkter wäre nur ですか.","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は どこへ <ruby>行<rt>い</rt></ruby>った<b>のでしょうか</b>。","de":"Wohin ist er wohl gegangen?"},"simpel":"Höfliche, vorsichtige Frage »wohl …?«. <b>のでしょうか</b> ans Plain-Verb hängen (N/な-Adj: + な).<br><span class=\"jp\"><ruby>彼<rt>かれ</rt></ruby>は <ruby>来<rt>こ</rt></ruby>ない<b>のでしょうか</b></span> = „Ob er wohl nicht kommt?“","rule":"Höfliche, vorsichtige Frage: Der Sprecher fragt nicht direkt, sondern tastend — »könnte es wohl sein, dass …?«. Kombination aus の (Erklärungs-Nominalisierer) + でしょう (Vermutung, Minna L32) + か (Fragepartikel). Klingt deutlich weicher und höflicher als ein einfaches ですか."},{"l":2,"t":"<ruby>自動詞<rt>じどうし</rt></ruby> ⇆ <ruby>他動詞<rt>たどうし</rt></ruby> (Vertiefung)","de":"Verbpaare: »passiert von selbst« ↔ »jemand macht es«","slots":[[{"text":"N が","role":"subj","label":"Subjekt"},{"text":"V<sub>自</sub>","role":"verb","label":"passiert von selbst"}],[{"text":"Person が","role":"actor","label":"Handelnder"},{"text":"N を","role":"obj","label":"Objekt"},{"text":"V<sub>他</sub>","role":"verb","label":"macht es aktiv"}]],"gloss":"»passiert von selbst« (自動詞: N が V) ↔ »jemand macht es« (他動詞: Person が N を V). Paare wie 集まる/集める, 決まる/決める, 変わる/変える.","ex":{"jp":"<ruby>人口<rt>じんこう</rt></ruby><b>が</b> <ruby>増<rt>ふ</rt></ruby>えて います。","de":"Die Bevölkerung nimmt zu. [自]"},"simpel":"Zwei Verben für eine Aktion: <b>自動詞</b> (が, passiert von selbst) ↔ <b>他動詞</b> (を, jemand macht es).<br><span class=\"jp\">ドアが <ruby>開<rt>あ</rt></ruby>く / ドアを <ruby>開<rt>あ</rt></ruby>ける</span> = „Tür geht auf / Tür öffnen“","rule":"Japanisch hat oft <b>zwei Verben</b> für dieselbe Aktion: ein <b>intransitives</b> (自動詞) für »passiert von selbst« und ein <b>transitives</b> (他動詞) für »jemand macht es aktiv«. Davon hängen Partikel (が vs. を) und Bedeutung von ている / てある ab. Wiederholung und Erweiterung von Minna L29 mit neuen Chuukyuu-Paaren."},{"l":2,"t":"V<sub>(よ)う</sub> + としても、〜ない","de":"auch wenn ich versuche zu V — es klappt nicht","slots":[{"text":"V-<ruby>意向<rt>いこう</rt></ruby>形","role":"verb","label":"ich will V"},{"text":"としても、","role":"actor","label":"auch wenn versucht"},{"text":"V-ない / V-れない","role":"verb","label":"klappt nicht"}],"gloss":"»Auch wenn ich versuche zu V, klappt es nicht.« — der Wille ist da, das Ergebnis nicht. Muster: V意向形 + としても、〜ない (z. B. 食べよう, しよう, 来よう).","ex":{"jp":"<ruby>忘<rt>わす</rt></ruby>れ<b>ようとしても</b>、<ruby>忘<rt>わす</rt></ruby>れられない。","de":"Auch wenn ich es vergessen will, kann ich es nicht."},"simpel":"Volitional-Form + <b>としても</b> + Verneinung: »auch wenn ich es versuche — es klappt nicht«.<br><span class=\"jp\"><ruby>忘<rt>わす</rt></ruby>れ<b>ようとしても</b>、<ruby>忘<rt>わす</rt></ruby>れられない</span> = „So sehr ich will, ich kann es nicht vergessen“","rule":"Konzessiv-Konstruktion: Der Wille zu handeln ist da, aber die Handlung scheitert oder ist sinnlos. Bildung: <b>Volitional-Form</b> (V意向形, »ich will V tun«) + としても + Verneinung/Schwierigkeit."},{"l":2,"t":"〜のは 〜 だ (Hervorhebung)","de":"Was/wer/wann … — das ist Y","slots":[{"text":"[Sachverhalt in V-Plain]","role":"verb","label":"Aktion"},{"text":"のは","role":"actor"},{"text":"[Hervorgehobenes]","role":"obj","label":"Person/Zeit/Ort"},{"text":"だ/です","role":"plain"}],"gloss":"»Das, was [Aktion], ist Y.« — schiebt die wichtige Info ans Satzende. Muster: V普通形 + のは + [Person/Sache/Zeit/Ort] + だ.","ex":{"jp":"この <ruby>絵<rt>え</rt></ruby>を <ruby>描<rt>か</rt></ruby>いた<b>のは</b> <ruby>子供<rt>こども</rt></ruby><b>だ</b>。","de":"Wer dieses Bild gemalt hat, war ein Kind."},"simpel":"Spaltsatz: das Wichtige (wer/was/wann) rückt mit <b>のは … だ</b> ans Ende und wird betont.<br><span class=\"jp\">この <ruby>絵<rt>え</rt></ruby>を <ruby>描<rt>か</rt></ruby>いた<b>のは</b> <ruby>子供<rt>こども</rt></ruby><b>だ</b></span> = „Wer das gemalt hat, war ein Kind“","rule":"Spaltsatz-Konstruktion (»cleft sentence«): Ein Teil des Satzes wird durch <code>のは … だ</code> ans Ende gerückt und dadurch hervorgehoben. Beantwortet implizit eine Frage: »Wer war's? Was genau? Wann eigentlich?«"},{"l":2,"t":"ている / てある / ておく — Überblick","de":"Zustand (passiv) ↔ vorbereitet (absichtlich) ↔ vorbereiten (aktiv)","slots":[[{"text":"N が","role":"subj"},{"text":"V<sub>自</sub>-て いる","role":"verb","label":"Zustand"}],[{"text":"N が","role":"subj"},{"text":"V<sub>他</sub>-て ある","role":"verb","label":"absichtlich vorbereitet"}],[{"text":"<ruby>私<rt>わたし</rt></ruby> が","role":"actor"},{"text":"N を","role":"obj"},{"text":"V-て おく","role":"verb","label":"ich bereite vor"}]],"gloss":"ている = »ist gerade im Zustand X«. てある = »wurde absichtlich gemacht und ist noch so« (Vテ + ある). ておく = »mache es jetzt, damit es später erledigt ist« (gespr. 〜とく).","ex":{"jp":"<ruby>窓<rt>まど</rt></ruby>が <ruby>開<rt>あ</rt></ruby>いて <b>います</b>。","de":"Das Fenster ist offen. [ている — Zustand]"},"simpel":"<b>ている</b> = Zustand, <b>てある</b> = absichtlich vorbereitet (sichtbar), <b>ておく</b> = vorsorglich erledigen.<br><span class=\"jp\"><ruby>窓<rt>まど</rt></ruby>が <ruby>開<rt>あ</rt></ruby>いて いる / <ruby>開<rt>あ</rt></ruby>けて ある</span> = „Fenster ist offen / wurde geöffnet“","rule":"Drei Konstruktionen mit て-Form, die ständig verwechselt werden. <b>ている</b> = Zustand oder Andauer (oft mit 自動詞). <b>てある</b> = Resultat einer absichtlichen Handlung, das noch sichtbar ist (nur mit 他動詞). <b>ておく</b> = ich bereite jetzt aktiv etwas für später vor."},{"l":3,"t":"〜<ruby>普通形<rt>ふつうけい</rt></ruby> + ような N","de":"ein N, wie es … ist / so eines, das …","slots":[{"text":"Vergleichs-Inhalt","role":"cond","label":"wie was?"},{"text":"(の/な)","role":"plain","label":"je nach Wortart"},{"text":"ような","role":"actor","label":"so beschaffen"},{"text":"N","role":"obj","label":"Nomen"}],"gloss":"»ein N, das so ist wie [Inhalt].« — verknüpft einen Vergleich mit einem Nomen. Muster: V/い-Adj + ような + N (な-Adj + な, N + の + ような).","ex":{"jp":"<ruby>夢<rt>ゆめ</rt></ruby><b>のような</b> <ruby>話<rt>はなし</rt></ruby>だ。","de":"Das ist eine Geschichte wie aus einem Traum."},"simpel":"<b>ような</b> verbindet eine Beschreibung attributiv mit einem Nomen — »ein N, das so ist wie …«.<br><span class=\"jp\"><ruby>夢<rt>ゆめ</rt></ruby>のような <ruby>話<rt>はなし</rt></ruby></span> = „eine Geschichte wie aus einem Traum“","rule":"<code>ような</code> verbindet einen Satz attributiv mit einem Nomen — »ein N, das so beschaffen ist wie …«. Der Vergleich/die Beschreibung steht vor <code>ような</code>, das beschriebene Nomen dahinter."},{"l":3,"t":"N のよう / のような / のように","de":"wie ein N (3 Positionen: Prädikat / Attribut / Adverb)","slots":[[{"text":"〜は N の","role":"obj"},{"text":"ようだ","role":"verb","label":"① Prädikat"}],[{"text":"N の","role":"obj"},{"text":"ような","role":"actor"},{"text":"N₂","role":"subj","label":"② Attribut"}],[{"text":"N の","role":"obj"},{"text":"ように","role":"actor"},{"text":"V","role":"verb","label":"③ Adverb"}]],"gloss":"»wie ein N.« — derselbe Vergleich an drei Stellen: のようだ am Satzende, のような vor Nomen, のように vor Verb. Auch mit Verben (V普通形 + ようだ).","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は <ruby>子<rt>こ</rt></ruby>ども<b>のようだ</b>。","de":"Er ist wie ein Kind. [① Prädikat]"},"simpel":"Ein Vergleich, drei Positionen: <b>ようだ</b> am Satzende, <b>ような</b> vor Nomen, <b>ように</b> vor Verb.<br><span class=\"jp\"><ruby>子<rt>こ</rt></ruby>どものように <ruby>笑<rt>わら</rt></ruby>う</span> = „lachen wie ein Kind“","rule":"Drei Formen für denselben Vergleich — die <b>Position im Satz</b> bestimmt die Form: am <b>Satzende</b> als Prädikat (ようだ), vor einem <b>Nomen</b> als Attribut (ような), vor einem <b>Verb</b> als Adverb (ように)."},{"l":3,"t":"N ばかり / V<sub>テ</sub> ばかり いる","de":"immer nur N / immer nur V-en (kritisch)","slots":[{"text":"Subjekt は","role":"subj"},{"text":"N / V-て","role":"verb","label":"das eine"},{"text":"ばかり","role":"actor","label":"immer nur"},{"text":"いる / だ","role":"plain"}],"gloss":"»immer nur N / immer nur V-en.« — kritisch-bedauernd, nichts anderes. Muster: N + ばかり, Vテ + ばかり + いる. (だけ ist neutral, しか〜ない = zu wenig.)","ex":{"jp":"<ruby>息子<rt>むすこ</rt></ruby>は ゲームを して<b>ばかりいる</b>。","de":"Mein Sohn spielt immer nur Videospiele."},"simpel":"<b>ばかり</b> = »immer nur das« mit kritischem Ton. Bei Verb: <b>V-て + ばかり + いる</b>.<br><span class=\"jp\">ゲームを して<b>ばかり いる</b></span> = „spielt immer nur Videospiele“","rule":"<code>ばかり</code> = einschränkend mit <b>negativem</b> oder bedauerndem Unterton: »immer nur das, nichts anderes«. Bei Nomen: direkt dranhängen. Bei Verben: <code>V-て + ばかり + いる</code>. Klingt häufig wie eine Beschwerde."},{"l":3,"t":"N を <ruby>欲<rt>ほ</rt></ruby>しがる / Vマス-Stamm + たがる","de":"jemand anders möchte … (Wunsch dritter Personen)","slots":[{"text":"Andere Person は/が","role":"actor","label":"er/sie (nicht ich)"},{"text":"N を / V-Stamm","role":"obj"},{"text":"<ruby>欲<rt>ほ</rt></ruby>しがって いる / たがって いる","role":"verb","label":"möchte (3. Person)"}],"gloss":"»jemand anders möchte …« — fremder Wunsch, daher meist mit ています. N を 欲しがっている (will N), Vマス-Stamm + たがっている (möchte V-en). Ich selbst: 欲しい / たい.","ex":{"jp":"<ruby>子<rt>こ</rt></ruby>どもたちが おもちゃ<b>を</b> <ruby>欲<rt>ほ</rt></ruby>しがって います。","de":"Die Kinder wollen Spielzeug haben."},"simpel":"Wünsche <b>anderer</b> Personen: <b>欲しがる</b> (N を) / V-Stamm + <b>たがる</b> — meist mit ている.<br><span class=\"jp\"><ruby>子<rt>こ</rt></ruby>どもが おもちゃを <ruby>欲<rt>ほ</rt></ruby>しがって いる</span> = „Das Kind will Spielzeug“","rule":"Ein eigener Wunsch heißt <code><ruby>欲<rt>ほ</rt></ruby>しい / 〜たい</code>. Bei Wünschen <b>anderer Personen</b> muss man dagegen <code><ruby>欲<rt>ほ</rt></ruby>しがる / 〜たがる</code> nutzen — Japanisch unterscheidet streng, weil man fremde Gefühle nur von außen beobachten kann."},{"l":3,"t":"つい + Vテ しまう","de":"aus Versehen / wider Willen / habe es leider doch getan","slots":[{"text":"つい (ついつい)","role":"time","label":"unbeabsichtigt"},{"text":"V-て","role":"verb"},{"text":"しまった","role":"actor","label":"leider passiert"}],"gloss":"»Habe leider doch X getan.« — aus Versehen, ohne es zu wollen, mit Reue. Muster: つい + Vテ + しまう/しまった (gespr. 〜ちゃった). Gegenteil: わざと (absichtlich).","ex":{"jp":"<ruby>食<rt>た</rt></ruby>べないつもりだったのに、<b>つい</b> <ruby>食<rt>た</rt></ruby>べて しまった。","de":"Eigentlich wollte ich nicht essen — habe es aber doch getan."},"simpel":"<b>つい</b> + <b>てしまう</b>: »ich wollte eigentlich nicht — ist aber leider doch passiert«.<br><span class=\"jp\"><b>つい</b> <ruby>食<rt>た</rt></ruby>べて <b>しまった</b></span> = „Ich hab's leider doch gegessen“","rule":"<code>つい</code> = unwillentlich, ungewollt, dem Impuls nachgegeben. Sehr oft kombiniert mit <code>てしまう</code> (Minna L29 — »leider passiert, vollendet«). Ergebnis: »Ich wollte eigentlich nicht — aber es ist trotzdem passiert.«"},{"l":3,"t":"〜のは 〜 からだ","de":"Der Grund, warum X passiert, ist Y","slots":[{"text":"[Sachverhalt X]","role":"cond","label":"das, was passiert"},{"text":"のは、","role":"actor"},{"text":"[Grund Y]","role":"verb"},{"text":"からだ / からです","role":"plain","label":"weil"}],"gloss":"»Dass X, liegt daran, dass Y.« — schiebt den Grund ans Satzende und betont ihn. Muster: 〜のは、〜からだ. Frage: なぜ 〜のですか.","ex":{"jp":"<ruby>日本語<rt>にほんご</rt></ruby>が <ruby>上手<rt>じょうず</rt></ruby>な<b>のは</b>、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>している<b>からだ</b>。","de":"Dass sein Japanisch so gut ist, liegt daran, dass er täglich übt."},"simpel":"Kausaler Spaltsatz: »Dass X — das liegt daran, dass Y«. Der Grund rückt mit <b>のは … からだ</b> ans Ende.<br><span class=\"jp\"><ruby>遅<rt>おく</rt></ruby>れた<b>のは</b>、<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>止<rt>と</rt></ruby>まった<b>からだ</b></span> = „Ich bin zu spät, weil der Zug stehenblieb“","rule":"Kausale Spaltsatz-Konstruktion: »Dass X — das liegt daran, dass Y.« Hervorhebung des Grundes. Verwandt mit der Hervorhebungs-Struktur 〜のは 〜だ (L2), nur mit Fokus auf <b>Grund/Ursache</b>."},{"l":4,"t":"V<sub>テ</sub> いく / V<sub>テ</sub> きた (Entwicklung über Zeit)","de":"wird sich entwickeln (→ Zukunft) / hat sich entwickelt (→ Jetzt)","slots":[[{"text":"これから・だんだん …","role":"time","label":"Zukunfts-Signal"},{"text":"V-て いく","role":"verb","label":"→ Zukunft"}],[{"text":"これまで・<ruby>最近<rt>さいきん</rt></ruby> …","role":"time","label":"Vergangenheits-Signal"},{"text":"V-て きた","role":"verb","label":"→ Jetzt"}]],"gloss":"»entwickelt sich weiter« — ていく zeigt in die Zukunft (»von jetzt an weiter so«), てきた zeigt bis zur Gegenwart (»hat sich bis jetzt so entwickelt«). Oft mit これから / だんだん.","ex":{"jp":"これからも <ruby>温暖化<rt>おんだんか</rt></ruby>が <ruby>進<rt>すす</rt></ruby>んで <b>いく</b> だろう。","de":"Die Erderwärmung wird sich wohl weiter fortsetzen."},"simpel":"Entwicklung über Zeit: <b>ていく</b> = von jetzt in die Zukunft, <b>てきた</b> = von früher bis jetzt.<br><span class=\"jp\"><ruby>増<rt>ふ</rt></ruby>えて <b>きた</b> / <ruby>増<rt>ふ</rt></ruby>えて <b>いく</b></span> = „hat zugenommen / wird zunehmen“","rule":"Aspekt für <b>Veränderung über Zeit</b>. <code>ていく</code> = ein Trend geht ab jetzt in die Zukunft weiter. <code>てきた</code> = ein Trend hat sich von der Vergangenheit bis jetzt entwickelt. Vertiefung von Minna L43 (dort: konkrete Bewegung) — hier abstrakt-zeitlich."},{"l":4,"t":"[<ruby>表<rt>ひょう</rt></ruby>/グラフ] で <ruby>見<rt>み</rt></ruby>ると、〜ことが わかる","de":"Wenn man [Quelle] betrachtet, sieht man, dass …","slots":[{"text":"<ruby>表<rt>ひょう</rt></ruby> / グラフ","role":"obj","label":"Quelle"},{"text":"で <ruby>見<rt>み</rt></ruby>ると、","role":"actor","label":"betrachtet man"},{"text":"[Inhalt]","role":"verb","label":"in Plain-Form"},{"text":"ことが わかる","role":"plain","label":"erkennt man"}],"gloss":"»Wenn man [Quelle] anschaut, sieht man, dass …« — Standardsatz für Datenanalyse. Muster: [Quelle] を/で 見ると、〜ことが わかる. Auch: 調査によると.","ex":{"jp":"このグラフ<b>で <ruby>見<rt>み</rt></ruby>ると</b>、<ruby>日本<rt>にほん</rt></ruby>の <ruby>人口<rt>じんこう</rt></ruby>が <ruby>減<rt>へ</rt></ruby>って いる <b>ことが わかる</b>。","de":"Wenn man diese Grafik betrachtet, erkennt man, dass Japans Bevölkerung abnimmt."},"simpel":"Schablone für Datenanalyse: erst Quelle nennen, dann Erkenntnis mit <b>〜ことが わかる</b>.<br><span class=\"jp\">グラフで <ruby>見<rt>み</rt></ruby>ると、<ruby>人口<rt>じんこう</rt></ruby>が <ruby>減<rt>へ</rt></ruby>って いる<b>ことが わかる</b></span> = „Die Grafik zeigt: die Bevölkerung sinkt“","rule":"Standard-Schablone für die <b>Interpretation von Daten</b> in Berichten, Aufsätzen und Präsentationen. Erst die Quelle nennen (Tabelle, Grafik, Studie), dann die Erkenntnis daraus formulieren."},{"l":4,"t":"N₁ の ような N₂ (Beispiel-Funktion)","de":"ein N₂ wie zum Beispiel N₁","slots":[{"text":"N₁ の","role":"obj","label":"konkretes Beispiel"},{"text":"ような","role":"actor","label":"wie z.B."},{"text":"N₂","role":"subj","label":"Kategorie"}],"gloss":"»ein N₂ wie zum Beispiel N₁.« — N₁ ist ein Beispiel, das zeigt, welche Art N₂ gemeint ist. Muster: N₁ + の + ような + N₂. Ähnlich gesprochen: N₁ など.","ex":{"jp":"すし<b>のような</b> <ruby>日本食<rt>にほんしょく</rt></ruby>が <ruby>好<rt>す</rt></ruby>きです。","de":"Ich mag japanisches Essen wie zum Beispiel Sushi."},"simpel":"Hier ist N₁ ein <b>konkretes Beispiel</b> für N₂ — »ein N₂ wie zum Beispiel N₁«.<br><span class=\"jp\">すしのような <ruby>日本食<rt>にほんしょく</rt></ruby></span> = „japanisches Essen wie z.B. Sushi“","rule":"Hier dient N₁ als <b>konkretes Beispiel</b> für die allgemeinere Kategorie N₂. Anders als bei einfachem »wie« (L3) — der Akzent liegt auf »zum Beispiel«: »Sushi und ähnliche japanische Gerichte«."},{"l":4,"t":"X は Y ほど 〜ない","de":"X ist nicht so … wie Y (negativer Vergleich)","slots":[{"text":"X は","role":"subj","label":"das Kleinere"},{"text":"Y","role":"obj","label":"Standard"},{"text":"ほど","role":"actor","label":"so wie"},{"text":"Adj + ない","role":"verb","label":"nicht so sehr"}],"gloss":"»X ist nicht so [Adj] wie Y.« — Y ist der Maßstab, X reicht nicht heran. Muster: X は Y ほど + Adj/Vない (い-Adj → くない, な-Adj → ではない).","ex":{"jp":"<ruby>今日<rt>きょう</rt></ruby>は <ruby>昨日<rt>きのう</rt></ruby><b>ほど</b> <ruby>寒<rt>さむ</rt></ruby>く ない。","de":"Heute ist nicht so kalt wie gestern."},"simpel":"Negativer Vergleich: »X ist <b>nicht so</b> … wie Y«. Y ist der Maßstab, mit <b>ほど</b> markiert.<br><span class=\"jp\"><ruby>今日<rt>きょう</rt></ruby>は <ruby>昨日<rt>きのう</rt></ruby><b>ほど</b> <ruby>寒<rt>さむ</rt></ruby>く ない</span> = „Heute ist nicht so kalt wie gestern“","rule":"Vergleich mit Verneinung: »X ist <b>nicht so</b> [Eigenschaft] wie Y«. <code>ほど</code> markiert den Vergleichsstandard. Wichtig: <b>X ist kleiner/weniger</b>, Y ist der höhere Standard."},{"l":4,"t":"<ruby>比較<rt>ひかく</rt></ruby> — Vergleichsformen im Überblick","de":"Alle wichtigen Vergleichsstrukturen auf einen Blick","slots":[[{"text":"A より","role":"obj","label":"Basis"},{"text":"B の ほうが","role":"subj","label":"besser"},{"text":"Adj です","role":"verb"}],[{"text":"〜の <ruby>中<rt>なか</rt></ruby>で","role":"place","label":"Gruppe"},{"text":"X が","role":"subj"},{"text":"<ruby>一番<rt>いちばん</rt></ruby> Adj です","role":"verb","label":"am meisten"}]],"gloss":"Vergleiche auf einen Blick: A より B の ほうが Adj (B mehr), A は B ほど Adj-ない (A weniger), 〜の中で一番 (am meisten), 同じくらい (gleich), Vば 〜ほど (je … desto).","ex":{"jp":"バス<b>より</b> <ruby>電車<rt>でんしゃ</rt></ruby>の <b>ほうが</b> <ruby>速<rt>はや</rt></ruby>い。","de":"Der Zug ist schneller als der Bus."},"simpel":"Vergleiche auf einen Blick: <b>より/ほうが</b> (B > A), <b>ほど〜ない</b> (A < B), <b><ruby>一番<rt>いちばん</rt></ruby></b> (Superlativ).<br><span class=\"jp\">バス<b>より</b> <ruby>電車<rt>でんしゃ</rt></ruby>の <b>ほうが</b> <ruby>速<rt>はや</rt></ruby>い</span> = „Der Zug ist schneller als der Bus“","rule":"Übersichtskarte: Alle Vergleichs-Werkzeuge nebeneinander. Wichtig ist zu wissen, <b>aus welcher Richtung</b> der Vergleich kommt (»A > B« oder »A < B«) und ob die Aussage <b>positiv</b> oder <b>verneint</b> ist."},{"l":5,"t":"い-Adj / な-Adj + さ (Nominalisierung)","de":"Aus Adjektiv wird Nomen: »die X-keit«","slots":[{"text":"Adj-さ","role":"subj","label":"nominalisiert"},{"text":"は","role":"plain"},{"text":"[Grad/Maß]","role":"obj","label":"Zahl/Antwort"},{"text":"です","role":"plain"}],"gloss":"»die X-keit.« — さ macht aus einer Eigenschaft ein messbares Nomen. Muster: い-Adj い → さ (長さ, 高さ), な-Adj + さ. Ausnahme: いい/よい → よさ.","ex":{"jp":"この <ruby>山<rt>やま</rt></ruby>の <ruby>高<rt>たか</rt></ruby><b>さ</b>は 3776メートルです。","de":"Die Höhe dieses Berges beträgt 3776 Meter."},"simpel":"<b>さ</b> verwandelt ein Adjektiv in ein messbares Nomen: <ruby>高<rt>たか</rt></ruby>い → <ruby>高<rt>たか</rt></ruby>さ (»die Höhe«).<br><span class=\"jp\">この <ruby>山<rt>やま</rt></ruby>の <ruby>高<rt>たか</rt></ruby><b>さ</b></span> = „die Höhe dieses Berges“","rule":"Adjektive lassen sich mit <code>さ</code> in <b>Nomen</b> verwandeln, die einen <b>messbaren Grad</b> ausdrücken: <code><ruby>高<rt>たか</rt></ruby>い</code> (hoch) → <code><ruby>高<rt>たか</rt></ruby>さ</code> (die Höhe). Sehr produktive Regel — funktioniert mit fast allen Adjektiven."},{"l":5,"t":"<ruby>連用<rt>れんよう</rt></ruby><ruby>中止<rt>ちゅうし</rt></ruby><ruby>形<rt>けい</rt></ruby> (Schriftstil-Verbindung)","de":"Sätze mit ます-Stamm verbinden (Schriftsprache)","slots":[{"text":"V₁-Stamm","role":"verb","label":"Verb 1 ohne ます"},{"text":"、","role":"plain"},{"text":"V₂-Stamm","role":"verb","label":"Verb 2 ohne ます"},{"text":"、…","role":"plain"},{"text":"V<sub>n</sub>-た/ます","role":"actor","label":"Endverb mit Tempus"}],"gloss":"Verbindet Sätze im Schriftstil mit dem ます-Stamm statt der テ-Form; nur das letzte Verb trägt Tempus und Höflichkeit. Geschrieben: Vマス-Stamm、… (い-Adj: 〜く、). Ausnahme: する → し、.","ex":{"jp":"<ruby>朝<rt>あさ</rt></ruby> <ruby>起<rt>お</rt></ruby><b>き</b>、<ruby>顔<rt>かお</rt></ruby>を <ruby>洗<rt>あら</rt></ruby><b>い</b>、<ruby>朝食<rt>ちょうしょく</rt></ruby>を <ruby>食<rt>た</rt></ruby>べた。","de":"Ich stand morgens auf, wusch mir das Gesicht und frühstückte. [schriftlich]"},"simpel":"Im <b>Schriftstil</b> verbindet man Sätze mit dem ます-Stamm statt mit der て-Form — Tempus nur am Schluss.<br><span class=\"jp\"><ruby>朝<rt>あさ</rt></ruby> <ruby>起<rt>お</rt></ruby><b>き</b>、<ruby>顔<rt>かお</rt></ruby>を <ruby>洗<rt>あら</rt></ruby>った</span> = „Ich stand auf und wusch mein Gesicht“","rule":"In <b>geschriebenen Texten</b> (Berichte, Romane, Zeitungen) werden Teilsätze oft nicht mit der て-Form, sondern mit dem <b>ます-Stamm</b> verbunden. Das wirkt eleganter und literarischer. Tempus und Höflichkeit nur am <b>letzten</b> Verb."},{"l":5,"t":"V<sub>辞書/ない</sub> + ものだ (allgemeine Norm)","de":"so ist das halt / das ist nun einmal so","slots":[{"text":"(<ruby>一般的<rt>いっぱんてき</rt></ruby>に)","role":"time","label":"allgemein"},{"text":"V-辞書 / V-ない","role":"verb"},{"text":"ものだ","role":"actor","label":"so ist das halt"}],"gloss":"»So ist das halt.« — eine allgemeine Wahrheit/Norm, keine persönliche Meinung. Muster: V辞書形/ない形 + ものだ. Verneinung der Norm: V辞書 + ものではない.","ex":{"jp":"<ruby>人<rt>ひと</rt></ruby>は <ruby>年<rt>とし</rt></ruby>を <ruby>取<rt>と</rt></ruby>る<b>ものだ</b>。","de":"Menschen werden älter — so ist das nun einmal."},"simpel":"<b>V-辞書 + ものだ</b> = »so ist das nun mal« — allgemeine Wahrheit oder gesellschaftliche Norm.<br><span class=\"jp\"><ruby>人<rt>ひと</rt></ruby>は <ruby>年<rt>とし</rt></ruby>を <ruby>取<rt>と</rt></ruby>る<b>ものだ</b></span> = „Menschen werden eben älter“","rule":"<code>ものだ</code> drückt eine <b>allgemeine Wahrheit oder gesellschaftliche Norm</b> aus — »so ist das nun mal, das gehört dazu«. Wirkt belehrend oder erfahrungsweise. Anschluss meist mit Plain-Form (辞書形/ない形)."},{"l":5,"t":"もの と こと の <ruby>整理<rt>せいり</rt></ruby> (Übersicht)","de":"もの vs. こと: konkret/erlebbar ↔ abstrakt/sachlich","slots":[[{"text":"V-辞書 + もの","role":"verb","label":"konkret/erlebt"}],[{"text":"V-辞書 + こと","role":"verb","label":"abstrakt/sachlich"}]],"gloss":"もの (konkret, persönlich-warm) vs. こと (abstrakt, sachlich) — gleicher Anschluss (V辞書 + もの/こと), andere Nuance. もの bei 感じる/好き, こと bei 知る/必要.","ex":{"jp":"<ruby>食<rt>た</rt></ruby>べる<b>もの</b>に <ruby>気<rt>き</rt></ruby>を つけて います。","de":"Ich achte auf das, was ich esse. [konkret — das Essen selbst]"},"simpel":"<b>もの</b> = konkret/erlebbar, <b>こと</b> = abstrakt/sachlich. Im Zweifel ist <b>こと</b> immer korrekt.<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べる<b>もの</b> / <ruby>食<rt>た</rt></ruby>べる<b>こと</b></span> = „das Essen (Ding) / das Essen (Handlung)“","rule":"Beide nominalisieren Sätze, aber mit unterschiedlicher Nuance. <code>もの</code> = <b>konkret, greifbar, persönlich-erlebbar</b> (das Ding/Erlebnis selbst). <code>こと</code> = <b>abstrakt, sachlich, faktisch</b> (die Handlung/Tatsache)."},{"l":5,"t":"〜と いう ことだ (Hörensagen, schriftlich)","de":"es heißt, dass … / mit anderen Worten: …","slots":[{"text":"(Quelle に よると)","role":"actor","label":"laut wem"},{"text":"<ruby>普通形<rt>ふつうけい</rt></ruby>","role":"verb","label":"in Plain-Form"},{"text":"と いう ことだ","role":"plain","label":"es heißt"}],"gloss":"»Es heißt, dass …« / »mit anderen Worten: …« — Hörensagen aus formellen Quellen oder Zusammenfassung. Muster: 普通形 + ということだ (な-Adj/N + だ + ということだ). Gesprochen eher そうだ.","ex":{"jp":"<ruby>来年<rt>らいねん</rt></ruby>から <ruby>消費税<rt>しょうひぜい</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がる<b>と いう ことだ</b>。","de":"Es heißt, dass die Konsumsteuer nächstes Jahr steigen wird."},"simpel":"Formelles Hörensagen oder Zusammenfassung: »es heißt, dass …« bzw. »das heißt also …«.<br><span class=\"jp\"><ruby>来年<rt>らいねん</rt></ruby> <ruby>税<rt>ぜい</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がる<b>と いう ことだ</b></span> = „Es heißt, die Steuer steigt nächstes Jahr“","rule":"<b>Formelle Variante</b> des Hörensagen-そうだ (Minna L47). Zwei Funktionen: ① <b>Hörensagen</b> aus Berichten, Nachrichten, Studien. ② <b>Zusammenfassung</b> einer komplexen Aussage (»das heißt also …«)."},{"l":5,"t":"<ruby>長<rt>なが</rt></ruby>い <ruby>文<rt>ぶん</rt></ruby>を <ruby>読<rt>よ</rt></ruby>むコツ (Lese-Strategie)","de":"Lange Mittelstufen-Sätze entschlüsseln","slots":[{"text":"[Subjekt]は","role":"subj","label":"Anfang"},{"text":"[Nebensatz] ので、","role":"cond","label":"Grund"},{"text":"[Objekt]を","role":"obj"},{"text":"[V] と","role":"verb","label":"Zitat-Inhalt"},{"text":"<ruby>思<rt>おも</rt></ruby>って います","role":"actor","label":"Hauptverb GANZ AM ENDE"}],"gloss":"Lese-Richtung: <b>von hinten nach vorne</b> denken. Erst das Hauptverb finden — alles davor sind Modifikatoren.","ex":{"jp":"<ruby>環境問題<rt>かんきょうもんだい</rt></ruby>が <ruby>深刻<rt>しんこく</rt></ruby>に なって いる<b>ので</b>、<ruby>私<rt>わたし</rt></ruby>たちは <ruby>生活習慣<rt>せいかつしゅうかん</rt></ruby>を <ruby>変<rt>か</rt></ruby>える <ruby>必要<rt>ひつよう</rt></ruby>が ある<b>と</b> <ruby>思<rt>おも</rt></ruby>います。","de":"Da die Umweltprobleme ernster werden, denke ich, dass wir unsere Lebensgewohnheiten ändern müssen."},"simpel":"Keine Grammatik, sondern eine Lesehilfe: Japanisch ist ende-fokussiert — lange Sätze <b>von hinten</b> erfassen.<br><span class=\"jp\">… <ruby>必要<rt>ひつよう</rt></ruby>が ある<b>と <ruby>思<rt>おも</rt></ruby>います</b></span> = „Hauptverb steht ganz am Satzende“","rule":"Ab Chuukyuu werden Sätze sehr lang — mehrere Nebensätze, Nominalausdrücke, Konjunktionen. Diese Karte ist <b>kein Grammatikpunkt</b>, sondern eine <b>Lese-Strategie</b>. Wichtig: das japanische Hauptverb steht <b>am Ende</b>, also rückwärts lesen."},{"l":6,"t":"N によって [<ruby>受身<rt>うけみ</rt></ruby>] — Urheber im Passiv","de":"von / durch N (im Passiv, formell)","slots":[{"text":"[Werk] は","role":"subj","label":"Ergebnis"},{"text":"[Urheber]","role":"actor","label":"Schöpfer"},{"text":"によって","role":"plain","label":"durch"},{"text":"V-<ruby>受身<rt>うけみ</rt></ruby>","role":"verb","label":"Passiv"}],"gloss":"»wurde durch [Urheber] V-t.« — formelles Passiv, das betont, wer etwas erschaffen/entschieden hat (Erfindungen, Kunst, Gesetze). Muster: [Werk] は [Urheber] + によって + V受身.","ex":{"jp":"この <ruby>小説<rt>しょうせつ</rt></ruby>は <ruby>夏目漱石<rt>なつめそうせき</rt></ruby><b>によって</b> <ruby>書<rt>か</rt></ruby>かれた。","de":"Dieser Roman wurde von Natsume Sōseki geschrieben."},"simpel":"Im Passiv markiert <b>によって</b> den Urheber (Erfinder, Autor …) — formeller als einfaches に.<br><span class=\"jp\"><ruby>電話<rt>でんわ</rt></ruby>は ベル<b>によって</b> <ruby>発明<rt>はつめい</rt></ruby>された</span> = „Das Telefon wurde von Bell erfunden“","rule":"<code>によって</code> markiert im Passivsatz den <b>Urheber</b> einer wichtigen Handlung: Erfinder, Autor, Architekt, Komitee, historische Figur. Formeller und betonter als das einfache <code>に</code> aus Minna L37. Standard für Erfindungen, Kunstwerke, historische Beschlüsse."},{"l":6,"t":"〜ため(に) — Grund / Ursache","de":"wegen / aufgrund von (Ursache, nicht Absicht)","slots":[{"text":"[Grund / Ursache]","role":"cond","label":"was eingetreten ist"},{"text":"ために、","role":"actor","label":"wegen"},{"text":"[Folge]","role":"verb","label":"was daraus folgt"}],"gloss":"»wegen [Grund] [Folge].« — nennt eine Ursache außerhalb der eigenen Kontrolle, oft neutral/negativ. Muster: V普通形/N + の/な-Adj + な + ために. (Zweck: V辞書 + ために.)","ex":{"jp":"<ruby>台風<rt>たいふう</rt></ruby>の<b>ために</b>、<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>止<rt>と</rt></ruby>まりました。","de":"Wegen des Taifuns hielt der Zug an."},"simpel":"<b>ため(に)</b> als <b>Grund</b>: »wegen«. Anschluss mit た-Form / Nomen + の (eingetretene Ursache).<br><span class=\"jp\"><ruby>台風<rt>たいふう</rt></ruby>の<b>ために</b>、<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>止<rt>と</rt></ruby>まった</span> = „Wegen des Taifuns hielt der Zug“","rule":"<code>ため(に)</code> als <b>Ursache</b>: ein Umstand führt zu einer Folge, meist ohne aktive Steuerung des Sprechers. Klingt formell-schriftlich. Anschluss: <b>た-Form / Plain-Form</b> bei Verb (= geschehener Sachverhalt); <b>N + の</b> bei Nomen. <b>Wichtig:</b> Ist das Verb im <code><ruby>辞書<rt>じしょ</rt></ruby>形</code> (Wörterbuchform) → dann ist es <b>Zweck</b>, nicht Grund (siehe nächste Karte)!"},{"l":6,"t":"〜ため(に) — Übersicht: Grund vs. Zweck","de":"wegen ↔ damit / um zu — eine Form, zwei Bedeutungen","slots":[[{"text":"V-<ruby>辞書<rt>じしょ</rt></ruby> + ために","role":"verb","label":"Zweck (aktiv)"},{"text":"→ »um zu V« / »damit«","role":"plain"}],[{"text":"V-た + ために","role":"verb","label":"Grund (passiv)"},{"text":"→ »wegen«","role":"plain"}]],"gloss":"Eine Form, zwei Bedeutungen: 食べる+ために = um zu essen (Zweck), 食べた+ために = weil ich gegessen habe (Grund). Bei Nomen (家族のために) entscheidet der Kontext.","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>の<b>ために</b>、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>運動<rt>うんどう</rt></ruby>して います。","de":"Um gesund zu bleiben, treibe ich täglich Sport. [Zweck]"},"simpel":"Die Verbform entscheidet: <b>辞書形 + ために</b> = Zweck (»um zu«), <b>た-Form + ために</b> = Grund (»wegen«).<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べる ために / <ruby>食<rt>た</rt></ruby>べた ために</span> = „um zu essen / weil ich gegessen habe“","rule":"<b>Sammelkarte</b>: <code>ために</code> ist berüchtigt, weil es zwei sehr verschiedene Dinge bedeuten kann — <b>Zweck</b> (Minna L42, »damit / um zu«) oder <b>Grund</b> (L6, »wegen«). Der Unterschied steckt in der <b>Verbform vor ために</b>: 辞書形 = Zweck, た-Form/普通形 = Grund. Bei Nomen entscheidet der Kontext."},{"l":6,"t":"V<sub>た</sub> / N の / Adj + まま","de":"so wie es ist / im Zustand bleibend","slots":[{"text":"[Zustand: V-た / V-ない / N の / Adj]","role":"cond","label":"Ausgangszustand"},{"text":"まま (で)","role":"actor","label":"bleibt so"},{"text":"[Handlung]","role":"verb","label":"V₂"}],"gloss":"»Etwas im selben Zustand lassen und dann V₂.« Bildung: Vた/Vない + まま, N+の+まま, い-Adj+まま, な-Adj+な+まま.","ex":{"jp":"<ruby>靴<rt>くつ</rt></ruby>を <ruby>履<rt>は</rt></ruby>いた<b>まま</b>、<ruby>家<rt>いえ</rt></ruby>に <ruby>入<rt>はい</rt></ruby>って しまった。","de":"Ich bin (versehentlich) mit Schuhen ins Haus gegangen."},"simpel":"<b>まま</b> = ein Zustand bleibt unverändert, obwohl man ihn normalerweise ändern würde.<br><span class=\"jp\"><ruby>靴<rt>くつ</rt></ruby>を <ruby>履<rt>は</rt></ruby>いた<b>まま</b> <ruby>入<rt>はい</rt></ruby>った</span> = „mit Schuhen hereingekommen“","rule":"<code>まま</code> beschreibt: ein <b>Zustand bleibt unverändert</b>, während eine zweite Handlung passiert — typisch dann, wenn man normalerweise den Zustand <b>ändern würde</b>. Daraus entsteht oft ein leicht unangemessener oder unbequemer Eindruck (»mit Schuhen ins Haus«). Anschluss: V-た-Form, N + の, oder Adjektiv."},{"l":7,"t":"Vタ ものだ (Nostalgie)","de":"früher pflegte ich … (wehmütige Erinnerung)","slots":[{"text":"<ruby>昔<rt>むかし</rt></ruby> / 子供のころ","role":"time","label":"früher"},{"text":"よく","role":"actor","label":"oft"},{"text":"V-た","role":"verb"},{"text":"ものだ","role":"plain","label":"Nostalgie"}],"gloss":"»Früher habe ich oft V gemacht.« Wehmütige Erinnerung an eine Gewohnheit von früher. Bildung: Vた + ものだ, oft mit よく.","ex":{"jp":"<ruby>子供<rt>こども</rt></ruby>のころ、よく この <ruby>川<rt>かわ</rt></ruby>で <ruby>泳<rt>およ</rt></ruby>いだ<b>ものだ</b>。","de":"Als Kind schwamm ich früher oft in diesem Fluss."},"simpel":"<b>V-た + ものだ</b> = wehmütige Erinnerung: »früher pflegte ich oft …«. Gern mit <b>よく</b>.<br><span class=\"jp\"><ruby>昔<rt>むかし</rt></ruby>は よく <ruby>泳<rt>およ</rt></ruby>いだ<b>ものだ</b></span> = „Früher schwamm ich oft“","rule":"<code>V-た + ものだ</code> drückt Nostalgie aus: eine Gewohnheit oder Erfahrung, die in der Vergangenheit häufig oder regelmäßig vorkam, heute aber nicht mehr. Ton ist wehmütig-warm. Wichtige Ergänzung: oft mit Zeitangaben wie <ruby>子供<rt>こども</rt></ruby>のころ, <ruby>学生<rt>がくせい</rt></ruby>のとき, <ruby>昔<rt>むかし</rt></ruby>."},{"l":7,"t":"N / V + として","de":"als (in der Funktion/Kapazität von)","slots":[{"text":"Subjekt は","role":"subj"},{"text":"N","role":"obj","label":"Rolle"},{"text":"として","role":"actor","label":"als"},{"text":"V / Adj","role":"verb"}],"gloss":"»Als [Rolle/Funktion].« Bildung: N+として. Z.B. 〜として有名だ = bekannt als.","ex":{"jp":"<ruby>教師<rt>きょうし</rt></ruby><b>として</b> 30<ruby>年間<rt>ねんかん</rt></ruby> <ruby>働<rt>はたら</rt></ruby>きました。","de":"Ich arbeitete 30 Jahre lang als Lehrer."},"simpel":"<b>として</b> = »als« in der Rolle/Funktion von N — nicht für Richtung (に) oder Urheber (によって).<br><span class=\"jp\"><ruby>教師<rt>きょうし</rt></ruby><b>として</b> <ruby>働<rt>はたら</rt></ruby>く</span> = „als Lehrer arbeiten“","rule":"<code>として</code> markiert die <b>Rolle, Funktion oder Eigenschaft</b>, in der jemand oder etwas auftritt. Auf Deutsch: »als«, aber nur bei Rollen — nicht beim Passiv (da: によって)."},{"l":7,"t":"〜といっても","de":"auch wenn man X sagt — in Wirklichkeit nur Y","slots":[{"text":"X (klingt groß)","role":"obj","label":"was gesagt wird"},{"text":"といっても、","role":"actor","label":"aber eigentlich"},{"text":"Y (Einschränkung)","role":"verb","label":"die Wahrheit"}],"gloss":"»Auch wenn man X sagt, ist es eigentlich nur Y.« Bildung: N/VPlain + といっても.","ex":{"jp":"<ruby>料理<rt>りょうり</rt></ruby>ができる<b>といっても</b>、<ruby>簡単<rt>かんたん</rt></ruby>なものしか <ruby>作<rt>つく</rt></ruby>れません。","de":"Auch wenn ich kochen kann — nur einfache Sachen."},"simpel":"<b>といっても</b> relativiert nach unten: »auch wenn X groß klingt — in Wirklichkeit nur Y«.<br><span class=\"jp\"><ruby>近<rt>ちか</rt></ruby>い<b>といっても</b>、<ruby>歩<rt>ある</rt></ruby>いて 20<ruby>分<rt>ぷん</rt></ruby></span> = „Nah heißt: 20 Minuten zu Fuß“","rule":"Relativiert eine Aussage oder ein Wort: »Auch wenn ich X sage — das solltest du nicht wörtlich/vollständig nehmen, denn eigentlich ist es nur Y.« Typisch für Bescheidenheit oder Einschränkung einer positiven Aussage."},{"l":7,"t":"Vル より Vル ほうが 〜","de":"lieber V₂ als V₁ / V₂ ist [Adj]-er als V₁","slots":[{"text":"V₁ / N₁","role":"obj","label":"Vergleichsbasis"},{"text":"より","role":"plain","label":"als"},{"text":"V₂ / N₂","role":"subj","label":"das Bessere"},{"text":"ほうが Adj (です)","role":"verb"}],"gloss":"»V₂/N₂ ist [Adj]-er als V₁/N₁« oder »lieber V₂ als V₁«. より = das Verglichene, ほうが = das Bevorzugte. Bildung: V₁より V₂ほうが.","ex":{"jp":"<ruby>読<rt>よ</rt></ruby>む<b>より</b> <ruby>書<rt>か</rt></ruby>く<b>ほうが</b> <ruby>難<rt>むずか</rt></ruby>しい。","de":"Schreiben ist schwerer als Lesen."},"simpel":"Handlungen vergleichen: <b>より</b> = die Basis, <b>ほうが</b> = das Bevorzugte/Bessere.<br><span class=\"jp\"><ruby>読<rt>よ</rt></ruby>む<b>より</b> <ruby>書<rt>か</rt></ruby>く<b>ほうが</b> <ruby>難<rt>むずか</rt></ruby>しい</span> = „Schreiben ist schwerer als Lesen“","rule":"Vergleich zweier <b>Handlungen</b> (oder Nomen): <code>より</code> = als (Basis), <code>ほうが</code> = der bevorzugte/bessere. Ergänzt die Vergleichs-Übersicht aus L4 um den Verb-Vergleich. Auch für persönliche Präferenzen: »ich mag lieber V₂ als V₁«."},{"l":7,"t":"〜なら (Reaktions-Konditional)","de":"wenn es um X geht / falls X (Thema aufgreifen)","slots":[{"text":"[bekanntes Thema X]","role":"cond","label":"aufgegriffen"},{"text":"なら、","role":"actor","label":"wenn das so ist"},{"text":"[Reaktion/Empfehlung]","role":"verb"}],"gloss":"»Wenn das so ist (wie du sagst), dann …« Greift etwas Gesagtes auf und reagiert darauf. Bildung: N/VPlain + なら.","ex":{"jp":"<ruby>京都<rt>きょうと</rt></ruby>へ <ruby>行<rt>い</rt></ruby>く<b>なら</b>、<ruby>金閣寺<rt>きんかくじ</rt></ruby>は <ruby>外<rt>はず</rt></ruby>せない。","de":"Wenn du nach Kyoto fährst, ist der Goldene Pavillon ein Muss."},"simpel":"<b>なら</b> greift ein bekanntes Thema auf und reagiert darauf mit Rat oder Empfehlung.<br><span class=\"jp\"><ruby>京都<rt>きょうと</rt></ruby>へ <ruby>行<rt>い</rt></ruby>く<b>なら</b>、<ruby>金閣寺<rt>きんかくじ</rt></ruby>だ</span> = „Wenn schon Kyoto, dann der Goldene Pavillon“","rule":"<code>なら</code> ist ein <b>Reaktions-Konditional</b>: es greift etwas auf, das vorher erwähnt wurde oder implizit bekannt ist, und reagiert mit Empfehlung, Kommentar oder Warnung. Unterschied zu ば/たら/と: なら setzt das Thema <b>X als bereits gegeben voraus</b> (»wenn X so ist, wie ich verstehe — dann …«)."},{"l":7,"t":"「なら・と・ば・たら」<ruby>整理<rt>せいり</rt></ruby>","de":"Die 4 Konditionale im Überblick","slots":[[{"text":"と","role":"cond","label":"Automat"},{"text":"→ Naturgesetz / Anleitung","role":"plain"}],[{"text":"たら","role":"cond","label":"Sequenz"},{"text":"→ konkreter nächster Schritt","role":"plain"}],[{"text":"ば","role":"cond","label":"Hypothese"},{"text":"→ allgemein / Rat","role":"plain"}],[{"text":"なら","role":"cond","label":"Reaktion"},{"text":"→ Empfehlung auf Thema","role":"plain"}]],"gloss":"Die 4 wenn-Formen: と = passiert automatisch, たら = danach/wenn, ば = falls (Annahme), なら = wenn es um X geht (Reaktion).","ex":{"jp":"この ボタンを <ruby>押<rt>お</rt></ruby>す<b>と</b>、ドアが <ruby>開<rt>あ</rt></ruby>く。","de":"Wenn man diesen Knopf drückt, öffnet sich die Tür. [と — Automat]"},"simpel":"<b>と</b> = Automatismus, <b>たら</b> = Sequenz, <b>ば</b> = Hypothese/Rat, <b>なら</b> = Reaktion aufs Thema.<br><span class=\"jp\">と・たら・ば・なら</span> = „vier »wenn«, vier Nuancen“","rule":"<b>Sammelkarte</b>: Alle vier Konditionalformen nebeneinander. Jede hat ihr Spezialgebiet — Überlappungen gibt es, aber die Kernbedeutungen sind klar verschieden. Vertiefung zu Minna L23 (と), L25 (たら), L35 (なら), L43 (ば)."},{"l":7,"t":"Vテ <ruby>欲<rt>ほ</rt></ruby>しい / Vナイで <ruby>欲<rt>ほ</rt></ruby>しい","de":"Ich möchte, dass du [V] / nicht [V]","slots":[{"text":"(Person) に","role":"actor","label":"von wem"},{"text":"V-て / V-ないで","role":"verb","label":"was sie tun/nicht tun"},{"text":"<ruby>欲<rt>ほ</rt></ruby>しい","role":"plain","label":"ich wünsche mir"}],"gloss":"»Ich möchte, dass du V machst (oder nicht machst).« Du wünschst, jemand anderes handelt. Bildung: (Person に) Vテ+欲しい / Vないで+欲しい.","ex":{"jp":"もっと <ruby>早<rt>はや</rt></ruby>く <ruby>来<rt>き</rt></ruby>て <ruby>欲<rt>ほ</rt></ruby>しかった。","de":"Ich hätte mir gewünscht, dass du früher kommst."},"simpel":"Wunsch an eine andere Person: <b>V-て + ほしい</b> (du sollst …) / <b>V-ないで + ほしい</b> (du sollst nicht …).<br><span class=\"jp\"><ruby>嘘<rt>うそ</rt></ruby>を つかないで <ruby>欲<rt>ほ</rt></ruby>しい</span> = „Ich möchte, dass du nicht lügst“","rule":"Wunsch an eine <b>andere Person</b>: »ich möchte, dass du etwas tust / nicht tust«. Ich = Subjekt (mit は), die andere Person = Empfänger des Wunsches (mit に), die Handlung = V-て + ほしい. <b>Nicht verwechseln</b> mit てみたい (ich selbst möchte ausprobieren) und mit 欲しい (ich möchte ein Ding haben)."},{"l":8,"t":"〜あいだ / 〜あいだに","de":"während [ganze Zeit] / während [irgendwann darin]","slots":[[{"text":"V₁-ている","role":"cond","label":"Zeitspanne"},{"text":"あいだ、","role":"actor","label":"ganze Zeit"},{"text":"V₂ (dauerhaft)","role":"verb"}],[{"text":"V₁-ている","role":"cond","label":"Zeitspanne"},{"text":"あいだに、","role":"actor","label":"einmal darin"},{"text":"V₂ (punktuell)","role":"verb"}]],"gloss":"あいだ = V₂ läuft die ganze Zeit durch; あいだに = V₂ passiert einmal irgendwann darin. Bildung: Vテいる+あいだ(に) bzw. N+の+あいだ(に).","ex":{"jp":"<ruby>父<rt>ちち</rt></ruby>が <ruby>昼寝<rt>ひるね</rt></ruby>して いる<b>あいだ</b>、<ruby>静<rt>しず</rt></ruby>かに して いました。","de":"Während Vater Mittagsschlaf hielt, war ich die ganze Zeit leise."},"simpel":"<b>あいだ</b> = die ganze Zeitspanne lang, <b>あいだに</b> = irgendwann einmal innerhalb der Zeitspanne.<br><span class=\"jp\"><ruby>寝<rt>ね</rt></ruby>て いる<b>あいだに</b> <ruby>電話<rt>でんわ</rt></ruby>が <ruby>来<rt>き</rt></ruby>た</span> = „Während ich schlief, kam ein Anruf“","rule":"Beide Formen beschreiben eine <b>Zeitspanne</b> (V₁), in der etwas anderes passiert. <code>あいだ</code>: V₂ läuft <b>die ganze Zeit</b> parallel (dauerhaft). <code>あいだに</code>: V₂ passiert <b>einmal irgendwann</b> innerhalb der Zeitspanne (punktuell)."},{"l":8,"t":"〜わけではない","de":"es ist nicht so, dass … / nicht unbedingt","slots":[{"text":"(Vermutung des Anderen)","role":"cond","label":"Missverständnis"},{"text":"V / Adj","role":"verb"},{"text":"わけではない","role":"actor","label":"nicht so (generell)"}],"gloss":"»Es heißt nicht, dass immer/grundsätzlich X gilt.« Sanfte Einschränkung. Bildung: VPlain/い-Adj+わけではない, な-Adj/N+な+わけではない.","ex":{"jp":"<ruby>嫌<rt>きら</rt></ruby>いな<b>わけではない</b>けど、あまり <ruby>食<rt>た</rt></ruby>べたくない。","de":"Es ist nicht so, dass ich es nicht mag — ich will es nur gerade nicht."},"simpel":"<b>わけではない</b> = sanfte Einschränkung: »es ist nicht so, dass … (immer/generell)«.<br><span class=\"jp\"><ruby>嫌<rt>きら</rt></ruby>いな<b>わけではない</b></span> = „Es ist nicht so, dass ich es nicht mag“","rule":"Relativiert oder verneint eine <b>Verallgemeinerung</b>. »Es stimmt nicht generell, dass X.« Oft zur sanften Korrektur eines Missverständnisses. Milder als einfaches ではない — man schränkt ein, ohne zu widersprechen."},{"l":8,"t":"Vル / Vナイ ことがある","de":"es kommt manchmal vor, dass …","slots":[{"text":"Subjekt は/が","role":"subj"},{"text":"(たまに)","role":"time","label":"manchmal"},{"text":"V-辞書 / V-ない","role":"verb"},{"text":"ことがある","role":"actor","label":"kommt vor"}],"gloss":"»Manchmal kommt es vor, dass V (oder nicht V).« Bildung: V辞書/Vない + ことがある. Oft mit たまに/時々. (Nicht verwechseln mit Vた+ことがある = Erfahrung.)","ex":{"jp":"<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>遅<rt>おく</rt></ruby>れる<b>ことがあります</b>。","de":"Es kommt vor, dass der Zug Verspätung hat."},"simpel":"<b>V-辞書/ない + ことがある</b> = »es kommt manchmal vor, dass …« (≠ た-Form = Erfahrung).<br><span class=\"jp\"><ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>遅<rt>おく</rt></ruby>れる<b>ことがある</b></span> = „Manchmal hat der Zug Verspätung“","rule":"<code>V<sub>辞書/ない</sub> + ことがある</code> = gelegentlich, nicht regelmäßig. Unterschied zu <code>V<sub>た</sub> + ことがある</code> (Minna L19 — Erfahrung in der Vergangenheit): <b>た-Form = Erfahrung (mindestens einmal passiert). 辞書形/ない = wiederkehrend gelegentlich.</b>"},{"l":8,"t":"Vル まで、V₂","de":"bis V₁ passiert, V₂ (durchgehend)","slots":[{"text":"V₁-辞書","role":"cond","label":"Zielpunkt"},{"text":"まで、","role":"actor","label":"bis"},{"text":"V₂ (dauerhaft)","role":"verb","label":"läuft durch"}],"gloss":"»V₂ läuft durch, bis V₁ eintritt.« Bildung: V辞書/N + まで + V₂. Achtung: までに = Frist (bis spätestens).","ex":{"jp":"<ruby>雨<rt>あめ</rt></ruby>が <ruby>止<rt>や</rt></ruby>む<b>まで</b>、ここで <ruby>待<rt>ま</rt></ruby>ちましょう。","de":"Warten wir hier, bis der Regen aufhört."},"simpel":"<b>まで</b> = durchgehend bis (warten), <b>までに</b> = Deadline (bis spätestens erledigen).<br><span class=\"jp\"><ruby>雨<rt>あめ</rt></ruby>が <ruby>止<rt>や</rt></ruby>む<b>まで</b> <ruby>待<rt>ま</rt></ruby>つ</span> = „warten, bis der Regen aufhört“","rule":"<code>まで</code> = bis zu einem Zielpunkt. <code>V₁ まで、V₂</code>: V₂ läuft <b>durchgehend</b>, bis V₁ eintritt. Wichtige Abgrenzung: <code>まで</code> = durchgehend bis; <code>まで に</code> = Deadline (erledigen bis spätestens)."},{"l":8,"t":"N によって (je nach)","de":"je nach N / abhängig von N (2. Bedeutung)","slots":[{"text":"N","role":"obj","label":"Variable"},{"text":"によって","role":"actor","label":"je nach"},{"text":"Ergebnis","role":"verb"},{"text":"が <ruby>違<rt>ちが</rt></ruby>う","role":"plain","label":"ist verschieden"}],"gloss":"»Je nach N ist das Ergebnis verschieden.« Bildung: N+によって + 違う/異なる.","ex":{"jp":"<ruby>国<rt>くに</rt></ruby><b>によって</b>、<ruby>文化<rt>ぶんか</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>います。","de":"Je nach Land ist die Kultur verschieden."},"simpel":"<b>によって</b> Bedeutung 2: »je nach N verschieden« — oft mit <ruby>違<rt>ちが</rt></ruby>う / <ruby>異<rt>こと</rt></ruby>なる.<br><span class=\"jp\"><ruby>国<rt>くに</rt></ruby><b>によって</b> <ruby>文化<rt>ぶんか</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>う</span> = „Je nach Land ist die Kultur anders“","rule":"<code>によって</code> Bedeutung 2: <b>Variation, die von N abhängt</b> — »je nach N ist es anders«. Oft mit <code><ruby>違<rt>ちが</rt></ruby>う / <ruby>異<rt>こと</rt></ruby>なる / <ruby>変<rt>か</rt></ruby>わる</code> am Satzende kombiniert. Nicht mit Urheber-Passiv (L6) oder Mittel (L10) verwechseln."},{"l":8,"t":"「として・について・によって」<ruby>整理<rt>せいり</rt></ruby>","de":"als / über / je nach (Übersicht Postpositionen)","slots":[[{"text":"N として","role":"actor","label":"als Rolle"},{"text":"→ <ruby>専門家<rt>せんもんか</rt></ruby>として<ruby>話<rt>はな</rt></ruby>す","role":"plain"}],[{"text":"N について","role":"actor","label":"Thema"},{"text":"→ <ruby>環境<rt>かんきょう</rt></ruby>について<ruby>話<rt>はな</rt></ruby>す","role":"plain"}],[{"text":"N によって","role":"actor","label":"variiert"},{"text":"→ <ruby>国<rt>くに</rt></ruby>によって<ruby>違<rt>ちが</rt></ruby>う","role":"plain"}]],"gloss":"Drei Postpositionen: として = als/in der Rolle, について = über/zum Thema, によって = durch/je nach/von wem. Alle mit N + Partikel.","ex":{"jp":"<ruby>専門家<rt>せんもんか</rt></ruby><b>として</b> <ruby>意見<rt>いけん</rt></ruby>を <ruby>述<rt>の</rt></ruby>べます。","de":"Als Experte äußere ich meine Meinung."},"simpel":"Drei Postpositionen: <b>として</b> = als (Rolle), <b>について</b> = über (Thema), <b>によって</b> = je nach / durch.<br><span class=\"jp\"><ruby>環境<rt>かんきょう</rt></ruby><b>について</b> <ruby>話<rt>はな</rt></ruby>す</span> = „über die Umwelt sprechen“","rule":"<b>Sammelkarte</b>: Drei wichtige Postpositionen nach Nomen — als Übersicht zum Klarhalten und Vergleichen. Alle drei kommen in Chuukyuu häufig vor."},{"l":9,"t":"〜にともなって / にともなう N","de":"im Zuge von / parallel dazu (Entwicklung)","slots":[{"text":"N の / V-辞書","role":"cond","label":"Entwicklung A"},{"text":"にともなって、","role":"actor","label":"im Zuge von"},{"text":"Entwicklung B","role":"verb"}],"gloss":"»Im Zuge von A verändert sich auch B.« — zwei Dinge entwickeln sich parallel. Anschluss: N + にともなって; attributiv: にともなう + N.","ex":{"jp":"<ruby>経済<rt>けいざい</rt></ruby>の<ruby>発展<rt>はってん</rt></ruby><b>にともなって</b>、<ruby>生活水準<rt>せいかつすいじゅん</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がった。","de":"Im Zuge der Wirtschaftsentwicklung stieg der Lebensstandard."},"simpel":"<b>にともなって</b> = zwei Entwicklungen verlaufen parallel: »im Zuge von A verändert sich B«.<br><span class=\"jp\"><ruby>人口<rt>じんこう</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>える<b>にともなって</b> …</span> = „Mit wachsender Bevölkerung …“","rule":"Drückt aus, dass <b>zwei Veränderungen parallel verlaufen</b>: wenn A zunimmt/wächst, nimmt/wächst B ebenfalls. Formell-schriftlich, typisch für gesellschaftliche oder wirtschaftliche Trends. Anschluss: N + にともなって oder V-辞書 + にともなって."},{"l":9,"t":"<ruby>接続詞<rt>せつぞくし</rt></ruby>: つまり / <ruby>一方<rt>いっぽう</rt></ruby>","de":"das heißt / andererseits (Satz-Konjunktionen)","slots":[[{"text":"Aussage A。","role":"cond"},{"text":"つまり、","role":"actor","label":"d.h."},{"text":"Zusammenfassung B","role":"verb"}],[{"text":"Aspekt A。","role":"cond"},{"text":"一方、","role":"actor","label":"andererseits"},{"text":"Aspekt B","role":"verb"}]],"gloss":"Satz-Verbinder: つまり = das heißt (fasst zusammen), 一方 = andererseits (stellt zwei Seiten nebeneinander). Stehen am Satzanfang.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby>に <ruby>出席<rt>しゅっせき</rt></ruby>できなかった。<b>つまり</b>、<ruby>重要<rt>じゅうよう</rt></ruby>な <ruby>議論<rt>ぎろん</rt></ruby>を <ruby>聞<rt>き</rt></ruby>けなかった。","de":"Ich konnte nicht an der Sitzung teilnehmen. Das heißt, die wichtige Diskussion habe ich verpasst."},"simpel":"<b>つまり</b> = »das heißt« (fasst zusammen), <b>一方</b> = »andererseits« (stellt zwei Aspekte gegenüber).<br><span class=\"jp\">A。<b>一方</b>、B。</span> = „A. Andererseits B.“","rule":"Zwei wichtige <b>schriftsprachliche Konjunktionen</b>. <code>つまり</code> = fasst zusammen/reformuliert (»das heißt, das läuft auf X hinaus«). <code>一方</code> = stellt zwei Aspekte nebeneinander (»auf der anderen Seite«)."},{"l":9,"t":"Na / N + である","de":"ist … (schriftsprachliches だ/です)","slots":[{"text":"N / な-Adj","role":"subj"},{"text":"である / ではない","role":"verb","label":"ist / ist nicht (formell)"}],"gloss":"»N/Adj ist X.« Wie だ/です, nur schriftsprachlich. Bildung: N/な-Adj + である. Verneinung: ではない.","ex":{"jp":"これは <ruby>重要<rt>じゅうよう</rt></ruby>な <ruby>問題<rt>もんだい</rt></ruby><b>である</b>。","de":"Dies ist ein wichtiges Problem."},"simpel":"<b>である</b> ist das schriftsprachliche <b>だ/です</b> — Standard in Berichten und Aufsätzen.<br><span class=\"jp\">これは <ruby>重要<rt>じゅうよう</rt></ruby>な <ruby>問題<rt>もんだい</rt></ruby><b>である</b></span> = „Dies ist ein wichtiges Problem“","rule":"<code>である</code> ist das schriftsprachlich-formelle Äquivalent von <code>だ</code>. Standard in Berichten, Essays, Nachrichten. Im Gespräch steif. Negation: <code>ではない</code>. Vergangenheit: <code>であった</code>."},{"l":9,"t":"<ruby>使役受身<rt>しえきうけみ</rt></ruby> — Kausativ-Passiv","de":"gezwungen werden zu V (unfreiwillig)","slots":[{"text":"<ruby>被害者<rt>ひがいしゃ</rt></ruby> は","role":"subj","label":"gezwungene Person"},{"text":"<ruby>加害者<rt>かがいしゃ</rt></ruby> に","role":"actor","label":"zwingende Person"},{"text":"(Objekt を)","role":"obj"},{"text":"V-させられる","role":"verb","label":"wird gezwungen"}],"gloss":"»Jemand wird (vom Veranlasser) gezwungen, V zu tun« – unfreiwillig. Bildung: Gr.II 未然形+させられる, Gr.I a-Reihe+される. する→させられる, 来る→来させられる. Veranlasser mit に.","ex":{"jp":"<ruby>子供<rt>こども</rt></ruby>のとき、<ruby>嫌<rt>きら</rt></ruby>いな <ruby>野菜<rt>やさい</rt></ruby>を <ruby>食<rt>た</rt></ruby>べ<b>させられた</b>。","de":"Als Kind wurde ich gezwungen, Gemüse zu essen, das ich nicht mochte."},"simpel":"Kausativ + Passiv: »ich werde <b>gezwungen</b>, etwas zu tun« — immer unfreiwillig, immer negativ.<br><span class=\"jp\"><ruby>残業<rt>ざんぎょう</rt></ruby><b>させられた</b></span> = „Ich wurde zu Überstunden gezwungen“","rule":"Kausativ + Passiv kombiniert: »ich werde von jmd. gezwungen, etwas zu tun — gegen meinen Willen.« Der Ton ist <b>immer negativ</b>."},{"l":9,"t":"<ruby>受身<rt>うけみ</rt></ruby>・<ruby>使役<rt>しえき</rt></ruby>・<ruby>使役受身<rt>しえきうけみ</rt></ruby> Übersicht","de":"Passiv / Kausativ / Kausativ-Passiv","slots":[[{"text":"A は B に","role":"subj"},{"text":"V-られる","role":"verb","label":"受身: von B betroffen"}],[{"text":"A は B を","role":"subj"},{"text":"V-させる","role":"verb","label":"使役: B veranlassen"}],[{"text":"A は B に","role":"subj"},{"text":"V-させられる","role":"verb","label":"使役受身: von B gezwungen"}]],"gloss":"受身 = Betroffener (う→aれる / る→られる), 使役 = Veranlasser (う→aせる / る→させる), 使役受身 = zum Tun gezwungen (させられる / Gr.I aされる).","ex":{"jp":"<ruby>先生<rt>せんせい</rt></ruby>に <ruby>褒<rt>ほ</rt></ruby>め<b>られた</b>。","de":"Ich wurde vom Lehrer gelobt. [受身]"},"simpel":"Drei Perspektiven: <b>受身</b> = betroffen werden, <b>使役</b> = veranlassen, <b>使役受身</b> = gezwungen werden.<br><span class=\"jp\"><ruby>読<rt>よ</rt></ruby>まれる / <ruby>読<rt>よ</rt></ruby>ませる / <ruby>読<rt>よ</rt></ruby>まされる</span> = „gelesen werden / lesen lassen / lesen müssen“","rule":"<b>Sammelkarte</b>: Die drei komplexen Verbformen — Bildung, Bedeutung, Perspektive auf einen Blick."},{"l":9,"t":"Vテ <ruby>欲<rt>ほ</rt></ruby>しいものだ","de":"Ich wünsche mir wirklich, dass … (eindringlich)","slots":[{"text":"(Adressat に)","role":"actor","label":"optional"},{"text":"V-て / V-ないで","role":"verb"},{"text":"ほしいものだ","role":"plain","label":"wünsche mir sehr"}],"gloss":"»Ich wünsche mir von Herzen, dass V.« Eindringlicher und emotionaler als てほしい. Bildung: Vテ+ほしいものだ / Vないで+ほしいものだ.","ex":{"jp":"<ruby>政治家<rt>せいじか</rt></ruby>には もっと <ruby>本気<rt>ほんき</rt></ruby>で <ruby>取<rt>と</rt></ruby>り<ruby>組<rt>く</rt></ruby>んで<b>ほしいものだ</b>。","de":"Ich wünschte mir wirklich, dass Politiker ernster an die Sache herangehen."},"simpel":"<b>てほしい + ものだ</b> = eindringlicher, fast seufzender Wunsch an »die Welt«.<br><span class=\"jp\">もっと <ruby>読書<rt>どくしょ</rt></ruby>して<b>ほしいものだ</b></span> = „Ich wünschte wirklich, sie würden mehr lesen“","rule":"てほしい (L7) + ものだ (L5) kombiniert = <b>eindringlicher, emotionaler Wunsch</b>. Stärker als einfaches てほしい. Oft mit Seufzer- oder Resignationston. Für allgemeine Wünsche an »die Welt«."},{"l":10,"t":"N によって (Mittel / Methode)","de":"durch / mittels N (3. Bedeutung von によって)","slots":[{"text":"N","role":"obj","label":"Mittel"},{"text":"によって","role":"actor","label":"durch / mittels"},{"text":"Ergebnis / V","role":"verb"}],"gloss":"»Durch/mittels N (wird das Ergebnis erreicht).« Formell. Bildung: N+によって + V (oft Passiv). Im Alltag sagt man で.","ex":{"jp":"インターネット<b>によって</b>、<ruby>世界中<rt>せかいじゅう</rt></ruby>の <ruby>情報<rt>じょうほう</rt></ruby>が <ruby>手<rt>て</rt></ruby>に <ruby>入<rt>はい</rt></ruby>る。","de":"Durch das Internet gelangt man an Informationen aus aller Welt."},"simpel":"<b>によって</b> Bedeutung 3: »durch / mittels N« (formell). Im Alltag dafür meist <b>で</b>.<br><span class=\"jp\">インターネット<b>によって</b> <ruby>調<rt>しら</rt></ruby>べる</span> = „mittels Internet recherchieren“","rule":"<code>によって</code> Bedeutung 3: <b>Mittel oder Methode</b> — »durch den Einsatz von N wird Y erreicht«. Formell-schriftlich. Im Alltag nimmt man dafür meist で."},{"l":10,"t":"Vル / N の <ruby>代<rt>か</rt></ruby>わりに","de":"anstelle von / statt / als Ausgleich dafür","slots":[{"text":"A / V₁","role":"obj","label":"was ersetzt wird"},{"text":"の<ruby>代<rt>か</rt></ruby>わりに、","role":"actor","label":"anstatt"},{"text":"B / V₂","role":"verb","label":"Ersatz"}],"gloss":"»Statt A macht man B« oder »dafür als Ausgleich B«. Bildung: N+の/V辞書 + 代わりに. Für Ausgleich: その代わり.","ex":{"jp":"バター<b>の<ruby>代<rt>か</rt></ruby>わりに</b>、オリーブオイルを <ruby>使<rt>つか</rt></ruby>った。","de":"Statt Butter habe ich Olivenöl verwendet."},"simpel":"<b>代わりに</b> = ① Ersatz (B statt A) oder ② Ausgleich (Nachteil, aber dafür Vorteil).<br><span class=\"jp\">バター<b>の<ruby>代<rt>か</rt></ruby>わりに</b> オイルを <ruby>使<rt>つか</rt></ruby>う</span> = „statt Butter Öl verwenden“","rule":"Zwei Verwendungen mit gemeinsamem Kern »an Stelle von«: ① <b>Ersatz</b> — N の 代わりに / V<sub><ruby>辞書<rt>じしょ</rt></ruby></sub> 代わりに = »anstatt N / statt etwas zu tun« (バターの 代わりに オイル). ② <b>Ausgleich</b> — meist als その代わり am Satzanfang: ein Nachteil wird durch einen Vorteil aufgewogen (»eng, aber dafür billig«). Anschluss merken: Nomen braucht <b>の</b> (N<b>の</b> 代わりに), das Verb steht in der Wörterbuchform direkt davor."},{"l":10,"t":"Vテくる / Vテいく (Sprecher-Perspektive)","de":"Richtung relativ zum Sprecher (Vertiefung)","slots":[[{"text":"V-て くる","role":"verb","label":"→ zum Sprecher / bis jetzt"}],[{"text":"V-て いく","role":"verb","label":"← vom Sprecher / ab jetzt"}]],"gloss":"Sprecher ist der Mittelpunkt: てくる = kommt näher / von früher bis jetzt, ていく = entfernt sich / von jetzt in die Zukunft. Bildung: Vテ+くる/いく (in Hiragana).","ex":{"jp":"<ruby>向<rt>む</rt></ruby>こうから <ruby>子供<rt>こども</rt></ruby>が <ruby>走<rt>はし</rt></ruby>って<b>きた</b>。","de":"Von drüben rannte ein Kind auf mich zu."},"simpel":"Sprecher als Mittelpunkt: <b>てくる</b> = auf mich zu / bis jetzt, <b>ていく</b> = von mir weg / ab jetzt.<br><span class=\"jp\"><ruby>走<rt>はし</rt></ruby>って <b>きた</b> / <ruby>去<rt>さ</rt></ruby>って <b>いった</b></span> = „kam herangerannt / ging fort“","rule":"Vertiefung von Minna L43 + L4: <code>てくる</code> und <code>ていく</code> aus der <b>Sprecher-Perspektive</b>. くる = auf Sprecher zu (physisch oder zeitlich: bis jetzt). いく = vom Sprecher weg (physisch oder zeitlich: in Zukunft)."},{"l":10,"t":"Vル べきだ / べきでない","de":"sollte V / sollte nicht V (moralisch-normativ)","slots":[{"text":"Subjekt は","role":"subj"},{"text":"V-辞書","role":"verb"},{"text":"べきだ / べきではない","role":"actor","label":"moralisches Sollen"}],"gloss":"»Man sollte V tun – so gehört es sich.« Moralisch. Bildung: V辞書+べきだ, Verneinung べきではない. Bei する: するべき oder すべき.","ex":{"jp":"<ruby>約束<rt>やくそく</rt></ruby>は <ruby>守<rt>まも</rt></ruby>る<b>べきだ</b>。","de":"Man sollte Versprechen halten."},"simpel":"<b>べきだ</b> = moralisches Sollen (stärker als ほうがいい, schwächer als なければならない).<br><span class=\"jp\"><ruby>約束<rt>やくそく</rt></ruby>は <ruby>守<rt>まも</rt></ruby>る<b>べきだ</b></span> = „Man sollte Versprechen halten“","rule":"<code>べきだ</code> = moralisches oder logisches Sollen. Stärker als <code>ほうがいい</code> (Rat), schwächer als <code>なければならない</code> (Pflicht). Standard für gesellschaftliche Normen und logische Schlussfolgerungen."},{"l":10,"t":"Vナイずに","de":"ohne zu V — schriftsprachliches ないで","slots":[{"text":"V-ない-Stamm","role":"verb","label":"ohne V₁"},{"text":"ずに、","role":"actor","label":"ohne"},{"text":"V₂","role":"verb","label":"macht V₂"}],"gloss":"»V₂ tun, ohne V₁ getan zu haben.« Schriftsprachliches ないで. Bildung: Vない-Stamm + ずに. Achtung: する → せずに.","ex":{"jp":"<ruby>何<rt>なに</rt></ruby>も <ruby>言<rt>い</rt></ruby>わ<b>ずに</b>、<ruby>部屋<rt>へや</rt></ruby>を <ruby>出<rt>で</rt></ruby>て <ruby>行<rt>い</rt></ruby>った。","de":"Er verließ das Zimmer, ohne etwas zu sagen."},"simpel":"<b>ずに</b> = schriftsprachliches <b>ないで</b> (»ohne zu …«). Achtung: する → <b>せずに</b>!<br><span class=\"jp\"><ruby>何<rt>なに</rt></ruby>も <ruby>言<rt>い</rt></ruby>わ<b>ずに</b> <ruby>出<rt>で</rt></ruby>て <ruby>行<rt>い</rt></ruby>った</span> = „Er ging, ohne etwas zu sagen“","rule":"<code>ずに</code> = schriftsprachliche Variante von <code>ないで</code> (Minna L34). Bildung: ない-Stamm + ずに. Wichtige Ausnahme: <code>する → せずに</code>!"},{"l":10,"t":"<ruby>敬語<rt>けいご</rt></ruby> Übersicht","de":"Keigo — drei Ebenen der Höflichkeit","slots":[[{"text":"尊敬: <ruby>先生<rt>せんせい</rt></ruby>が","role":"actor","label":"andere Person"},{"text":"いらっしゃいます","role":"verb","label":"② 尊敬語"}],[{"text":"謙譲: <ruby>私<rt>わたし</rt></ruby>が","role":"subj","label":"ich"},{"text":"参ります","role":"verb","label":"③ 謙譲語"}],[{"text":"丁寧: 〜さんが","role":"subj"},{"text":"行きます","role":"verb","label":"① 丁寧語"}]],"gloss":"Drei Höflichkeitsebenen: 丁寧語 = neutral höflich (です/ます), 尊敬語 = das Gegenüber erhöhen, 謙譲語 = sich selbst kleiner machen. Niemals mischen.","ex":{"jp":"<ruby>先生<rt>せんせい</rt></ruby>は 何と <b>おっしゃいました</b>か。","de":"Was hat der Lehrer gesagt? [② 尊敬語]"},"simpel":"Drei Höflichkeitsebenen: <b>丁寧語</b> (neutral), <b>尊敬語</b> (andere erhöhen), <b>謙譲語</b> (sich selbst senken).<br><span class=\"jp\"><ruby>先生<rt>せんせい</rt></ruby>が いらっしゃる / <ruby>私<rt>わたし</rt></ruby>が <ruby>参<rt>まい</rt></ruby>る</span> = „Der Lehrer kommt / ich komme“","rule":"<b>Abschlusskarte</b>: Wiederholung Minna L50 mit Chuukyuu-Erweiterung. Drei Ebenen: ① 丁寧語 (neutrale Höflichkeit), ② 尊敬語 (andere erhöhen), ③ 謙譲語 (sich selbst erniedrigen)."},{"l":11,"t":"〜はず(だ) / 〜はずがない","de":"müsste (eigentlich) so sein / kann unmöglich sein","slots":[{"text":"N は","role":"subj"},{"text":"V<sub>Plain</sub>","role":"verb"},{"text":"はずだ","role":"plain","label":"müsste"}],"gloss":"»Logisch müsste es so sein.« はずだ = begründete Erwartung, はずがない = ausgeschlossen. Anschluss wie ans Nomen (N + の, な-Adj + な).","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は もう <ruby>着<rt>つ</rt></ruby>いた<b>はず</b>です。","de":"Er müsste schon angekommen sein."},"simpel":"<b>はず</b> = logische Erwartung: »es müsste so sein«. Verneint <b>はずがない</b> = »das kann nicht sein«.<br><span class=\"jp\">4<ruby>時<rt>じ</rt></ruby>に <ruby>着<rt>つ</rt></ruby>く<b>はず</b>です</span> = „müsste um 4 ankommen“","rule":"はず drückt eine aus Fakten/Logik abgeleitete Erwartung aus — nicht ein bloßes Gefühl, sondern »nach allem, was ich weiß, müsste es so sein«. はずだ = begründete Erwartung; はずがない = »ausgeschlossen, unmöglich«. Anschluss wie ans Nomen."},{"l":11,"t":"〜に <ruby>違<rt>ちが</rt></ruby>いない","de":"es muss ganz sicher … sein (starke Überzeugung)","slots":[{"text":"N は","role":"subj"},{"text":"[Vermutung]","role":"cond"},{"text":"に違いない","role":"plain","label":"muss sicher sein"}],"gloss":"»Aus den Indizien: es muss so sein.« Starke Überzeugung. Anschluss Plain; な-Adj/Nomen OHNE だ. Lockerer: に決まっている.","ex":{"jp":"<ruby>電気<rt>でんき</rt></ruby>が ついている。<ruby>家<rt>いえ</rt></ruby>に いる<b>に違いない</b>。","de":"Das Licht brennt. Sie muss zu Hause sein."},"simpel":"Feste Überzeugung aus Indizien: »es muss … sein«.<br><span class=\"jp\"><ruby>犯人<rt>はんにん</rt></ruby>は <ruby>彼<rt>かれ</rt></ruby>に<b>違いない</b></span> = „Der Täter muss er sein“","rule":"に違いない zeigt eine starke Schlussfolgerung des Sprechers: »ich bin (fast) sicher, dass …«. Stärker als 〜だろう, subjektiver als 〜はず. Anschluss an Plain-Form; bei な-Adj/Nomen ohne だ."},{"l":11,"t":"〜わけがない / 〜わけにはいかない","de":"kann unmöglich … / darf/kann (aus Prinzip) nicht …","slots":[{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"わけにはいかない","role":"plain","label":"geht nicht"}],"gloss":"わけがない = logisch ausgeschlossen. わけにはいかない = möglich, aber aus Vernunft/Moral unmöglich. Vない + わけにはいかない = »ich MUSS (kann es nicht lassen)«.","ex":{"jp":"あんな <ruby>簡単<rt>かんたん</rt></ruby>な <ruby>問題<rt>もんだい</rt></ruby>を <ruby>間違<rt>まちが</rt></ruby>える<b>わけがない</b>。","de":"So eine leichte Aufgabe kann ich unmöglich falsch machen."},"simpel":"<b>わけがない</b> = »völlig ausgeschlossen«. <b>わけにはいかない</b> = »geht (aus Vernunft/Moral) nicht«.<br><span class=\"jp\"><ruby>今<rt>いま</rt></ruby> <ruby>休<rt>やす</rt></ruby>む<b>わけにはいかない</b></span> = „ich kann jetzt unmöglich Pause machen“","rule":"Zwei verschiedene わけ-Muster: 〜わけがない = logisch unmöglich (»das kann gar nicht sein«). 〜わけにはいかない = es ist zwar möglich, aber aus sozialen/moralischen/vernünftigen Gründen geht es nicht."},{"l":11,"t":"〜<ruby>恐<rt>おそ</rt></ruby>れがある","de":"es besteht die Gefahr, dass … (Negatives)","slots":[{"text":"[Negatives]","role":"cond"},{"text":"<ruby>恐<rt>おそ</rt></ruby>れがある","role":"plain","label":"es droht"}],"gloss":"»Es besteht die Gefahr, dass …« — nur für Unerwünschtes, schriftsprachlich. V辞書形 / N + の.","ex":{"jp":"<ruby>大雨<rt>おおあめ</rt></ruby>で <ruby>川<rt>かわ</rt></ruby>が あふれる<b>恐れがあります</b>。","de":"Durch den Starkregen droht der Fluss über die Ufer zu treten."},"simpel":"Warnung vor etwas Schlechtem: »es droht/es besteht die Gefahr, dass …«.<br><span class=\"jp\"><ruby>台風<rt>たいふう</rt></ruby>が <ruby>来<rt>く</rt></ruby>る<b>恐れがある</b></span> = „es droht ein Taifun“","rule":"〜恐れがある warnt vor einer möglichen negativen Entwicklung. Schriftsprachlich, typisch für Nachrichten und Warnungen. Nur für Unerwünschtes! Anschluss: V辞書形 / N + の."},{"l":11,"t":"〜に <ruby>決<rt>き</rt></ruby>まっている","de":"das ist doch todsicher … / natürlich …","slots":[{"text":"[Aussage]","role":"cond"},{"text":"に<ruby>決<rt>き</rt></ruby>まっている","role":"plain","label":"todsicher"}],"gloss":"»Das ist doch todsicher so.« Subjektive Gewissheit, umgangssprachlich, oft emotional. Plain-Anschluss, な-Adj/N ohne だ.","ex":{"jp":"<ruby>試験<rt>しけん</rt></ruby><ruby>前<rt>まえ</rt></ruby>だから、<ruby>忙<rt>いそが</rt></ruby>しい<b>に決まっている</b>。","de":"Vor der Prüfung ist er doch todsicher beschäftigt."},"simpel":"Sprecher ist völlig überzeugt: »das ist doch klar/todsicher«.<br><span class=\"jp\">こんな <ruby>時間<rt>じかん</rt></ruby>、<ruby>寝<rt>ね</rt></ruby>ている<b>に決まっている</b></span> = „um die Zeit schläft er doch todsicher“","rule":"に決まっている = die (subjektive) Überzeugung des Sprechers, dass etwas selbstverständlich/todsicher so ist. Umgangssprachlich, oft mit leichter Emotion (Ungeduld, »das ist doch offensichtlich«). Anschluss Plain; な-Adj/Nomen ohne だ."},{"l":12,"t":"〜ようになる (allmähliche Veränderung)","de":"dazu kommen, dass … / (nach und nach) anfangen zu (können)","slots":[{"text":"N は","role":"subj"},{"text":"V<sub>可能</sub>","role":"verb"},{"text":"ように なる","role":"plain","label":"kommt dazu"}],"gloss":"»Es kommt (allmählich) dazu, dass …« — neue Fähigkeit/Gewohnheit über die Zeit. Gegenteil: 〜なくなる.","ex":{"jp":"<ruby>練習<rt>れんしゅう</rt></ruby>して、<ruby>日本語<rt>にほんご</rt></ruby>が <ruby>話<rt>はな</rt></ruby>せる<b>ようになりました</b>。","de":"Durch Üben habe ich Japanisch sprechen gelernt."},"simpel":"Zustandswechsel über Zeit — früher nicht, jetzt schon. Oft mit Potenzialform.<br><span class=\"jp\"><ruby>泳<rt>およ</rt></ruby>げる<b>ようになった</b></span> = „habe schwimmen gelernt“","rule":"V<sub>辞書/可能</sub> + ようになる zeigt eine Veränderung über die Zeit: ein neuer Zustand oder eine neue Fähigkeit entsteht allmählich. Verneinung/Gegenteil: 〜なくなる (»es hört auf, dass …«)."},{"l":12,"t":"〜ようにする (sich etw. angewöhnen)","de":"sich bemühen zu … / darauf achten, dass …","slots":[{"text":"[Vorsatz]","role":"cond"},{"text":"ように する","role":"plain","label":"achte darauf"}],"gloss":"»Ich achte bewusst darauf, zu …« — Absicht/Gewohnheit. Vない + ようにする = »darauf achten, NICHT zu …«. ようにしている = laufende Gewohnheit.","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>のため、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>運動<rt>うんどう</rt></ruby>する<b>ようにしています</b>。","de":"Der Gesundheit zuliebe achte ich darauf, täglich Sport zu treiben."},"simpel":"Bewusste Bemühung/Gewohnheit: »ich achte darauf, zu …«.<br><span class=\"jp\"><ruby>毎日<rt>まいにち</rt></ruby> <ruby>歩<rt>ある</rt></ruby>く<b>ようにして</b>います</span> = „ich achte darauf, täglich zu gehen“","rule":"V<sub>辞書/ない</sub> + ようにする drückt eine bewusste Anstrengung oder Gewohnheit aus. ようにしている = laufende Gewohnheit; ようにしてください = höfliche Bitte »achten Sie bitte darauf, zu …«."},{"l":12,"t":"〜(よ)うとする","de":"versuchen zu … / gerade im Begriff sein zu …","slots":[{"text":"V<sub>(よ)う</sub>","role":"verb","label":"Willensform"},{"text":"とする","role":"plain","label":"versuchen"}],"gloss":"»Ich setze an / versuche zu …« oder »bin gerade dabei zu …«. Willensform + とする. Verneint 〜(よ)うとしない = keine Anstalten machen.","ex":{"jp":"ドアを <ruby>開<rt>あ</rt></ruby>け<b>ようとした</b>が、<ruby>開<rt>あ</rt></ruby>かなかった。","de":"Ich wollte die Tür öffnen, doch sie ging nicht auf."},"simpel":"Willensform + とする = »ansetzen/versuchen zu …«.<br><span class=\"jp\"><ruby>出<rt>で</rt></ruby>かけ<b>ようとした</b> とき</span> = „als ich gerade gehen wollte“","rule":"Willensform (V<sub>よう/おう</sub>) + とする: (1) »versuchen zu …« (Anlauf nehmen), (2) »gerade im Begriff sein zu …« (kurz davor). Verneint 〜(よ)うとしない = »macht keine Anstalten zu …«."},{"l":12,"t":"〜ところ (だ) — gerade …","de":"gerade dabei / gerade eben getan / kurz davor","slots":[{"text":"V<sub>辞書/テいる/タ</sub>","role":"verb"},{"text":"ところだ","role":"plain","label":"Phase"}],"gloss":"Drei Phasen: するところ (davor) → しているところ (dabei) → したところ (danach). Zeitliche Phase, nicht der Ort.","ex":{"jp":"<ruby>今<rt>いま</rt></ruby>から <ruby>出<rt>で</rt></ruby>かける<b>ところです</b>。","de":"Ich bin gerade im Begriff loszugehen."},"simpel":"<b>ところ</b> markiert die zeitliche Phase einer Handlung.<br>V<sub>辞書</sub>ところ = gleich · V<sub>テ</sub>いるところ = mittendrin · V<sub>タ</sub>ところ = eben fertig","rule":"ところ (»Punkt/Stelle«) zeigt die Phase: 辞書形 + ところだ = »gerade im Begriff«; ているところだ = »mitten dabei«; たところだ = »eben gerade getan«. Zeitlich, nicht örtlich."},{"l":12,"t":"Vマス + <ruby>切<rt>き</rt></ruby>る / <ruby>切<rt>き</rt></ruby>れない","de":"etw. vollständig tun / es nicht bis zum Ende schaffen","slots":[{"text":"V<sub>マス-Stamm</sub>","role":"verb"},{"text":"きる / きれない","role":"plain","label":"ganz / nicht ganz"}],"gloss":"きる = komplett, restlos, bis zum Ende (oft mit Anstrengung). きれない = zu viel/zu groß, um es zu schaffen. 数えきれない »unzählbar«.","ex":{"jp":"この <ruby>本<rt>ほん</rt></ruby>を <ruby>一日<rt>いちにち</rt></ruby>で <ruby>読<rt>よ</rt></ruby>み<b>きった</b>。","de":"Ich habe dieses Buch an einem Tag ganz durchgelesen."},"simpel":"<b>〜きる</b> = ganz/restlos zu Ende; <b>〜きれない</b> = »nicht zu schaffen«, zu viel.<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べ<b>きれない</b></span> = „kann nicht alles aufessen“","rule":"V<sub>ます</sub>-Stamm + きる = eine Handlung vollständig / bis zum Ende ausführen (使いきる »ganz aufbrauchen«, 走りきる »durchhalten«). Negativ きれない = »es ist zu viel/zu groß, um es fertigzubringen«."},{"l":13,"t":"〜うちに / 〜ないうちに","de":"während (noch) … / bevor …","slots":[{"text":"[Zustand]","role":"cond"},{"text":"うちに","role":"actor","label":"solange / bevor"},{"text":"[Handlung]","role":"verb"}],"gloss":"»Solange (noch) A gilt, tu B« bzw. mit ない »bevor A eintritt, tu B«. Zeitfenster ausnutzen.","ex":{"jp":"<ruby>明<rt>あか</rt></ruby>るい<b>うちに</b> <ruby>帰<rt>かえ</rt></ruby>りましょう。","de":"Lass uns heimgehen, solange es noch hell ist."},"simpel":"Zeitfenster nutzen: »solange (noch) …« bzw. »bevor …«.<br><span class=\"jp\"><ruby>熱<rt>あつ</rt></ruby>い<b>うちに</b> <ruby>食<rt>た</rt></ruby>べて</span> = „iss, solange es noch heiß ist“","rule":"〜うちに = »während ein (meist vorteilhafter) Zustand noch anhält«, oft mit Handlungsaufforderung. 〜ないうちに = »bevor ein (unerwünschter) Zustand eintritt«. Anschluss: V<sub>ている/辞書/ない</sub>, い-Adj, な-Adj + な, N + の."},{"l":13,"t":"〜た とたん(に)","de":"kaum dass … / im selben Moment, als …","slots":[{"text":"V<sub>た</sub>","role":"verb","label":"Moment A"},{"text":"とたん(に)","role":"actor","label":"im selben Moment"},{"text":"[plötzlich B]","role":"cond"}],"gloss":"»Kaum dass A geschah, geschah (überraschend) B.« Nur た-Form davor; B ist unkontrolliert und vergangen.","ex":{"jp":"<ruby>立<rt>た</rt></ruby>ち<ruby>上<rt>あ</rt></ruby>がった<b>とたん</b>、めまいが した。","de":"Kaum war ich aufgestanden, wurde mir schwindelig."},"simpel":"Zwei Ereignisse direkt hintereinander, das zweite meist überraschend.<br><span class=\"jp\">ドアを <ruby>開<rt>あ</rt></ruby>けた<b>とたん</b></span> = „kaum dass ich die Tür öffnete“","rule":"V<sub>た</sub> + とたん(に): »genau in dem Moment, als A geschah, geschah (plötzlich, unerwartet) B«. B ist meist ungeplant und in der Vergangenheit. Nur mit der た-Form davor."},{"l":13,"t":"〜<ruby>最中<rt>さいちゅう</rt></ruby>に","de":"gerade mitten in … / mittendrin, als …","slots":[{"text":"[laufende Handlung]","role":"cond"},{"text":"<ruby>最中<rt>さいちゅう</rt></ruby>に","role":"actor","label":"mittendrin"},{"text":"[Störung]","role":"verb"}],"gloss":"»Genau mitten in der laufenden Handlung passiert (störend) …« V<sub>ている</sub> / N + の davor.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby>の<b>最中に</b> <ruby>電話<rt>でんわ</rt></ruby>が <ruby>鳴<rt>な</rt></ruby>った。","de":"Mitten in der Sitzung klingelte das Telefon."},"simpel":"Etwas passiert mitten in einer laufenden Handlung — meist störend.<br><span class=\"jp\"><ruby>食事<rt>しょくじ</rt></ruby>の<b>最中に</b></span> = „mitten beim Essen“","rule":"〜最中に betont, dass etwas GENAU in der intensivsten Phase einer laufenden Handlung geschieht — häufig eine Störung. Anschluss: V<sub>ている</sub> / N + の."},{"l":13,"t":"〜<ruby>次第<rt>しだい</rt></ruby> / 〜<ruby>次第<rt>しだい</rt></ruby>で","de":"sobald … / je nach … (hängt ab von)","slots":[{"text":"V<sub>マス</sub>","role":"verb"},{"text":"<ruby>次第<rt>しだい</rt></ruby>","role":"plain","label":"sobald"}],"gloss":"(1) V<sub>ます</sub> + 次第 = »sobald …« (formell, Zukunft). (2) N + 次第だ/で = »hängt von N ab / je nach N«.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby>が <ruby>終<rt>お</rt></ruby>わり<b>次第</b>、<ruby>電話<rt>でんわ</rt></ruby>します。","de":"Sobald die Sitzung zu Ende ist, rufe ich an."},"simpel":"V<sub>マス</sub>+次第 = »sobald …« (formell). N+次第で = »je nach …«.<br><span class=\"jp\"><ruby>着<rt>つ</rt></ruby>き<b>次第</b> <ruby>連絡<rt>れんらく</rt></ruby>します</span> = „sobald ich ankomme, melde ich mich“","rule":"Zwei Verwendungen: (1) V<sub>ます</sub>-Stamm + 次第 = »sobald / unmittelbar nachdem …«, sehr formell (Geschäft, nur Zukunft). (2) N + 次第だ / 次第で = »es hängt von N ab / je nach N«."},{"l":13,"t":"Vマス + つつある","de":"ist gerade dabei, sich (allmählich) zu … / zusehends","slots":[{"text":"N が","role":"subj"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"つつある","role":"plain","label":"zusehends"}],"gloss":"»Ein Prozess läuft ab und schreitet voran.« Schriftsprachlich, betont den Verlauf der Veränderung. Nur mit Veränderungsverben.","ex":{"jp":"<ruby>森<rt>もり</rt></ruby>が <ruby>消<rt>き</rt></ruby>え<b>つつある</b>。","de":"Die Wälder verschwinden zusehends."},"simpel":"Ein Vorgang ist im Verlauf: »entwickelt sich allmählich zu …«.<br><span class=\"jp\"><ruby>景気<rt>けいき</rt></ruby>が <ruby>回復<rt>かいふく</rt></ruby>し<b>つつある</b></span> = „die Konjunktur erholt sich zusehends“","rule":"V<sub>ます</sub>-Stamm + つつある: ein Prozess läuft gerade ab und schreitet voran. Schriftsprachlich; betont (anders als 〜ている) den Verlauf bzw. die Tendenz einer Veränderung."},{"l":14,"t":"〜おかげで / 〜せいで","de":"dank … (positiv) / wegen … (negativ)","slots":[{"text":"[Grund]","role":"cond"},{"text":"おかげで / せいで","role":"actor","label":"dank / wegen"},{"text":"[Ergebnis]","role":"verb"}],"gloss":"おかげで = dankbar (gutes Ergebnis), せいで = vorwurfsvoll (schlechtes Ergebnis). Neutralen Grund → から/ので.","ex":{"jp":"<ruby>先生<rt>せんせい</rt></ruby>の<b>おかげで</b> <ruby>合格<rt>ごうかく</rt></ruby>できた。","de":"Dank des Lehrers habe ich bestanden."},"simpel":"<b>おかげで</b> = »dank« (gutes Ergebnis). <b>せいで</b> = »wegen« (schlechtes Ergebnis).<br><span class=\"jp\"><ruby>雨<rt>あめ</rt></ruby>の<b>せいで</b> <ruby>遅<rt>おく</rt></ruby>れた</span> = „wegen des Regens zu spät“","rule":"Beide nennen einen Grund, aber mit Wertung: おかげで dankbar/positiv, せいで vorwurfsvoll/negativ. Anschluss wie ans Nomen (Plain, な-Adj + な, N + の)."},{"l":14,"t":"〜せいか","de":"vielleicht wegen … / womöglich weil …","slots":[{"text":"[vermuteter Grund]","role":"cond"},{"text":"せいか","role":"actor","label":"vielleicht weil"},{"text":"[Ergebnis]","role":"verb"}],"gloss":"»Vielleicht (weiß nicht genau) wegen … ist es so.« Unsicherer, spürbarer Grund. N + の + せいか.","ex":{"jp":"<ruby>緊張<rt>きんちょう</rt></ruby>の<b>せいか</b>、うまく <ruby>話<rt>はな</rt></ruby>せなかった。","de":"Vielleicht wegen der Nervosität konnte ich nicht gut sprechen."},"simpel":"Vermuteter, unsicherer Grund: »vielleicht weil …«.<br><span class=\"jp\"><ruby>年<rt>とし</rt></ruby>の<b>せいか</b> <ruby>疲<rt>つか</rt></ruby>れやすい</span> = „vielleicht wegen des Alters schnell müde“","rule":"せいか = »ich bin nicht sicher, aber vielleicht ist … der Grund«. Wie せいで, aber mit dem か der Unsicherheit — für einen spürbaren, aber nicht bewiesenen Zusammenhang."},{"l":14,"t":"〜ものだから / 〜もので","de":"weil (nun mal) … (Rechtfertigung / Erklärung)","slots":[{"text":"[Grund]","role":"cond"},{"text":"ものだから","role":"actor","label":"weil nun mal"},{"text":"[Folge/Ausrede]","role":"verb"}],"gloss":"»Weil es eben so war, konnte ich nicht anders.« Subjektive Rechtfertigung. Plain-Anschluss (な-Adj + な, N + な). Kein Befehl im Hauptsatz.","ex":{"jp":"<ruby>子<rt>こ</rt></ruby>どもが <ruby>熱<rt>ねつ</rt></ruby>を <ruby>出<rt>だ</rt></ruby>した<b>ものだから</b>、<ruby>休<rt>やす</rt></ruby>みました。","de":"Weil mein Kind Fieber bekam, bin ich zu Hause geblieben."},"simpel":"Persönliche Rechtfertigung: »ist ja/nun mal so, deshalb …«.<br><span class=\"jp\"><ruby>安<rt>やす</rt></ruby>かった<b>ものだから</b>、<ruby>買<rt>か</rt></ruby>いすぎた</span> = „es war ja so billig, drum kaufte ich zu viel“","rule":"〜ものだから (locker もので/もんで) gibt einen Grund als Entschuldigung/Erklärung an — »weil es eben so war, konnte ich nicht anders«. Subjektiv, rechtfertigend. Anschluss Plain (な-Adj + な, N + な)."},{"l":14,"t":"〜ものの","de":"zwar …, aber (doch) …","slots":[{"text":"[A: zwar]","role":"cond"},{"text":"ものの","role":"actor","label":"aber doch"},{"text":"[B: unerwartet]","role":"verb"}],"gloss":"»A trifft zwar zu, doch die erwartete Folge B bleibt aus.« Schriftsprachlich. Nicht mit の (Nominalisierung) verwechseln.","ex":{"jp":"<ruby>免許<rt>めんきょ</rt></ruby>は <ruby>取<rt>と</rt></ruby>った<b>ものの</b>、<ruby>車<rt>くるま</rt></ruby>が ない。","de":"Den Führerschein habe ich zwar, aber kein Auto."},"simpel":"Einräumung: »zwar A, aber (entgegen der Erwartung) B«.<br><span class=\"jp\"><ruby>買<rt>か</rt></ruby>った<b>ものの</b>、<ruby>使<rt>つか</rt></ruby>っていない</span> = „gekauft habe ich es zwar, aber ich nutze es nicht“","rule":"〜ものの verbindet zwei Sätze mit Widerspruch: A trifft zu, doch die erwartete Folge tritt nicht ein. Schriftlicher als 〜けど. Anschluss Plain (な-Adj + な/である, N + である)."},{"l":14,"t":"〜わりに(は)","de":"im Verhältnis zu … / für … (überraschend)","slots":[{"text":"[Maßstab A]","role":"cond"},{"text":"わりに(は)","role":"actor","label":"für / gemessen an"},{"text":"[unerwartetes B]","role":"verb"}],"gloss":"»Gemessen an A ist B unerwartet.« Vergleicht Erwartung mit Realität. Plain / N + の. Verwandt: 〜にしては.","ex":{"jp":"たくさん <ruby>食<rt>た</rt></ruby>べる<b>わりに</b> <ruby>太<rt>ふと</rt></ruby>らない。","de":"Für die Menge, die er isst, nimmt er erstaunlich wenig zu."},"simpel":"Ergebnis passt nicht zur Erwartung aus A: »für A überraschend …«.<br><span class=\"jp\"><ruby>値段<rt>ねだん</rt></ruby>の<b>わりに</b> おいしい</span> = „für den Preis (erstaunlich) lecker“","rule":"〜わりに(は): »gemessen an A ist B unerwartet (viel/wenig/gut/schlecht)«. Vergleicht Erwartung mit Realität. Anschluss Plain (な-Adj + な, N + の)."},{"l":15,"t":"〜くせに","de":"obwohl … (mit Vorwurf / Verachtung)","slots":[{"text":"[A: obwohl]","role":"cond"},{"text":"くせに","role":"actor","label":"obwohl (Vorwurf)"},{"text":"[B: Kritik]","role":"verb"}],"gloss":"»Obwohl A — und das ist frech/unpassend — B.« Immer wertend/negativ. Meist gleiches Subjekt. Neutral wäre のに.","ex":{"jp":"<ruby>知<rt>し</rt></ruby>っている<b>くせに</b>、<ruby>教<rt>おし</rt></ruby>えて くれない。","de":"Obwohl er es weiß, sagt er es mir nicht."},"simpel":"Wie のに, aber mit Kritik/Verachtung: »obwohl … (und das ist frech/unpassend)«.<br><span class=\"jp\"><ruby>知<rt>し</rt></ruby>っている<b>くせに</b></span> = „obwohl er es doch weiß (Frechheit)“","rule":"〜くせに = adversativ »obwohl«, aber immer mit negativer Gefühlswertung (Vorwurf, Verachtung, Spott). Subjekt von Neben- und Hauptsatz meist dieselbe Person. Anschluss Plain (な-Adj + な, N + の)."},{"l":15,"t":"〜こそ","de":"gerade / genau dies / jetzt erst recht","slots":[{"text":"N","role":"subj","label":"Hervorhebung"},{"text":"こそ","role":"actor","label":"genau dies"},{"text":"[Aussage]","role":"verb"}],"gloss":"»Genau dieses, kein anderes / jetzt erst recht.« Starke Hervorhebung. 〜からこそ = »gerade weil«.","ex":{"jp":"<ruby>今<rt>いま</rt></ruby><b>こそ</b> <ruby>始<rt>はじ</rt></ruby>める ときだ。","de":"Jetzt erst recht ist es Zeit anzufangen."},"simpel":"Hebt ein Wort nachdrücklich hervor: »genau das, kein anderes«.<br><span class=\"jp\"><ruby>今<rt>いま</rt></ruby><b>こそ</b></span> = „jetzt erst recht / genau jetzt“","rule":"こそ hängst du an ein Nomen/Wort und betonst es stark: »genau dieses«. Häufig 今こそ (jetzt erst recht), こちらこそ (ganz meinerseits), 〜からこそ (gerade weil)."},{"l":15,"t":"〜さえ / 〜さえ〜ば","de":"sogar … / wenn nur … (dann reicht's)","slots":[{"text":"N さえ","role":"cond","label":"wenn nur N"},{"text":"…ば","role":"actor","label":"dann"},{"text":"[reicht es]","role":"verb"}],"gloss":"さえ = »sogar/selbst«. さえ〜ば = »die einzige nötige Bedingung; wenn die erfüllt ist, genügt es«. Vマス + さえすれば.","ex":{"jp":"<ruby>子<rt>こ</rt></ruby>ども<b>さえ</b> <ruby>知<rt>し</rt></ruby>っている。","de":"Sogar Kinder wissen das."},"simpel":"<b>さえ</b> = »sogar«; <b>さえ〜ば</b> = »wenn nur …, dann«.<br><span class=\"jp\"><ruby>水<rt>みず</rt></ruby><b>さえ</b> あれば</span> = „wenn es nur Wasser gibt“","rule":"さえ = »sogar/selbst« (extremes Beispiel). Kombiniert さえ〜ば = »die einzige Bedingung ist …; ist die erfüllt, reicht es«. Nomen + さえ; Verb ます-Stamm + さえ すれば."},{"l":15,"t":"〜ずには いられない","de":"ich kann nicht anders, als zu … / muss einfach","slots":[{"text":"V<sub>ない語幹</sub>","role":"verb"},{"text":"ずには いられない","role":"plain","label":"muss einfach"}],"gloss":"»Ich kann den Drang zu V nicht unterdrücken.« V<sub>ない</sub>-Stamm + ずには. する → せずに. Emotional/unwillkürlich.","ex":{"jp":"あの <ruby>映画<rt>えいが</rt></ruby>を <ruby>見<rt>み</rt></ruby>ると、<ruby>泣<rt>な</rt></ruby>か<b>ずには いられない</b>。","de":"Bei dem Film muss ich einfach weinen."},"simpel":"Ein Gefühl ist unwiderstehlich: »ich kann nicht anders, als zu …«.<br><span class=\"jp\"><ruby>笑<rt>わら</rt></ruby>わ<b>ずには いられない</b></span> = „ich muss einfach lachen“","rule":"V<sub>ない</sub>-Stamm + ずにはいられない (する→せずに): der Sprecher kann einen inneren Drang nicht unterdrücken. Formeller/emotionaler als 〜ないではいられない."},{"l":15,"t":"〜どころか","de":"von wegen … / ganz im Gegenteil","slots":[{"text":"[Erwartung X]","role":"cond"},{"text":"どころか","role":"actor","label":"von wegen"},{"text":"[Realität ≠ X]","role":"verb"}],"gloss":"»Von wegen X — in Wirklichkeit das Gegenteil / viel mehr.« Reißt die Erwartung des Hörers ein. Oft + 〜も…ない.","ex":{"jp":"<ruby>休<rt>やす</rt></ruby>む<b>どころか</b>、もっと <ruby>忙<rt>いそが</rt></ruby>しくなった。","de":"Von wegen ausruhen — es wurde nur noch stressiger."},"simpel":"Reißt eine Erwartung ein: »von wegen X — in Wirklichkeit …«.<br><span class=\"jp\"><ruby>休<rt>やす</rt></ruby>む<b>どころか</b></span> = „von wegen ausruhen (im Gegenteil)“","rule":"V/Adj/N + どころか: nennt eine Erwartung X und stellt klar, dass die Realität ganz anders ist — oft das Gegenteil oder viel extremer. Anschluss Plain / Nomen."},{"l":16,"t":"〜ことか","de":"wie sehr …! (emotionaler Ausruf)","slots":[{"text":"どんなに","role":"actor","label":"wie sehr"},{"text":"[Plain]","role":"cond"},{"text":"ことか","role":"plain","label":"…!"}],"gloss":"»Wie sehr … (!)« — Ausruf starker Emotion mit Fragewort, keine echte Frage. Gehoben.","ex":{"jp":"どんなに <ruby>心配<rt>しんぱい</rt></ruby>した<b>ことか</b>。","de":"Wie große Sorgen ich mir gemacht habe!"},"simpel":"Emotionaler Ausruf mit Fragewort: »wie sehr …!«.<br><span class=\"jp\">どんなに <ruby>嬉<rt>うれ</rt></ruby>しかった<b>ことか</b></span> = „wie sehr ich mich gefreut habe!“","rule":"Fragewort (どんなに / なんと / どれほど) + Plain + ことか: ein Ausruf starker Emotion, KEINE echte Frage. Schriftlich/gehoben. Anschluss Plain (な-Adj + な)."},{"l":16,"t":"〜ものか / 〜もんか","de":"niemals! / auf gar keinen Fall werde ich …","slots":[{"text":"[Plain]","role":"cond"},{"text":"ものか / もんか","role":"plain","label":"niemals!"}],"gloss":"»Als ob ich …! Auf keinen Fall.« Frageform, aber Bedeutung = starke Verneinung. Trotzig, gesprochen. もんか = lockerer.","ex":{"jp":"<ruby>二度<rt>にど</rt></ruby>と <ruby>行<rt>い</rt></ruby>く<b>ものか</b>。","de":"Da gehe ich nie wieder hin!"},"simpel":"Starke Verweigerung als rhetorische Frage: »niemals!«.<br><span class=\"jp\"><ruby>負<rt>ま</rt></ruby>ける<b>ものか</b></span> = „niemals verliere ich!“","rule":"V/Adj (Plain) + ものか (locker もんか): emphatische Verneinung in Frageform — »als ob ich …! auf keinen Fall«. Gesprochen, emotional/trotzig."},{"l":16,"t":"〜まい","de":"werde gewiss nicht … / wird wohl nicht …","slots":[{"text":"V","role":"verb"},{"text":"まい","role":"plain","label":"gewiss nicht"}],"gloss":"(1) »ich werde bestimmt nicht …« (Entschluss) oder (2) »wird wohl nicht …« (Vermutung). Gehoben. Anschluss variiert je Verbtyp.","ex":{"jp":"もう <ruby>泣<rt>な</rt></ruby>く<b>まい</b>と <ruby>決<rt>き</rt></ruby>めた。","de":"Ich habe beschlossen, nie wieder zu weinen."},"simpel":"Negative Willens- oder Vermutungsform: »ich werde ganz sicher nicht …«.<br><span class=\"jp\">もう <ruby>二度<rt>にど</rt></ruby>と <ruby>行<rt>い</rt></ruby>く<b>まい</b></span> = „ich gehe gewiss nie wieder hin“","rule":"〜まい: (1) negativer Wille »ich werde bestimmt nicht …« (Entschluss); (2) negative Vermutung »wird wohl nicht …«. Schriftlich/gehoben."},{"l":16,"t":"〜ことなく","de":"ohne (je) zu …","slots":[{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"ことなく","role":"actor","label":"ohne je zu"},{"text":"[Haupthandlung]","role":"cond"}],"gloss":"»Ohne (auch nur einmal) zu V …« Schriftsprachlich, nachdrücklicher als 〜ないで. Betont das völlige Ausbleiben.","ex":{"jp":"<ruby>一度<rt>いちど</rt></ruby>も <ruby>休<rt>やす</rt></ruby>む<b>ことなく</b> <ruby>働<rt>はたら</rt></ruby>いた。","de":"Er arbeitete, ohne ein einziges Mal Pause zu machen."},"simpel":"Schriftliches »ohne zu …«: »ohne (auch nur einmal) zu …«.<br><span class=\"jp\">ふり<ruby>返<rt>かえ</rt></ruby>る<b>ことなく</b></span> = „ohne sich umzudrehen“","rule":"V<sub>辞書形</sub> + ことなく = »ohne (auch nur einmal) zu …«. Schriftsprachlicher/nachdrücklicher als 〜ないで. Betont, dass etwas gar nicht geschah."},{"l":16,"t":"〜てこそ","de":"erst dadurch, dass … (wirklich)","slots":[{"text":"V<sub>テ</sub>","role":"verb"},{"text":"こそ","role":"actor","label":"erst dadurch"},{"text":"[B: das Eigentliche]","role":"cond"}],"gloss":"»Erst wenn man wirklich A tut, ergibt sich B.« A ist die unverzichtbare Voraussetzung. Gehoben, oft in Weisheiten.","ex":{"jp":"<ruby>努力<rt>どりょく</rt></ruby>し<b>てこそ</b>、<ruby>成功<rt>せいこう</rt></ruby>が ある。","de":"Erst durch echte Anstrengung gibt es Erfolg."},"simpel":"Erst durch A wird B möglich/wahr: »erst wenn man wirklich A tut, …«.<br><span class=\"jp\"><ruby>努力<rt>どりょく</rt></ruby>し<b>てこそ</b></span> = „erst wenn man sich wirklich anstrengt“","rule":"V<sub>テ</sub> + こそ: »erst dadurch, dass man (wirklich) A tut, ergibt sich B (das Eigentliche/Wertvolle)«. Hebt A als unverzichtbare Voraussetzung hervor. Gehoben."},{"l":17,"t":"〜に<ruby>対<rt>たい</rt></ruby>して","de":"gegenüber … / gegen … / im Gegensatz zu …","slots":[{"text":"N","role":"subj","label":"Adressat"},{"text":"に<ruby>対<rt>たい</rt></ruby>して","role":"actor","label":"gegenüber"},{"text":"[Haltung/Handlung]","role":"verb"}],"gloss":"»gegenüber / gegen N« (Adressat einer Haltung) oder »im Gegensatz zu« (Kontrast). Attributiv: に対する + N.","ex":{"jp":"<ruby>質問<rt>しつもん</rt></ruby><b>に対して</b> <ruby>答<rt>こた</rt></ruby>える。","de":"Auf die Frage antworten."},"simpel":"Richtung/Gegenüber einer Handlung — oder ein Kontrast.<br><span class=\"jp\"><ruby>先生<rt>せんせい</rt></ruby><b>に対して</b> <ruby>失礼<rt>しつれい</rt></ruby>だ</span> = „dem Lehrer gegenüber unhöflich“","rule":"N + に対して: (1) »gegenüber / gegen« — Ziel/Adressat einer Haltung oder Handlung; (2) Kontrast »im Gegensatz zu, wohingegen«. Attributiv: に対する + N."},{"l":17,"t":"〜に<ruby>比<rt>くら</rt></ruby>べて","de":"im Vergleich zu …","slots":[{"text":"N","role":"subj","label":"Vergleichsbasis"},{"text":"に<ruby>比<rt>くら</rt></ruby>べて","role":"actor","label":"verglichen mit"},{"text":"[Unterschied]","role":"verb"}],"gloss":"»Verglichen mit N ist …« — stellt die Vergleichsbasis heraus. Etwas formeller als より.","ex":{"jp":"<ruby>去年<rt>きょねん</rt></ruby><b>に比べて</b> <ruby>暑<rt>あつ</rt></ruby>い。","de":"Verglichen mit dem letzten Jahr ist es heiß."},"simpel":"Vergleichsbasis: »verglichen mit …«.<br><span class=\"jp\"><ruby>去年<rt>きょねん</rt></ruby><b>に比べて</b></span> = „im Vergleich zum letzten Jahr“","rule":"N + に比べて = »verglichen mit N«. Stellt einen Maßstab für einen Vergleich auf. Variante に比べ (formeller)."},{"l":17,"t":"〜に<ruby>加<rt>くわ</rt></ruby>えて","de":"zusätzlich zu … / neben …","slots":[{"text":"N","role":"subj","label":"Basis"},{"text":"に<ruby>加<rt>くわ</rt></ruby>えて","role":"actor","label":"zusätzlich zu"},{"text":"[+ etwas mehr]","role":"verb"}],"gloss":"»Zusätzlich zu N kommt noch …« — fügt eine weitere Sache hinzu, schriftlich, oft mit も.","ex":{"jp":"<ruby>雨<rt>あめ</rt></ruby><b>に加えて</b>、<ruby>風<rt>かぜ</rt></ruby>も <ruby>強<rt>つよ</rt></ruby>くなった。","de":"Zusätzlich zum Regen wurde auch der Wind stärker."},"simpel":"Etwas kommt hinzu: »zusätzlich zu …«.<br><span class=\"jp\"><ruby>雨<rt>あめ</rt></ruby><b>に加えて</b> <ruby>風<rt>かぜ</rt></ruby>も</span> = „zusätzlich zum Regen auch Wind“","rule":"N + に加えて = »zusätzlich zu N (kommt noch …)«. Fügt eine weitere Sache/Eigenschaft hinzu; schriftlich. Oft mit も im Folgeteil."},{"l":17,"t":"〜に<ruby>関<rt>かん</rt></ruby>して","de":"bezüglich … / in Bezug auf …","slots":[{"text":"N","role":"subj","label":"Thema"},{"text":"に<ruby>関<rt>かん</rt></ruby>して","role":"actor","label":"bezüglich"},{"text":"[Aussage]","role":"verb"}],"gloss":"»Bezüglich N / was N betrifft …« — formeller als について. Attributiv: に関する + N.","ex":{"jp":"<ruby>事件<rt>じけん</rt></ruby><b>に関して</b> <ruby>話<rt>はな</rt></ruby>す。","de":"Über den Vorfall sprechen."},"simpel":"Formelles »über/bezüglich«: das Thema einer Aussage.<br><span class=\"jp\">その <ruby>件<rt>けん</rt></ruby><b>に関して</b></span> = „bezüglich dieser Sache“","rule":"N + に関して = »bezüglich N / was N betrifft«, formeller als について. Attributiv: に関する + N."},{"l":17,"t":"〜において / 〜における","de":"in / bei / auf (Ort, Zeit, Bereich) — formell","slots":[{"text":"N","role":"time","label":"Ort/Zeit/Bereich"},{"text":"において","role":"actor","label":"in/bei"},{"text":"[Ereignis]","role":"verb"}],"gloss":"Formelles で: »in/bei/auf« für Ort, Zeit oder abstrakten Bereich. Nur schriftlich/formell. Attributiv: における + N.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby><b>において</b> <ruby>決定<rt>けってい</rt></ruby>された。","de":"Bei der Sitzung wurde es beschlossen."},"simpel":"Formelles で für Ort/Zeit/Bereich: »in/bei«.<br><span class=\"jp\"><ruby>会議<rt>かいぎ</rt></ruby><b>において</b></span> = „bei der Sitzung“","rule":"N + において = formelles »in/bei/auf« für Ort, Zeitpunkt oder abstrakten Bereich (wie で, aber schriftlich). Attributiv: における + N."},{"l":18,"t":"Vマス / N + がち","de":"neigt zu … / oft … (meist negativ)","slots":[{"text":"V<sub>マス</sub> / N","role":"subj"},{"text":"がち","role":"plain","label":"neigt zu (oft)"}],"gloss":"»Neigt dazu / passiert oft« — meist etwas Negatives. Vます-Stamm oder Nomen + がち.","ex":{"jp":"<ruby>最近<rt>さいきん</rt></ruby> <ruby>疲<rt>つか</rt></ruby>れ<b>がち</b>だ。","de":"In letzter Zeit bin ich oft müde."},"simpel":"Tendenz, oft unerwünscht: »neigt dazu, zu …«.<br><span class=\"jp\"><ruby>忘<rt>わす</rt></ruby>れ<b>がち</b></span> = „vergisst oft / neigt zum Vergessen“","rule":"V<sub>ます</sub>-Stamm / Nomen + がち = »neigt zu …, tut oft …«, meist etwas Negatives/Unerwünschtes. 病気がち »kränklich«, 遅れがち »oft verspätet«."},{"l":18,"t":"〜っぽい","de":"wirkt wie … / neigt zu … / -haft","slots":[{"text":"N / V<sub>マス</sub>","role":"subj"},{"text":"っぽい","role":"plain","label":"wirkt wie / neigt zu"}],"gloss":"»Hat den Anschein/die Neigung von …« Wird wie ein い-Adjektiv gebeugt. 忘れっぽい »vergesslich«, 水っぽい »wässrig«.","ex":{"jp":"この スープは <ruby>水<rt>みず</rt></ruby><b>っぽい</b>。","de":"Diese Suppe ist wässrig."},"simpel":"»wirkt wie / hat viel von …« — macht Adjektive aus Nomen/Verben.<br><span class=\"jp\"><ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b></span> = „kindisch“","rule":"N / V<sub>ます</sub> / Adj-Stamm + っぽい = »hat den Anschein/die Neigung von …«. Wird wie ein い-Adjektiv verwendet. 水っぽい »wässrig«, 忘れっぽい »vergesslich«, 怒りっぽい »reizbar«."},{"l":18,"t":"N + <ruby>向<rt>む</rt></ruby>き / N + <ruby>向<rt>む</rt></ruby>け","de":"geeignet für … / gerichtet an … (Zielgruppe)","slots":[{"text":"N","role":"subj","label":"Zielgruppe"},{"text":"<ruby>向<rt>む</rt></ruby>き / <ruby>向<rt>む</rt></ruby>け","role":"plain","label":"passt / extra für"}],"gloss":"向き = »passt (von selbst) zu« (zufällige Eignung). 向け = »eigens gemacht für« (bewusste Zielgruppe).","ex":{"jp":"この <ruby>仕事<rt>しごと</rt></ruby>は <ruby>女性<rt>じょせい</rt></ruby><b>向き</b>だ。","de":"Diese Arbeit eignet sich für Frauen."},"simpel":"<b>向き</b> = passt (von Natur) zu; <b>向け</b> = eigens gemacht für.<br><span class=\"jp\"><ruby>初心者<rt>しょしんしゃ</rt></ruby><b>向け</b></span> = „für Anfänger (gemacht)“","rule":"N + 向き = »passt/eignet sich für« (eine Eigenschaft passt zufällig). N + 向け = »eigens gerichtet an / hergestellt für« (bewusste Zielgruppe)."},{"l":18,"t":"〜らしい","de":"anscheinend … / typisch für … (echt …)","slots":[{"text":"[Plain] / N","role":"subj"},{"text":"らしい","role":"plain","label":"anscheinend / typisch"}],"gloss":"(1) Plain + らしい = »anscheinend« (aus Info). (2) N + らしい = »typisch/echt N« (男らしい). Wird wie い-Adj gebeugt.","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は <ruby>来<rt>こ</rt></ruby>ない<b>らしい</b>。","de":"Anscheinend kommt er nicht."},"simpel":"Zwei Sinne: »anscheinend« (Hörensagen) und »typisch/echt …«.<br><span class=\"jp\"><ruby>春<rt>はる</rt></ruby><b>らしい</b> <ruby>天気<rt>てんき</rt></ruby></span> = „echtes Frühlingswetter“","rule":"(1) Plain + らしい = »anscheinend / es heißt« (Vermutung aus zuverlässiger Info). (2) N + らしい = »typisch für N, wie es sich für N gehört« (男らしい »männlich«, 学生らしい »wie ein echter Student«)."},{"l":18,"t":"〜かのようだ / かのように","de":"(gerade) so, als ob …","slots":[{"text":"まるで","role":"actor","label":"gerade so"},{"text":"[Plain]","role":"cond"},{"text":"かのようだ","role":"plain","label":"als ob"}],"gloss":"»So, als ob … (in Wahrheit aber nicht).« Irrealer Vergleich, oft mit まるで. Adverbial かのように, attributiv かのような.","ex":{"jp":"まるで <ruby>何<rt>なに</rt></ruby>も なかった<b>かのように</b> <ruby>話<rt>はな</rt></ruby>す。","de":"Er redet, als ob nichts gewesen wäre."},"simpel":"Irrealer Vergleich, oft mit まるで: »als ob …«.<br><span class=\"jp\">まるで <ruby>夢<rt>ゆめ</rt></ruby>を <ruby>見<rt>み</rt></ruby>ている<b>かのようだ</b></span> = „als ob man träumt“","rule":"Plain + かのようだ = »so, als ob (in Wirklichkeit aber nicht)«. Vergleich mit etwas Irrealem/Unwahrem, oft mit まるで. Adverbial かのように, attributiv かのような."},{"l":19,"t":"〜たびに","de":"jedes Mal, wenn …","slots":[{"text":"V<sub>辞書</sub> / N の","role":"cond"},{"text":"たびに","role":"actor","label":"jedes Mal"},{"text":"[B]","role":"verb"}],"gloss":"»Jedes Mal, wenn A (geschieht), (geschieht) B.« Regelmäßige Kopplung. Nomen braucht の.","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>に <ruby>会<rt>あ</rt></ruby>う<b>たびに</b>、<ruby>元気<rt>げんき</rt></ruby>を もらう。","de":"Jedes Mal, wenn ich ihn treffe, gibt er mir Energie."},"simpel":"»immer wenn A, (dann) B«.<br><span class=\"jp\"><ruby>会<rt>あ</rt></ruby>う<b>たびに</b></span> = „jedes Mal, wenn wir uns treffen“","rule":"V<sub>辞書</sub> / N + の + たびに = »jedes Mal, wenn / bei jedem …«. B tritt regelmäßig zusammen mit A auf."},{"l":19,"t":"〜ば〜ほど","de":"je …, desto …","slots":[{"text":"V<sub>ば</sub>","role":"cond","label":"je …"},{"text":"V<sub>辞書</sub> + ほど","role":"actor","label":"desto …"},{"text":"[Folge]","role":"verb"}],"gloss":"»Je mehr A, desto mehr B.« Dasselbe Wort zweimal (ば-Form + 辞書形 + ほど).","ex":{"jp":"<ruby>考<rt>かんが</rt></ruby>えれば <ruby>考<rt>かんが</rt></ruby>える<b>ほど</b> わからない。","de":"Je mehr ich nachdenke, desto weniger verstehe ich."},"simpel":"Proportional: »je mehr A, desto mehr B«.<br><span class=\"jp\"><ruby>考<rt>かんが</rt></ruby>えれば <ruby>考<rt>かんが</rt></ruby>える<b>ほど</b></span> = „je mehr ich nachdenke“","rule":"V<sub>ば</sub> + V<sub>辞書</sub> + ほど (い-Adj: ければ〜いほど; な-Adj: なら〜なほど): »je …, desto …«. Beide Male dasselbe Wort."},{"l":19,"t":"N + だらけ","de":"voller … (meist unangenehm)","slots":[{"text":"N","role":"subj"},{"text":"だらけ","role":"plain","label":"voller (negativ)"}],"gloss":"»Übersät/ganz voller N« — fast immer negativ (Schmutz, Fehler, Blut). Betont die unangenehme Menge.","ex":{"jp":"<ruby>部屋<rt>へや</rt></ruby>が ほこり<b>だらけ</b>だ。","de":"Das Zimmer ist voller Staub."},"simpel":"Übervoll mit etwas Unangenehmem: »voller …«.<br><span class=\"jp\"><ruby>間違<rt>まちが</rt></ruby>い<b>だらけ</b></span> = „voller Fehler“","rule":"N + だらけ = »ganz/übersät voller N«, fast immer negativ (Schmutz, Fehler, Blut …). Betont die unangenehm große Menge/Verteilung."},{"l":19,"t":"〜だけでなく(〜も)","de":"nicht nur …, (sondern auch) …","slots":[{"text":"[A]","role":"cond"},{"text":"だけでなく","role":"actor","label":"nicht nur"},{"text":"[B] も","role":"verb","label":"sondern auch"}],"gloss":"»Nicht nur A, sondern auch B.« Zweiter Teil oft mit も. Formeller: 〜のみならず.","ex":{"jp":"この <ruby>店<rt>みせ</rt></ruby>は <ruby>安<rt>やす</rt></ruby>い<b>だけでなく</b>、おいしい。","de":"Dieser Laden ist nicht nur billig, sondern auch lecker."},"simpel":"Fügt hinzu: »nicht nur A, sondern auch B«.<br><span class=\"jp\"><ruby>安<rt>やす</rt></ruby>い<b>だけでなく</b></span> = „nicht nur billig …“","rule":"…だけでなく + …も = »nicht nur A, sondern auch B«. Anschluss wie ans Nomen (Plain, な-Adj + な, N direkt). Formeller: 〜のみならず."},{"l":19,"t":"〜とおり(に) / N + どおり","de":"so wie … / gemäß …","slots":[{"text":"V<sub>辞書/た</sub> / N の","role":"cond"},{"text":"とおり(に)","role":"actor","label":"so wie"},{"text":"[Handlung]","role":"verb"}],"gloss":"»Genau so wie A.« An Nomen direkt → どおり (時間どおり, 期待どおり). ≈ 〜ように.","ex":{"jp":"<ruby>私<rt>わたし</rt></ruby>が <ruby>言<rt>い</rt></ruby>う<b>とおりに</b> して。","de":"Mach genau so, wie ich sage."},"simpel":"Etwas geschieht genau wie A: »so wie …«.<br><span class=\"jp\"><ruby>言<rt>い</rt></ruby>った<b>とおりに</b></span> = „genau so, wie ich gesagt habe“","rule":"V<sub>辞書/た</sub> / N + の + とおり(に) = »genau so wie …«. An ein Nomen direkt angehängt wird とおり klanglich zu どおり: 予定どおり »planmäßig«."},{"l":20,"t":"〜にとって","de":"für … / aus Sicht von …","slots":[{"text":"N","role":"subj","label":"Perspektive"},{"text":"にとって","role":"actor","label":"für / aus Sicht von"},{"text":"[Bewertung]","role":"verb"}],"gloss":"»Für N / aus der Sicht von N (ist etwas wichtig/schwer …).« Leitet eine Bewertung aus jds. Perspektive ein.","ex":{"jp":"<ruby>私<rt>わたし</rt></ruby><b>にとって</b> <ruby>家族<rt>かぞく</rt></ruby>は <ruby>一番<rt>いちばん</rt></ruby> <ruby>大切<rt>たいせつ</rt></ruby>だ。","de":"Für mich ist die Familie das Wichtigste."},"simpel":"Standpunkt einer Bewertung: »für jdn / aus jds. Sicht«.<br><span class=\"jp\"><ruby>私<rt>わたし</rt></ruby><b>にとって</b></span> = „für mich (aus meiner Sicht)“","rule":"N + にとって = »für N / aus der Sicht von N«, leitet eine Bewertung aus jemandes Perspektive ein (wichtig, schwer, wertvoll …). Attributiv: にとっての + N."},{"l":20,"t":"〜あげく(に)","de":"nach langem … schließlich (meist schlecht)","slots":[{"text":"V<sub>た</sub>","role":"cond","label":"nach langem A"},{"text":"あげく(に)","role":"actor","label":"schließlich"},{"text":"[schlechtes B]","role":"verb"}],"gloss":"»Nach langem/mühsamem A kam es schließlich zu (meist schlechtem) B.« Nur nach た-Form / N + の.","ex":{"jp":"<ruby>悩<rt>なや</rt></ruby>んだ<b>あげく</b>、<ruby>留学<rt>りゅうがく</rt></ruby>を やめた。","de":"Nach langem Grübeln gab ich den Auslandsaufenthalt auf."},"simpel":"Nach viel A ein (meist übles) Endergebnis.<br><span class=\"jp\"><ruby>悩<rt>なや</rt></ruby>んだ<b>あげく</b></span> = „nach langem Grübeln schließlich“","rule":"V<sub>た</sub> / N + の + あげく(に) = »nach langem/vielem A kam es schließlich zu B« — B ist meist ein negatives Endergebnis. Betont den mühsamen Prozess davor."},{"l":20,"t":"〜<ruby>気<rt>き</rt></ruby>がする","de":"ich habe das Gefühl, dass …","slots":[{"text":"[Plain]","role":"cond"},{"text":"<ruby>気<rt>き</rt></ruby>がする","role":"plain","label":"habe das Gefühl"}],"gloss":"»Ich habe das (unsichere) Gefühl, dass …« Subjektive Ahnung ohne Beweis, oft mit ような.","ex":{"jp":"どこかで <ruby>会<rt>あ</rt></ruby>ったような <b><ruby>気<rt>き</rt></ruby>がする</b>。","de":"Ich habe das Gefühl, wir sind uns schon mal begegnet."},"simpel":"Vage Ahnung/Empfindung: »mir ist, als ob …«.<br><span class=\"jp\"><ruby>忘<rt>わす</rt></ruby>れた <ruby>気<rt>き</rt></ruby>がする</span> = „ich habe das Gefühl, es vergessen zu haben“","rule":"Plain (+ ような) + 気がする = »ich habe das (unsichere) Gefühl, dass …«. Subjektive Ahnung ohne Beweis."},{"l":20,"t":"〜ふりをする","de":"so tun, als ob … / vorgeben zu …","slots":[{"text":"[Plain] / N の","role":"cond"},{"text":"ふりをする","role":"plain","label":"so tun, als ob"}],"gloss":"»Vorgeben zu … / so tun, als ob.« Verhalten ≠ Wirklichkeit. N + の + ふり (子どものふり).","ex":{"jp":"<ruby>聞<rt>き</rt></ruby>こえない<b>ふりをした</b>。","de":"Ich tat, als hörte ich es nicht."},"simpel":"Vortäuschen: »so tun, als ob …«.<br><span class=\"jp\"><ruby>寝<rt>ね</rt></ruby>た<b>ふりをする</b></span> = „sich schlafend stellen“","rule":"Plain + ふりをする (N + の + ふり) = »vorgeben zu … / so tun, als ob«. Die Wirklichkeit ist anders als das gezeigte Verhalten."},{"l":20,"t":"〜<ruby>一方<rt>いっぽう</rt></ruby>だ","de":"wird nur immer … (einseitige Tendenz)","slots":[{"text":"N は","role":"subj"},{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"<ruby>一方<rt>いっぽう</rt></ruby>だ","role":"plain","label":"nur immer …"}],"gloss":"»Entwickelt sich immer weiter (nur) in eine Richtung.« Meist negativ. Nur mit Veränderungsverben.","ex":{"jp":"<ruby>物価<rt>ぶっか</rt></ruby>は <ruby>上<rt>あ</rt></ruby>がる<b>一方だ</b>。","de":"Die Preise steigen nur immer weiter."},"simpel":"Einseitige, fortschreitende Tendenz: »wird nur immer …«.<br><span class=\"jp\"><ruby>悪<rt>わる</rt></ruby>くなる<b>一方だ</b></span> = „wird nur immer schlechter“","rule":"V<sub>辞書</sub> + 一方だ = »die Lage entwickelt sich immer weiter (nur) in eine Richtung«, oft negativ. Betont eine stetige, einseitige Veränderung."},{"l":20,"t":"〜ところだった","de":"beinahe wäre … (passiert)","slots":[{"text":"もう<ruby>少<rt>すこ</rt></ruby>しで","role":"actor","label":"um ein Haar"},{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"ところだった","role":"plain","label":"beinahe wäre …"}],"gloss":"»Beinahe wäre … passiert (ist aber nicht).« Oft mit もう少しで/あぶなく. Immer 辞書形 + ところだった.","ex":{"jp":"もう<ruby>少<rt>すこ</rt></ruby>しで <ruby>電車<rt>でんしゃ</rt></ruby>に <ruby>乗<rt>の</rt></ruby>り<ruby>遅<rt>おく</rt></ruby>れる<b>ところだった</b>。","de":"Beinahe hätte ich den Zug verpasst."},"simpel":"Um ein Haar wäre etwas passiert (ist aber nicht).<br><span class=\"jp\">もう<ruby>少<rt>すこ</rt></ruby>しで <ruby>落<rt>お</rt></ruby>ちる<b>ところだった</b></span> = „beinahe wäre ich gefallen“","rule":"V<sub>辞書</sub> + ところだった = »um ein Haar wäre … passiert (ist aber gerade nicht)«. Oft mit もう少しで / あぶなく. Erleichterung oder Schreck im Nachhinein."},{"l":21,"t":"1 · <ruby>登<rt>のぼ</rt></ruby>り<ruby>始<rt>はじ</rt></ruby>めた","de":"Vマス + 始める — anfangen zu … (+Plus: 〜終わる)","slots":[{"text":"N を","role":"obj"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"<ruby>始<rt>はじ</rt></ruby>めた","role":"plain","label":"begann zu"}],"gloss":"»begann zu V-en« — ます-Stamm + 始める; Abschluss: 〜終わる. Plötzlich: 〜出す.","ex":{"jp":"<ruby>朝<rt>あさ</rt></ruby> 5<ruby>時<rt>じ</rt></ruby>に <ruby>山<rt>やま</rt></ruby>を <ruby>登<rt>のぼ</rt></ruby>り<b>始めました</b>。","de":"Um 5 Uhr morgens begannen wir den Aufstieg."},"simpel":"ます-Stamm + <b><ruby>始<rt>はじ</rt></ruby>める</b> = »anfangen zu …« — klebt direkt am Stamm.<br><span class='jp'><ruby>山<rt>やま</rt></ruby>を <ruby>登<rt>のぼ</rt></ruby>り<b>始めた</b></span> = „begann den Berg zu besteigen“","rule":"V<sub>ます</sub>-Stamm + 始める markiert den Beginn einer Handlung. Das Gegenstück 〜終わる markiert den Abschluss. Neutraler Anfang (auch geplant) — plötzliches Losbrechen wäre 〜出す (Punkt 16)."},{"l":21,"t":"2 · <ruby>持<rt>も</rt></ruby>って いくように <ruby>言<rt>い</rt></ruby>われた","de":"〜ように言う/言われる — jdm. sagen, dass er … soll","slots":[{"text":"[<ruby>人<rt>ひと</rt></ruby>] に","role":"obj","label":"von wem"},{"text":"V<sub>辞書/ない</sub>","role":"verb","label":"was (nicht) tun"},{"text":"ように<ruby>言<rt>い</rt></ruby>われた","role":"plain","label":"wurde gesagt"}],"gloss":"Indirekte Aufforderung: »X sagte (mir), ich solle (nicht) …«. 辞書形/ない形 + ように + Sprechverb.","ex":{"jp":"<ruby>山小屋<rt>やまごや</rt></ruby>の <ruby>人<rt>ひと</rt></ruby>に、<ruby>水<rt>みず</rt></ruby>を たくさん <ruby>持<rt>も</rt></ruby>って いく<b>ように 言われました</b>。","de":"Die Leute von der Berghütte sagten mir, ich solle viel Wasser mitnehmen."},"simpel":"Aufforderung indirekt wiedergeben; passiv = »mir wurde gesagt, ich solle …«.<br><span class='jp'><ruby>水<rt>みず</rt></ruby>を <ruby>持<rt>も</rt></ruby>って いく<b>ように 言われた</b></span> = „man sagte mir, ich solle Wasser mitnehmen“","rule":"V<sub>辞書/ない</sub> + ように + 言う/頼む/注意する/伝える: gibt Bitten/Anweisungen indirekt wieder. Sehr häufig im Passiv: 〜ように言われた »mir wurde gesagt, dass ich … soll«."},{"l":21,"t":"3 · <ruby>病気<rt>びょうき</rt></ruby>に なる <ruby>人<rt>ひと</rt></ruby>も いる ということ","de":"〜ということだ — es heißt, dass … / das bedeutet …","slots":[{"text":"[Satz<sub>Plain</sub>]","role":"cond"},{"text":"ということ","role":"actor","label":"dass …"},{"text":"(だ)","role":"plain"}],"gloss":"Macht einen Satz zur »Information, dass …«. Am Ende: Hörensagen (es heißt) oder Schluss (das bedeutet).","ex":{"jp":"<ruby>高山病<rt>こうざんびょう</rt></ruby>に なる <ruby>人<rt>ひと</rt></ruby>も いる<b>ということ</b>を <ruby>知<rt>し</rt></ruby>った。","de":"Ich erfuhr, dass manche höhenkrank werden."},"simpel":"<b>ということ</b> macht einen Satz zur Information/Aussage: »(es heißt,) dass …«.<br><span class='jp'><ruby>病気<rt>びょうき</rt></ruby>に なる <ruby>人<rt>ひと</rt></ruby>も いる<b>ということ</b></span> = „(die Tatsache,) dass manche krank werden“","rule":"Satz + ということ nominalisiert eine ganze Aussage (»die Tatsache/Information, dass …«). Am Satzende ということだ = Hörensagen (»es heißt, dass …«) oder Schlussfolgerung (»das bedeutet …«)."},{"l":21,"t":"4 · <ruby>大丈夫<rt>だいじょうぶ</rt></ruby>だろうと <ruby>思<rt>おも</rt></ruby>った","de":"〜だろうと思う — ich dachte/denke, dass wohl …","slots":[{"text":"[Vermutung]","role":"cond"},{"text":"だろう","role":"actor","label":"wohl"},{"text":"と<ruby>思<rt>おも</rt></ruby>った","role":"plain","label":"dachte ich"}],"gloss":"»Ich dachte, es wird wohl …« — Plain + だろう + と思う; な-Adj/N ohne だ.","ex":{"jp":"<ruby>夏<rt>なつ</rt></ruby>だから <ruby>大丈夫<rt>だいじょうぶ</rt></ruby><b>だろうと 思った</b>。","de":"Weil Sommer war, dachte ich, es würde schon gehen."},"simpel":"Vermutung + <b>と思う</b>: »ich dachte, es wird wohl …«.<br><span class='jp'><ruby>大丈夫<rt>だいじょうぶ</rt></ruby><b>だろうと 思った</b></span> = „ich dachte, es geht schon“","rule":"Plain + だろう + と思う: die eigene Vermutung, abgeschwächt und subjektiv — »wird wohl … , denke ich«. な-Adj/Nomen ohne だ direkt + だろう. Vergangenheit: 〜だろうと思った (oft mit Enttäuschung, wenn es anders kam)."},{"l":21,"t":"5 · <ruby>大変<rt>たいへん</rt></ruby>じゃなさそうだった","de":"〜そうだ (Anschein) — sieht … aus / sah nicht … aus","slots":[{"text":"Adj/N","role":"cond"},{"text":"じゃなさそう","role":"actor","label":"sieht nicht … aus"},{"text":"だった","role":"plain","label":"(Verg.)"}],"gloss":"Anschein-そう verneint: 〜くなさそう / 〜じゃなさそう »sieht nicht … aus«. Nicht mit Hörensagen-そう verwechseln!","ex":{"jp":"ガイドブックでは、そんなに <ruby>大変<rt>たいへん</rt></ruby><b>じゃなさそう</b>だった。","de":"Laut Reiseführer sah es nicht so anstrengend aus."},"simpel":"Anschein: »sieht … aus«. Verneint: <b>じゃなさそう</b> »sieht nicht … aus«.<br><span class='jp'><ruby>大変<rt>たいへん</rt></ruby><b>じゃなさそう</b>だった</span> = „sah nicht anstrengend aus“","rule":"Anschein-そう: い-Adj-Stamm/な-Adj + そうだ (»sieht … aus«). Verneinung: い-Adj くなさそう, な-Adj/N じゃなさそう, Verben そうもない/そうにない. Vergangenheit: そうだった."},{"l":21,"t":"6 · <ruby>登<rt>のぼ</rt></ruby>って みると","de":"〜てみると — als ich es (aus)probierte, (da) …","slots":[{"text":"V<sub>テ</sub>","role":"verb"},{"text":"みると","role":"actor","label":"als ich probierte"},{"text":"[Entdeckung]","role":"cond"}],"gloss":"»Als ich es dann (wirklich) tat, stellte sich heraus: …« — てみる + と-Entdeckung.","ex":{"jp":"<ruby>実際<rt>じっさい</rt></ruby>に <ruby>登<rt>のぼ</rt></ruby>って<b>みると</b>、<ruby>思<rt>おも</rt></ruby>ったより ずっと <ruby>大変<rt>たいへん</rt></ruby>だった。","de":"Als ich dann wirklich hinaufstieg, war es viel härter als gedacht."},"simpel":"て-Form + <b>みると</b>: »als ich es dann tat/probierte, stellte sich heraus …«.<br><span class='jp'><ruby>登<rt>のぼ</rt></ruby>って<b>みると</b></span> = „als ich dann (wirklich) hinaufstieg …“","rule":"V<sub>テ</sub> + みると: man probiert etwas (てみる) — und mit と folgt die überraschende Entdeckung, die man dabei macht. Der Nachsatz ist eine Feststellung, kein Wille."},{"l":21,"t":"7 · <ruby>立<rt>た</rt></ruby>って いるのも つらいほど","de":"〜ほど — so (sehr), dass … (Grad)","slots":[{"text":"[sogar X ist Y]","role":"cond","label":"Ausmaß"},{"text":"ほど","role":"actor","label":"so sehr, dass"},{"text":"[Zustand]","role":"plain"}],"gloss":"Grad-Angabe: »so …, dass (sogar) …«. Der ほど-Satz veranschaulicht das Ausmaß.","ex":{"jp":"<ruby>立<rt>た</rt></ruby>って いるのも つらい<b>ほど</b> <ruby>疲<rt>つか</rt></ruby>れて いた。","de":"Ich war so erschöpft, dass selbst Stehen qualvoll war."},"simpel":"<b>ほど</b> gibt den Grad an: »so …, dass …«.<br><span class='jp'><ruby>立<rt>た</rt></ruby>って いるのも つらい<b>ほど</b></span> = „so schlimm, dass selbst Stehen qualvoll war“","rule":"[Ausmaß-Satz] + ほど: drückt aus, WIE stark etwas ist, mit einem anschaulichen Vergleich (»so …, dass sogar …«). Auch N + ほど (山ほど »bergeweise«)."},{"l":21,"t":"8 · どんどん <ruby>登<rt>のぼ</rt></ruby>って いく","de":"〜ていく — (von mir weg / weiter) fort-… (+Plus: 〜てくる)","slots":[{"text":"どんどん","role":"time","label":"zügig"},{"text":"V<sub>テ</sub>","role":"verb"},{"text":"いく","role":"plain","label":"weiter/fort"}],"gloss":"ていく = weg vom Sprecher / ab jetzt weiter; てくる = her zum Sprecher / bis jetzt. Raum & Zeit.","ex":{"jp":"みんな どんどん <ruby>登<rt>のぼ</rt></ruby>って<b>いきます</b>。","de":"Alle steigen zügig weiter hinauf (von mir weg)."},"simpel":"<b>ていく</b> = Bewegung/Entwicklung vom Sprecher weg oder in die Zukunft; <b>てくる</b> = her/bis jetzt.<br><span class='jp'>どんどん <ruby>登<rt>のぼ</rt></ruby>って<b>いく</b></span> = „steigt zügig (weiter) hinauf“","rule":"V<sub>テ</sub> + いく: räumlich »V-en und sich entfernen« oder zeitlich »von jetzt an weiter«. V<sub>テ</sub> + くる: »her-« bzw. »bis jetzt (allmählich)«. Perspektive des Sprechers entscheidet."},{"l":21,"t":"9 · <ruby>登<rt>のぼ</rt></ruby>り<ruby>続<rt>つづ</rt></ruby>けた","de":"Vマス + 続ける — weiter/unaufhörlich …","slots":[{"text":"N を","role":"obj"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"<ruby>続<rt>つづ</rt></ruby>けた","role":"plain","label":"weiter (durchgehalten)"}],"gloss":"»V-te weiter, ohne aufzuhören« — ます-Stamm + 続ける; Durchhalte-Nuance.","ex":{"jp":"<ruby>休<rt>やす</rt></ruby>まずに 3<ruby>時間<rt>じかん</rt></ruby>も <ruby>登<rt>のぼ</rt></ruby>り<b>続けました</b>。","de":"Ich stieg ganze drei Stunden ohne Pause weiter."},"simpel":"ます-Stamm + <b><ruby>続<rt>つづ</rt></ruby>ける</b> = »ohne aufzuhören weiter …«.<br><span class='jp'><ruby>登<rt>のぼ</rt></ruby>り<b>続けた</b></span> = „stieg unaufhörlich weiter“","rule":"V<sub>ます</sub>-Stamm + 続ける: die Handlung dauert an, ohne Unterbrechung — oft mit Durchhalte-Nuance. Anhaltender Zustand: 〜続けている."},{"l":21,"t":"10 · <ruby>上<rt>うえ</rt></ruby>まで <ruby>行<rt>い</rt></ruby>きたいなら","de":"〜なら — wenn (du) … (willst), dann (rate ich) …","slots":[{"text":"V<sub>たい</sub>","role":"cond","label":"Wunsch"},{"text":"なら","role":"actor","label":"wenn, dann"},{"text":"[Rat]","role":"plain"}],"gloss":"Reaktions-Konditional: greift den Wunsch/Plan des Gegenübers auf und gibt einen Rat. Typisch 〜たいなら.","ex":{"jp":"<ruby>上<rt>うえ</rt></ruby>まで <ruby>行<rt>い</rt></ruby>きたい<b>なら</b>、ちゃんと <ruby>準備<rt>じゅんび</rt></ruby>した ほうが いい。","de":"Wenn du bis zum Gipfel willst, solltest du dich richtig vorbereiten."},"simpel":"<b>なら</b> reagiert auf Gesagtes/Gewolltes: »wenn du … willst, dann …«.<br><span class='jp'><ruby>上<rt>うえ</rt></ruby>まで <ruby>行<rt>い</rt></ruby>きたい<b>なら</b></span> = „wenn du bis oben willst, (dann) …“","rule":"[Thema/Wunsch] + なら + Ratschlag/Urteil: greift auf, was der andere gesagt oder vor hat, und gibt dazu eine Empfehlung. Typisch nach 〜たい: 行きたいなら »wenn du gehen willst«."},{"l":22,"t":"11 · クロって <ruby>名前<rt>なまえ</rt></ruby>","de":"〜って — locker für という/は (»namens … / was … angeht«)","slots":[{"text":"クロ","role":"subj","label":"Name"},{"text":"って","role":"actor","label":"namens"},{"text":"<ruby>名前<rt>なまえ</rt></ruby>","role":"obj"}],"gloss":"Gesprochenes という/は/と: »namens«, Themenmarker oder Zitat. Nur informell.","ex":{"jp":"クロ<b>って</b> <ruby>名前<rt>なまえ</rt></ruby>は、ぼくが つけた。","de":"Den Namen „Kuro“ habe ich ihm gegeben."},"simpel":"<b>って</b> ist das gesprochene という/は: »namens X« oder »X? (was das angeht)«.<br><span class='jp'>クロ<b>って</b> <ruby>名前<rt>なまえ</rt></ruby></span> = „der Name ‚Kuro‘“","rule":"って ersetzt in lockerer Sprache: (1) という (クロって名前 = クロという名前), (2) Themen-は (これって何? = これは何?), (3) Zitat と (行くって言った). Sehr häufig im Gespräch."},{"l":22,"t":"12 · <ruby>飼<rt>か</rt></ruby>わせて もらった","de":"使役 + てもらう — (die Erlaubnis) bekommen, zu …","slots":[{"text":"[<ruby>親<rt>おや</rt></ruby>] に","role":"obj","label":"von wem"},{"text":"V<sub>させて</sub>","role":"verb","label":"lassen-Form"},{"text":"もらった","role":"plain","label":"durfte"}],"gloss":"»Jemand ließ mich (netterweise) …« — Kausativ-て + もらう/くれる. Dankbare Erlaubnis.","ex":{"jp":"<ruby>両親<rt>りょうしん</rt></ruby>に <ruby>犬<rt>いぬ</rt></ruby>を <ruby>飼<rt>か</rt></ruby>わせて<b>もらいました</b>。","de":"Meine Eltern erlaubten mir, einen Hund zu halten."},"simpel":"Kausativ-て + もらう = »man ließ mich … (ich durfte)«.<br><span class='jp'><ruby>飼<rt>か</rt></ruby>わせて<b>もらった</b></span> = „ich durfte ihn halten“","rule":"V<sub>使役て</sub> + もらう/くれる: jemand erlaubt mir wohlwollend, etwas zu tun — »ich durfte (dank ihm)«. Höflich-dankbar: 〜させていただく."},{"l":22,"t":"13 · <ruby>約束<rt>やくそく</rt></ruby>させられた","de":"使役受身 — gezwungen werden, zu … (musste)","slots":[{"text":"[<ruby>親<rt>おや</rt></ruby>] に","role":"obj","label":"von wem"},{"text":"V<sub>使役受身</sub>","role":"verb","label":"musste"},{"text":"(いやいや)","role":"time","label":"widerwillig"}],"gloss":"»Ich wurde (gegen meinen Willen) dazu gebracht, zu …« — させられる; う-Verben oft 〜される.","ex":{"jp":"<ruby>毎日<rt>まいにち</rt></ruby> <ruby>散歩<rt>さんぽ</rt></ruby>に <ruby>行<rt>い</rt></ruby>くと、<ruby>親<rt>おや</rt></ruby>に <ruby>約束<rt>やくそく</rt></ruby><b>させられた</b>。","de":"Meine Eltern nahmen mir das Versprechen ab, täglich Gassi zu gehen."},"simpel":"Kausativ-Passiv = »ich wurde dazu gebracht / musste (widerwillig)«.<br><span class='jp'><ruby>約束<rt>やくそく</rt></ruby><b>させられた</b></span> = „ich musste (es) versprechen“","rule":"V<sub>使役受身</sub> (させられる/…される): jemand zwingt mich zu etwas, das ich nicht (gern) tue. う-Verben oft Kurzform (行かされる), する→させられる."},{"l":22,"t":"14 · <ruby>散歩<rt>さんぽ</rt></ruby>に <ruby>行<rt>い</rt></ruby>きたがって","de":"〜たがる — (er/sie) will … (3. Person)","slots":[{"text":"[3. Person] は","role":"subj"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"たがっている","role":"plain","label":"will (sichtbar)"}],"gloss":"Wunsch Dritter: たい→たがる, ほしい→ほしがる. Der Wunsch zeigt sich im Verhalten.","ex":{"jp":"クロは <ruby>朝<rt>あさ</rt></ruby>から <ruby>散歩<rt>さんぽ</rt></ruby>に <ruby>行<rt>い</rt></ruby>き<b>たがって</b> いる。","de":"Kuro will schon seit dem Morgen unbedingt Gassi gehen."},"simpel":"Wunsch der 3. Person: ます-Stamm + <b>たがる</b>.<br><span class='jp'><ruby>行<rt>い</rt></ruby>き<b>たがって</b> いる</span> = „(der Hund) will unbedingt los“","rule":"たい ist nur für die eigene Person; bei Dritten nutzt man V<sub>ます</sub> + たがる (»zeigt, dass er … will«). Meist たがっている. Ebenso: ほしい → ほしがる."},{"l":22,"t":"15 · <ruby>玄関<rt>げんかん</rt></ruby>を <ruby>出<rt>で</rt></ruby>たとたん","de":"〜たとたん(に) — kaum dass … / im selben Moment","slots":[{"text":"V<sub>た</sub>","role":"verb","label":"Moment A"},{"text":"とたん","role":"actor","label":"im selben Moment"},{"text":"[plötzlich B]","role":"cond"}],"gloss":"»Kaum dass A, (da) B (überraschend).« Nur た-Form davor.","ex":{"jp":"<ruby>玄関<rt>げんかん</rt></ruby>を <ruby>出<rt>で</rt></ruby>た<b>とたん</b>、クロが <ruby>走<rt>はし</rt></ruby>り<ruby>出<rt>だ</rt></ruby>した。","de":"Kaum waren wir aus der Haustür, rannte Kuro los."},"simpel":"Zwei Ereignisse Schlag auf Schlag, das zweite überraschend.<br><span class='jp'><ruby>玄関<rt>げんかん</rt></ruby>を <ruby>出<rt>で</rt></ruby>た<b>とたん</b></span> = „kaum aus der Haustür …“","rule":"V<sub>た</sub> + とたん(に): »genau in dem Moment, als A geschah, geschah (unerwartet) B«. B ist unkontrolliert und vergangen; kein Wille/Befehl."},{"l":22,"t":"16 · <ruby>全速力<rt>ぜんそくりょく</rt></ruby>で <ruby>走<rt>はし</rt></ruby>り<ruby>出<rt>だ</rt></ruby>す","de":"Vマス + 出す — plötzlich los-…","slots":[{"text":"<ruby>急<rt>きゅう</rt></ruby>に","role":"time","label":"plötzlich"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"<ruby>出<rt>だ</rt></ruby>す","role":"plain","label":"los-"}],"gloss":"»Bricht plötzlich los« — unkontrolliert/überraschend. Neutral: 〜始める.","ex":{"jp":"クロは <ruby>全速力<rt>ぜんそくりょく</rt></ruby>で <ruby>走<rt>はし</rt></ruby>り<b>出した</b>。","de":"Kuro rannte mit voller Geschwindigkeit los."},"simpel":"ます-Stamm + <b><ruby>出<rt>だ</rt></ruby>す</b> = »plötzlich anfangen« (losrennen, losweinen).<br><span class='jp'><ruby>走<rt>はし</rt></ruby>り<b>出す</b></span> = „losrennen“","rule":"V<sub>ます</sub>-Stamm + 出す: etwas bricht plötzlich, unkontrolliert los. Anders als 〜始める (neutral, Punkt 1) schwingt Überraschung mit."},{"l":22,"t":"17 · <ruby>帰<rt>かえ</rt></ruby>ろうとする","de":"〜(よ)うとする — im Begriff sein / versuchen zu …","slots":[{"text":"V<sub>(よ)う</sub>","role":"verb","label":"Willensform"},{"text":"とすると","role":"actor","label":"als ich gerade wollte"},{"text":"[B]","role":"cond"}],"gloss":"»Gerade ansetzen zu …« — Willensform + とする; Verweigerung: ようとしない.","ex":{"jp":"<ruby>家<rt>いえ</rt></ruby>に <ruby>帰<rt>かえ</rt></ruby>ろ<b>うとする</b>と、クロが <ruby>動<rt>うご</rt></ruby>かなく なる。","de":"Sobald ich heimgehen will, rührt sich Kuro nicht mehr vom Fleck."},"simpel":"Willensform + <b>とする</b>: »gerade ansetzen / versuchen zu …«.<br><span class='jp'><ruby>帰<rt>かえ</rt></ruby>ろ<b>うとする</b>と</span> = „als ich gerade gehen wollte …“","rule":"V<sub>(よ)う</sub> + とする: (1) »gerade im Begriff sein« (帰ろうとしたとき), (2) »versuchen« (Anlauf nehmen). Verneint 〜(よ)うとしない = »macht keine Anstalten«."},{"l":22,"t":"18 · コンビニに <ruby>寄<rt>よ</rt></ruby>る こともある","de":"〜こともある — es kommt (auch) vor, dass …","slots":[{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"こともある","role":"plain","label":"kommt vor"}],"gloss":"»Es kommt (auch) vor, dass …« — gelegentlich, nicht die Regel. ≠ たことがある (Erfahrung).","ex":{"jp":"<ruby>散歩<rt>さんぽ</rt></ruby>の <ruby>帰<rt>かえ</rt></ruby>りに、コンビニに <ruby>寄<rt>よ</rt></ruby>る<b>こともある</b>。","de":"Auf dem Rückweg vom Spaziergang schauen wir manchmal am Konbini vorbei."},"simpel":"Gelegentliches: »manchmal passiert es, dass …«.<br><span class='jp'><ruby>寄<rt>よ</rt></ruby>る<b>こともある</b></span> = „manchmal schauen wir (dort) vorbei“","rule":"V<sub>辞書/ない</sub> + こともある: etwas ist nicht die Regel, kommt aber vor. Stärker »nur manchmal« als schlichtes ときどき; auch 〜ないこともある (»es kommt vor, dass nicht«)."},{"l":22,"t":"19 · <ruby>待<rt>ま</rt></ruby>たせて おいて","de":"使役 + ておく — jdn. (erstmal) … lassen (und so belassen)","slots":[{"text":"[<ruby>人<rt>ひと</rt></ruby>/<ruby>犬<rt>いぬ</rt></ruby>] を","role":"obj"},{"text":"V<sub>させて</sub>","role":"verb","label":"lassen"},{"text":"おく","role":"plain","label":"(so belassen)"}],"gloss":"»Jemanden (vorerst) … lassen und dabei belassen« — Kausativ-て + おく.","ex":{"jp":"クロを <ruby>外<rt>そと</rt></ruby>で <ruby>待<rt>ま</rt></ruby>たせて<b>おいて</b>、<ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>を した。","de":"Ich ließ Kuro draußen warten und erledigte den Einkauf."},"simpel":"Kausativ + <b>ておく</b>: »jemanden (vorerst) warten/machen lassen«.<br><span class='jp'><ruby>待<rt>ま</rt></ruby>たせて<b>おいて</b></span> = „ihn warten lassen (und derweil …)“","rule":"V<sub>使役て</sub> + おく: man lässt jemanden in einem Zustand/einer Tätigkeit und belässt es dabei (Vorbereitungs-/Belassen-おく auf den Kausativ angewandt). 待たせておく »warten lassen«, 遊ばせておく »spielen lassen«."},{"l":22,"t":"20 · <ruby>顔中<rt>かおじゅう</rt></ruby> なめられて しまう","de":"受身 + てしまう — (ungewollt) ganz … werden (+ N中)","slots":[{"text":"<ruby>顔中<rt>かおじゅう</rt></ruby>","role":"obj","label":"ganz N"},{"text":"V<sub>られて</sub>","role":"verb","label":"Passiv"},{"text":"しまう","role":"plain","label":"komplett/leider"}],"gloss":"Betroffenheits-Passiv + しまう: »mir wird (ungewollt) komplett … angetan«. N中 = das ganze N.","ex":{"jp":"クロに <ruby>顔中<rt>かおじゅう</rt></ruby> なめられて<b>しまいました</b>。","de":"Kuro hat mir das ganze Gesicht abgeschleckt."},"simpel":"Passiv + <b>てしまう</b> = »es passiert mir (ungewollt/komplett)«. <b>顔中</b> = »das ganze Gesicht«.<br><span class='jp'><ruby>顔中<rt>かおじゅう</rt></ruby> なめられて<b>しまう</b></span> = „das ganze Gesicht wird abgeschleckt“","rule":"V<sub>受身て</sub> + しまう kombiniert Betroffenheits-Passiv (»mir wird … angetan«) mit しまう (»restlos/leider«). Dazu N + 中(じゅう) = »das ganze N« (顔中, 部屋中, 一日中)."},{"l":23,"t":"21 · インターネットによる お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>み","de":"N による — mittels / per … (Methode, formell)","slots":[{"text":"N₁","role":"subj","label":"Mittel"},{"text":"による","role":"actor","label":"per"},{"text":"N₂","role":"obj","label":"Sache"}],"gloss":"»N₂ mittels N₁« — formelle Methoden-Angabe vor Nomen; adverbial によって.","ex":{"jp":"お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>みは インターネット<b>による</b> <ruby>受付<rt>うけつけ</rt></ruby>のみ です。","de":"Die Anmeldung erfolgt ausschließlich per Internet."},"simpel":"<b>による</b> vor Nomen = »per/mittels« (formell).<br><span class='jp'>インターネット<b>による</b> お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>み</span> = „Anmeldung per Internet“","rule":"N₁ + による + N₂ nennt das Mittel/die Methode für N₂ (schriftlich-formell, typisch in Bekanntmachungen). Adverbial: 〜によって. Achtung: による hat weitere Lesarten (Ursache, Urheber im Passiv, je nach)."},{"l":23,"t":"22 · 100<ruby>区画<rt>くかく</rt></ruby>の <ruby>募集<rt>ぼしゅう</rt></ruby>に<ruby>対<rt>たい</rt></ruby>して","de":"〜に対して — auf … (hin) / gegenüber / im Verhältnis zu","slots":[{"text":"100<ruby>区画<rt>くかく</rt></ruby>","role":"subj","label":"Angebot"},{"text":"に<ruby>対<rt>たい</rt></ruby>して","role":"actor","label":"auf … (kamen)"},{"text":"[Nachfrage]","role":"obj"}],"gloss":"Zahlenverhältnis: »auf X (Angebot) kommen Y (Bewerber)«. Weitere Lesarten: gegenüber / wohingegen.","ex":{"jp":"100<ruby>区画<rt>くかく</rt></ruby>の <ruby>募集<rt>ぼしゅう</rt></ruby><b>に対して</b>、300<ruby>件<rt>けん</rt></ruby>の <ruby>応募<rt>おうぼ</rt></ruby>が あった。","de":"Auf die Ausschreibung von 100 Parzellen kamen 300 Bewerbungen."},"simpel":"<b>に対して</b>: Reaktion/Verhältnis — »auf 100 Parzellen (kamen) …«.<br><span class='jp'>100<ruby>区画<rt>くかく</rt></ruby><b>に対して</b>、300<ruby>人<rt>にん</rt></ruby></span> = „auf 100 Parzellen 300 Bewerber“","rule":"N + に対して: (1) Ziel/Adressat einer Handlung (»gegenüber«), (2) Verhältnis von Zahlen (»auf N kommen …«), (3) Kontrast (»wohingegen«). Hier Lesart 2: Nachfrage vs. Angebot."},{"l":23,"t":"23 · <ruby>希望者<rt>きぼうしゃ</rt></ruby>が <ruby>多<rt>おお</rt></ruby>いため","de":"〜ため(に) — wegen / da … (Grund, formell)","slots":[{"text":"[Grund<sub>Plain</sub>]","role":"cond"},{"text":"ため","role":"actor","label":"da/wegen"},{"text":"[Folge]","role":"verb"}],"gloss":"Formeller Grund: »da …, (deshalb) …«. Zweck-ため (um zu) ist die andere Lesart — Kontext prüfen.","ex":{"jp":"<ruby>希望者<rt>きぼうしゃ</rt></ruby>が <ruby>多<rt>おお</rt></ruby>い<b>ため</b>、<ruby>抽選<rt>ちゅうせん</rt></ruby>と なります。","de":"Da es viele Interessenten gibt, entscheidet das Los."},"simpel":"<b>ため</b> als Grund: »da/weil …« (formell, Aushang-Stil).<br><span class='jp'><ruby>希望者<rt>きぼうしゃ</rt></ruby>が <ruby>多<rt>おお</rt></ruby>い<b>ため</b></span> = „da es viele Interessenten gibt“","rule":"Plain + ため(に): nennt formell den Grund (»da/wegen«). In Bekanntmachungen sehr häufig, oft ohne に. Nicht verwechseln mit Zweck-ため (»um zu«, mit Willensverben)."},{"l":23,"t":"24 · 1<ruby>家族<rt>かぞく</rt></ruby>につき 1<ruby>区画<rt>くかく</rt></ruby>","de":"〜につき — pro … (formell; auch: wegen)","slots":[{"text":"1<ruby>家族<rt>かぞく</rt></ruby>","role":"subj","label":"Einheit"},{"text":"につき","role":"actor","label":"pro"},{"text":"1<ruby>区画<rt>くかく</rt></ruby>","role":"obj","label":"Menge"}],"gloss":"»Pro Einheit …« (formell, Regeln). Zweite Lesart auf Schildern: »wegen«.","ex":{"jp":"お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>みは 1<ruby>家族<rt>かぞく</rt></ruby><b>につき</b> 1<ruby>区画<rt>くかく</rt></ruby>まで。","de":"Anmeldung: maximal eine Parzelle pro Familie."},"simpel":"<b>につき</b> = »pro X« in Regeln/Aushängen.<br><span class='jp'>1<ruby>家族<rt>かぞく</rt></ruby><b>につき</b> 1<ruby>区画<rt>くかく</rt></ruby></span> = „pro Familie eine Parzelle“","rule":"N + につき: (1) »pro N« bei Mengen/Preisen (formell); (2) »wegen N« auf Schildern (工事中につき). Alltag: 〜あたり (pro) bzw. 〜だから (wegen)."},{"l":23,"t":"25 · <ruby>下記<rt>かき</rt></ruby>の とおりです","de":"〜のとおり / どおり — wie (unten angegeben) / gemäß","slots":[{"text":"<ruby>下記<rt>かき</rt></ruby> の","role":"subj","label":"Vorlage"},{"text":"とおり","role":"actor","label":"genau so wie"},{"text":"です","role":"plain"}],"gloss":"»Genau wie (unten/die Vorgabe)« — Aushänge lieben 下記のとおり/次のとおり; direkt am Nomen: どおり.","ex":{"jp":"<ruby>募集<rt>ぼしゅう</rt></ruby><ruby>内容<rt>ないよう</rt></ruby>は <ruby>下記<rt>かき</rt></ruby>の<b>とおり</b>です。","de":"Die Ausschreibungsdetails sind wie unten angegeben."},"simpel":"<b>とおり</b> = »genau so wie …«; <b>下記のとおり</b> = »wie unten aufgeführt«.<br><span class='jp'><ruby>下記<rt>かき</rt></ruby>の<b>とおり</b>です</span> = „wie unten angegeben“","rule":"N + の + とおり / V<sub>辞書・た</sub> + とおり(に) = »genau wie …«. Direkt ans Nomen: どおり (予定どおり). Aushang-Floskeln: 下記のとおり (wie unten), 次のとおり (wie folgt), 以上のとおり (wie oben)."},{"l":23,"t":"26 · <ruby>野菜<rt>やさい</rt></ruby><ruby>作<rt>づく</rt></ruby>りを<ruby>通<rt>とお</rt></ruby>して","de":"〜を通して — durch/über … (als Weg/Erfahrung)","slots":[{"text":"N","role":"subj","label":"Weg/Erfahrung"},{"text":"を<ruby>通<rt>とお</rt></ruby>して","role":"actor","label":"durch/über"},{"text":"[Gewinn]","role":"verb"}],"gloss":"»Durch N (als Erfahrung/Mittel) …« — auch zeitlich: N hindurch. を通じて formeller.","ex":{"jp":"<ruby>野菜<rt>やさい</rt></ruby><ruby>作<rt>づく</rt></ruby>り<b>を通して</b>、<ruby>自然<rt>しぜん</rt></ruby>の <ruby>大切<rt>たいせつ</rt></ruby>さを <ruby>学<rt>まな</rt></ruby>べます。","de":"Über den Gemüseanbau lernt man den Wert der Natur."},"simpel":"<b>を通して</b> = »durch X (als Mittel/Erfahrung)«.<br><span class='jp'><ruby>野菜<rt>やさい</rt></ruby><ruby>作<rt>づく</rt></ruby>り<b>を通して</b></span> = „über den Gemüseanbau (lernt man …)“","rule":"N + を通して/を通じて: durch N als Vermittler, Mittel oder Erfahrung; mit Zeitwort »den Zeitraum hindurch« (一年を通して). を通じて ist etwas schriftlicher."},{"l":23,"t":"27 · パーティーのような <ruby>楽<rt>たの</rt></ruby>しい イベント","de":"N のような N — (so etwas) wie … (Beispiel)","slots":[{"text":"N₁","role":"subj","label":"Beispiel"},{"text":"のような","role":"actor","label":"wie"},{"text":"N₂","role":"obj","label":"Kategorie"}],"gloss":"»N₂ wie (z. B.) N₁« — Beispiel oder bildhafter Vergleich; adverbial のように.","ex":{"jp":"<ruby>収穫祭<rt>しゅうかくさい</rt></ruby><b>のような</b> <ruby>楽<rt>たの</rt></ruby>しい イベントも あります。","de":"Es gibt auch schöne Veranstaltungen wie das Erntefest."},"simpel":"<b>のような</b> nennt ein Beispiel vor einem Nomen.<br><span class='jp'>パーティー<b>のような</b> イベント</span> = „Veranstaltungen wie eine Party“","rule":"N₁ + のような + N₂: N₁ ist Beispiel oder Vergleichsbild für N₂. Adverbial: のように. Beispiel-Funktion (»wie z. B.«) und Vergleich (»wie ein/e«) — Kontext entscheidet."},{"l":23,"t":"28 · ご<ruby>利用<rt>りよう</rt></ruby>されている <ruby>方<rt>かた</rt></ruby>の お<ruby>話<rt>はなし</rt></ruby>によれば","de":"〜によれば — laut … (Quelle; + そう/ということ)","slots":[{"text":"[Quelle]","role":"subj"},{"text":"によれば、","role":"actor","label":"laut"},{"text":"[Info] そうだ","role":"plain","label":"soll …"}],"gloss":"Quellenangabe + Hörensagen-Ende. によれば ≈ によると (Punkt 21≠: das ist Methode!).","ex":{"jp":"ご<ruby>利用<rt>りよう</rt></ruby>の <ruby>方<rt>かた</rt></ruby>の お<ruby>話<rt>はなし</rt></ruby><b>によれば</b>、<ruby>週末<rt>しゅうまつ</rt></ruby>が <ruby>楽<rt>たの</rt></ruby>しみに なった<b>ということです</b>。","de":"Nach Aussage der Nutzer freuen sie sich nun aufs Wochenende."},"simpel":"<b>によれば</b> nennt die Quelle: »laut/nach Aussage von …«.<br><span class='jp'><ruby>利用者<rt>りようしゃ</rt></ruby>の <ruby>話<rt>はなし</rt></ruby><b>によれば</b></span> = „laut den Nutzern …“","rule":"N + によれば/によると markiert die Informationsquelle; das Satzende trägt Hörensagen (〜そうだ/〜ということだ/〜らしい). によれば wirkt eine Spur schriftlicher als によると."},{"l":23,"t":"29 · <ruby>楽<rt>たの</rt></ruby>しかった ということです","de":"〜ということだ/です — es heißt, dass … (Wiedergabe)","slots":[{"text":"[Gehörtes<sub>Plain</sub>]","role":"cond"},{"text":"ということです","role":"plain","label":"es heißt"}],"gloss":"Neutrale Wiedergabe von Gehörtem; Partner von によれば/によると (Punkt 28).","ex":{"jp":"みなさん、<ruby>家族<rt>かぞく</rt></ruby>との <ruby>時間<rt>じかん</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えて <ruby>楽<rt>たの</rt></ruby>しかった<b>ということです</b>。","de":"Es heißt, alle hätten mehr schöne Familienzeit gehabt."},"simpel":"Zitiert Gehörtes wörtlich-neutral: »(sie sagen,) dass es schön war«.<br><span class='jp'><ruby>楽<rt>たの</rt></ruby>しかった<b>ということです</b></span> = „es heißt, es sei schön gewesen“","rule":"[Satz Plain] + ということだ: gibt Gehörtes/Gelesenes wieder, ohne es zu bewerten — schriftlicher als 〜そうだ. Auch als Schluss: »das bedeutet …« (つまり…ということだ)."},{"l":23,"t":"30 · <ruby>農園<rt>のうえん</rt></ruby>の <ruby>活動<rt>かつどう</rt></ruby>について","de":"〜について — über / zu … (Thema)","slots":[{"text":"N","role":"subj","label":"Thema"},{"text":"について","role":"actor","label":"über/zu"},{"text":"[<ruby>詳<rt>くわ</rt></ruby>しくは …]","role":"verb"}],"gloss":"Themenmarker »über/zu N«; Aushang-Floskel: について詳しくは…をご覧ください.","ex":{"jp":"<ruby>活動<rt>かつどう</rt></ruby><b>について</b> <ruby>詳<rt>くわ</rt></ruby>しい ことは、ホームページを ご<ruby>覧<rt>らん</rt></ruby>ください。","de":"Näheres zu den Aktivitäten finden Sie auf der Homepage."},"simpel":"<b>について</b> markiert das Thema: »über/zu X«.<br><span class='jp'><ruby>活動<rt>かつどう</rt></ruby><b>について</b> <ruby>詳<rt>くわ</rt></ruby>しくは …</span> = „Näheres zu den Aktivitäten …“","rule":"N + について: »über N (sprechen/schreiben/fragen)«. Attributiv についての + N. In Aushängen: 〜について詳しくは… (»Näheres zu … finden Sie …«). Formeller: に関して."},{"l":24,"t":"31 · <ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>してるんだ","de":"〜てる(んだ) — gesprochenes ている (+ Erklär-んだ)","slots":[{"text":"<ruby>毎日<rt>まいにち</rt></ruby>","role":"time"},{"text":"V<sub>テ</sub>る","role":"verb","label":"てる=ている"},{"text":"んだ","role":"plain","label":"nämlich"}],"gloss":"Gesprochen: ている→てる; んだ liefert den Erklär-Ton. Schriftlich wieder ausschreiben!","ex":{"jp":"<ruby>大会<rt>たいかい</rt></ruby>の ために <ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>して<b>るんだ</b>。","de":"Für den Wettkampf trainiere ich nämlich jeden Tag."},"simpel":"Im Gespräch schrumpft <b>ている → てる</b>; <b>んだ</b> erklärt.<br><span class='jp'><ruby>練習<rt>れんしゅう</rt></ruby>して<b>るんだ</b></span> = „ich trainiere nämlich (gerade jeden Tag)“","rule":"ている wird gesprochen fast immer zu てる (しています→してる). んだ/んです fügt die Erklär-/Hintergrund-Nuance hinzu. Zusammen: 〜てるんだ »(weißt du,) ich … nämlich gerade«."},{"l":24,"t":"32 · <ruby>応援<rt>おうえん</rt></ruby>に <ruby>行<rt>い</rt></ruby>かなきゃ","de":"〜なきゃ — muss … (gesprochen für なければならない)","slots":[{"text":"[Ziel] に","role":"obj"},{"text":"V<sub>ない-Stamm</sub>","role":"verb"},{"text":"なきゃ","role":"plain","label":"muss!"}],"gloss":"Gesprochene Pflicht: なければならない → なきゃ; なくてはいけない → なくちゃ.","ex":{"jp":"<ruby>友<rt>とも</rt></ruby>だちの <ruby>大会<rt>たいかい</rt></ruby>だから、<ruby>応援<rt>おうえん</rt></ruby>に <ruby>行<rt>い</rt></ruby>か<b>なきゃ</b>。","de":"Es ist der Wettkampf meines Freundes — da muss ich anfeuern!"},"simpel":"<b>なきゃ</b> = geschrumpftes なければ(ならない): »ich muss …«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>か<b>なきゃ</b></span> = „da muss ich hin!“","rule":"V<sub>ない</sub>-Stamm + なきゃ (= なければならない) bzw. なくちゃ (= なくてはいけない): gesprochene Pflicht. Das ならない/いけない fällt oft komplett weg."},{"l":24,"t":"33 · <ruby>出<rt>で</rt></ruby>るんだっけ","de":"〜っけ — wie war das nochmal? (Vergewisserung)","slots":[{"text":"[halb Vergessenes]","role":"cond"},{"text":"(ん)だっけ","role":"plain","label":"…nochmal?"}],"gloss":"Vergewisserungs-Partikel: »wie war das nochmal?« — nur gesprochen, an だ/た angeschlossen.","ex":{"jp":"<ruby>大会<rt>たいかい</rt></ruby>、<ruby>君<rt>きみ</rt></ruby>も <ruby>出<rt>で</rt></ruby>るん<b>だっけ</b>?","de":"Du machst doch auch beim Wettkampf mit — oder wie war das?"},"simpel":"<b>っけ</b> fragt nach halb Vergessenem: »… nochmal?«.<br><span class='jp'><ruby>出<rt>で</rt></ruby>るん<b>だっけ</b></span> = „du machst doch mit, oder (wie war das)?“","rule":"Satz + っけ: der Sprecher vergewissert sich über etwas, das er wusste, aber vergessen hat. Anschluss meist über だ/た: 〜だっけ / 〜たっけ (何時だっけ, 会ったっけ)."},{"l":24,"t":"34 · <ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby>って","de":"N って — »was X angeht / X, sowas wie …« (+Plus: 〜みたい)","slots":[{"text":"N","role":"subj","label":"Thema"},{"text":"って","role":"actor","label":"was … angeht"},{"text":"[Aussage]","role":"plain"}],"gloss":"Lockerer Themenmarker (=は/というのは) für Verallgemeinerungen und Definitionsfragen.","ex":{"jp":"<ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>って</b>、<ruby>練習<rt>れんしゅう</rt></ruby>の <ruby>量<rt>りょう</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>うんだね。","de":"Starke Athleten — bei denen ist das Trainingspensum einfach anders."},"simpel":"<b>って</b> hebt lockeres Thema hervor: »starke Athleten, die sind doch …«.<br><span class='jp'><ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>って</b></span> = „starke Schwimmer (was die angeht) …“","rule":"N + って als lockerer Themen-/Definitionsmarker (= は/というのは): leitet eine allgemeine Aussage oder Nachfrage über N ein. +Plus im Buch: 〜みたい (»wie/scheinbar«, Punkt-übergreifend)."},{"l":24,"t":"35 · がんばったって","de":"V たって — selbst wenn … (gesprochenes ても)","slots":[{"text":"V<sub>たって</sub>","role":"cond","label":"selbst wenn"},{"text":"[trotzdem-Aussage]","role":"plain"}],"gloss":"Gesprochenes ても. がんばったって = がんばっても. Verneint なくたって.","ex":{"jp":"<ruby>今<rt>いま</rt></ruby>から がんばっ<b>たって</b>、もう <ruby>間<rt>ま</rt></ruby>に<ruby>合<rt>あ</rt></ruby>わないよ。","de":"Selbst wenn du dich jetzt noch anstrengst, reicht es nicht mehr."},"simpel":"<b>たって</b> = lockeres ても: »selbst wenn du dich anstrengst …«.<br><span class='jp'>がんばっ<b>たって</b></span> = „selbst wenn man sich anstrengt“","rule":"V<sub>た</sub>-Basis + って = 〜ても in gesprochener Sprache: »selbst wenn / auch wenn«. Verneint: なくたって (= なくても). Adjektive: 高くたって."},{"l":24,"t":"36 · <ruby>無理<rt>むり</rt></ruby>に<ruby>決<rt>き</rt></ruby>まってるよ","de":"〜に決まってる — das ist doch todsicher …","slots":[{"text":"[Aussage]","role":"cond"},{"text":"に<ruby>決<rt>き</rt></ruby>まってる","role":"plain","label":"doch klar!"}],"gloss":"»Das ist doch todsicher so!« — salopp-emotional; formeller: に違いない.","ex":{"jp":"<ruby>優勝<rt>ゆうしょう</rt></ruby>なんて <ruby>無理<rt>むり</rt></ruby><b>に決まってる</b>よ。","de":"Den Sieg holen? Das ist doch todsicher unmöglich!"},"simpel":"Volle Überzeugung, salopp: »ist doch klar!«.<br><span class='jp'><ruby>無理<rt>むり</rt></ruby><b>に決まってる</b>よ</span> = „das ist doch todsicher unmöglich!“","rule":"Plain/N + に決まっている (gesprochen 決まってる): subjektive Gewissheit »ganz sicher, logisch!«. Emotionaler/salopper als に違いない."},{"l":24,"t":"37 · <ruby>行<rt>い</rt></ruby>かなきゃ だめじゃない","de":"〜なきゃだめ(じゃない) — du musst doch …! (Vorwurf)","slots":[{"text":"V<sub>なきゃ</sub>","role":"verb","label":"wenn nicht"},{"text":"だめ","role":"actor","label":"geht nicht"},{"text":"じゃない","role":"plain","label":"doch wohl!"}],"gloss":"»Du musst doch …!« — Pflicht-なきゃだめ + Vorwurfs-じゃない. Reiner Dialog-Ton.","ex":{"jp":"<ruby>友<rt>とも</rt></ruby>だちの <ruby>大会<rt>たいかい</rt></ruby>なんだから、<ruby>行<rt>い</rt></ruby>か<b>なきゃ だめじゃない</b>。","de":"Es ist der Wettkampf deines Freundes — da musst du doch hin!"},"simpel":"Pflicht + Vorwurf: »du MUSST doch hin, oder etwa nicht?!«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>か<b>なきゃ だめじゃない</b></span> = „du musst doch hingehen!“","rule":"V<sub>なきゃ</sub> + だめ = »muss unbedingt« (gesprochen). Angehängtes じゃない(か) macht daraus einen Vorwurf/eine nachdrückliche Bestätigung: »… doch wohl!«."},{"l":24,"t":"38 · <ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby>だって","de":"N だって — sogar … / auch … (betont)","slots":[{"text":"N","role":"subj","label":"sogar"},{"text":"だって","role":"actor","label":"selbst/auch"},{"text":"[Aussage]","role":"plain"}],"gloss":"»Sogar/auch N« — gesprochenes でも/さえ. だれだって = jeder.","ex":{"jp":"<ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>だって</b>、<ruby>緊張<rt>きんちょう</rt></ruby>する ことは ある。","de":"Sogar starke Athleten sind manchmal nervös."},"simpel":"<b>だって</b> nach Nomen = »sogar/selbst X«.<br><span class='jp'><ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>だって</b> <ruby>負<rt>ま</rt></ruby>ける</span> = „sogar starke Athleten verlieren“","rule":"N + だって: (1) »sogar/selbst« (= でも/さえ), (2) »auch« (私だって = ich doch auch). Mit Fragewort + だって = »jede/r« (だれだって). Nur gesprochen."},{"l":24,"t":"39 · <ruby>大変<rt>たいへん</rt></ruby>みたいだね","de":"〜みたいだ — scheint … / anscheinend (gesprochen)","slots":[{"text":"[Beobachtung]","role":"cond"},{"text":"みたいだ","role":"plain","label":"scheint"}],"gloss":"Gesprochenes ようだ: Vermutung aus Beobachtung oder Vergleich (みたいに/な).","ex":{"jp":"<ruby>毎日<rt>まいにち</rt></ruby> <ruby>朝<rt>あさ</rt></ruby> 5<ruby>時<rt>じ</rt></ruby>から <ruby>練習<rt>れんしゅう</rt></ruby>。<ruby>大変<rt>たいへん</rt></ruby><b>みたいだ</b>ね。","de":"Jeden Tag ab 5 Uhr Training — scheint hart zu sein."},"simpel":"<b>みたい</b> = gesprochenes ようだ: »scheint wohl …«.<br><span class='jp'><ruby>大変<rt>たいへん</rt></ruby><b>みたいだ</b>ね</span> = „scheint hart zu sein, was?“","rule":"Plain/N + みたいだ: Vermutung aus Beobachtung (»scheint«), Vergleich (»wie«: みたいに/みたいな). Lockerer als ようだ; beugt wie な-Adjektiv."},{"l":24,"t":"40 · やって おけば よかった","de":"〜ばよかった — hätte ich (doch) … sollen (Reue)","slots":[{"text":"V<sub>テ</sub>おけ<b>ば</b>","role":"verb","label":"hätte (vorher)"},{"text":"よかった","role":"plain","label":"wäre gut gewesen"}],"gloss":"Reue: ば-Form + よかった. Mit ておく = versäumte Vorbereitung. Oft mit なあ.","ex":{"jp":"ぼくも <ruby>水泳<rt>すいえい</rt></ruby>を <ruby>続<rt>つづ</rt></ruby>けて おけ<b>ば よかった</b> なあ。","de":"Hätte ich doch auch mit dem Schwimmen weitergemacht …"},"simpel":"Reue: »hätte ich doch …!« — ば-Form + よかった.<br><span class='jp'>やって おけ<b>ば よかった</b></span> = „hätte ich es (vorher) mal gemacht“","rule":"V<sub>ば</sub> + よかった: Bedauern über Nicht-Getanes (»hätte ich doch …«). Verneint: なければよかった (»hätte ich bloß nicht …«). Hier mit ておく: やっておけばよかった »hätte ich vorbereitend tun sollen«."},{"l":24,"t":"41 · <ruby>遊<rt>あそ</rt></ruby>んで ばかり いた","de":"〜てばかりいる — nichts als … / andauernd nur …","slots":[{"text":"V<sub>テ</sub>","role":"verb"},{"text":"ばかり","role":"actor","label":"nichts als"},{"text":"いる/いた","role":"plain"}],"gloss":"»Macht andauernd nur …« — einseitig, meist kritisch. N + ばかり = lauter N.","ex":{"jp":"<ruby>高校<rt>こうこう</rt></ruby><ruby>時代<rt>じだい</rt></ruby>、ぼくは <ruby>遊<rt>あそ</rt></ruby>んで<b>ばかり いた</b>。","de":"In der Oberschulzeit habe ich nichts als gefaulenzt."},"simpel":"<b>てばかりいる</b> = »macht nichts anderes als …« (leicht tadelnd).<br><span class='jp'><ruby>遊<rt>あそ</rt></ruby>んで<b>ばかり いた</b></span> = „habe nur gespielt/gefaulenzt“","rule":"V<sub>テ</sub> + ばかりいる: jemand tut andauernd nur eine Sache (meist kritisch/bereuend). Auch N + ばかり (甘いものばかり食べる »isst nur Süßes«)."},{"l":25,"t":"42 · <ruby>本当<rt>ほんとう</rt></ruby>の ハムのように","de":"N のように — (genau) wie … (Vergleich)","slots":[{"text":"N","role":"subj","label":"Vergleichsbild"},{"text":"のように","role":"actor","label":"wie"},{"text":"V/Adj","role":"verb"}],"gloss":"»(Genau) wie N« — Vergleich vor Verb/Adjektiv; vor Nomen のような; locker みたいに.","ex":{"jp":"<ruby>本当<rt>ほんとう</rt></ruby>の ハム<b>のように</b> おいしく できます。","de":"Er gelingt so lecker wie echter Schinken."},"simpel":"<b>のように</b> vergleicht: »wie echter Schinken«.<br><span class='jp'><ruby>本当<rt>ほんとう</rt></ruby>の ハム<b>のように</b> おいしい</span> = „lecker wie echter Schinken“","rule":"N + のように + V/Adj: Vergleich »(genau) wie N«. Vor Nomen のような (Punkt 27). Nach Verben heißt ように auch »damit/so dass« — Kontext beachten."},{"l":25,"t":"43 · サンドイッチは もちろん、ほかの <ruby>料理<rt>りょうり</rt></ruby>にも","de":"〜はもちろん — … sowieso, und auch …","slots":[{"text":"N₁","role":"subj","label":"klar"},{"text":"はもちろん、","role":"actor","label":"sowieso"},{"text":"N₂ にも","role":"obj","label":"und auch"}],"gloss":"»N₁ ist eh klar — und (sogar) auch N₂.« Steigernde Aufzählung.","ex":{"jp":"サンドイッチ<b>は もちろん</b>、サラダや パスタ<b>にも</b> <ruby>合<rt>あ</rt></ruby>います。","de":"Passt natürlich zu Sandwiches — aber auch zu Salat und Pasta."},"simpel":"A ist klar, B kommt dazu: »für Sandwiches sowieso, aber auch …«.<br><span class='jp'>サンドイッチ<b>は もちろん</b>、ほかの <ruby>料理<rt>りょうり</rt></ruby><b>にも</b></span>","rule":"N₁ + はもちろん、N₂ + も/にも: »N₁ versteht sich von selbst — und auch N₂«. Erst das Offensichtliche, dann die Erweiterung. Schriftlicher: はもとより."},{"l":25,"t":"44 · もも<ruby>肉<rt>にく</rt></ruby>でも むね<ruby>肉<rt>にく</rt></ruby>でも、どちらでも","de":"〜でも〜でも / どちらでも — egal ob … oder …","slots":[{"text":"A でも","role":"cond","label":"ob A"},{"text":"B でも","role":"cond","label":"oder B"},{"text":"いい/かまわない","role":"plain","label":"beides ok"}],"gloss":"»Egal ob A oder B — beides geht.« Fragewort+でも = jede/r/s (どちらでも, 何でも).","ex":{"jp":"とり<ruby>肉<rt>にく</rt></ruby>は もも<ruby>肉<rt>にく</rt></ruby><b>でも</b> むね<ruby>肉<rt>にく</rt></ruby><b>でも</b>、<b>どちらでも</b> いいです。","de":"Beim Hähnchen geht Keule oder Brust — beides ist in Ordnung."},"simpel":"<b>でも…でも</b> = »egal ob A oder B«; <b>どちらでも</b> = »beides geht«.<br><span class='jp'>もも<ruby>肉<rt>にく</rt></ruby><b>でも</b> むね<ruby>肉<rt>にく</rt></ruby><b>でも</b> いい</span>","rule":"N + でも + N + でも (+いい/かまわない): beide Optionen sind zulässig. Fragewort + でも = totale Offenheit: どちらでも (beides), 何でも (alles), いつでも (jederzeit)."},{"l":25,"t":"45 · はちみつの かわりに","de":"〜のかわりに — anstelle von … / als Ersatz","slots":[{"text":"N の","role":"subj","label":"Original"},{"text":"かわりに","role":"actor","label":"statt"},{"text":"[Ersatz]","role":"obj"}],"gloss":"»Anstelle von N (nimm …)« — Ersatz; nach Verb: »dafür/im Gegenzug«.","ex":{"jp":"はちみつ<b>の かわりに</b> さとうを <ruby>使<rt>つか</rt></ruby>っても いいです。","de":"Statt Honig kann man auch Zucker verwenden."},"simpel":"<b>かわりに</b> = »statt/als Ersatz für«.<br><span class='jp'>はちみつ<b>の かわりに</b> さとう</span> = „statt Honig Zucker“","rule":"N + の + かわりに: Ersatz (»statt N«). V<sub>辞書/た</sub> + かわりに: Ausgleich (»dafür, im Gegenzug«). Beide Lesarten sehr häufig."},{"l":25,"t":"46 · とり<ruby>肉<rt>にく</rt></ruby>を <ruby>切<rt>き</rt></ruby>らずに","de":"〜ずに — ohne zu … (schriftlich für ないで)","slots":[{"text":"N を","role":"obj"},{"text":"V<sub>ず</sub>","role":"verb","label":"ohne zu"},{"text":"に、[Haupthandlung]","role":"plain"}],"gloss":"»Ohne zu V, …« — ない-Stamm + ずに; する→せずに. Anleitungssprache.","ex":{"jp":"とり<ruby>肉<rt>にく</rt></ruby>は <ruby>切<rt>き</rt></ruby>ら<b>ずに</b>、そのまま <ruby>使<rt>つか</rt></ruby>います。","de":"Das Hähnchen wird nicht geschnitten, sondern im Ganzen verwendet."},"simpel":"<b>ずに</b> = »ohne zu …« (eine Spur schriftlicher als ないで).<br><span class='jp'><ruby>切<rt>き</rt></ruby>ら<b>ずに</b> そのまま</span> = „ohne es zu schneiden, im Ganzen“","rule":"V<sub>ない</sub>-Stamm + ずに = 〜ないで (»ohne zu V«). Ausnahme: する → せずに. In Rezepten und Anleitungen sehr üblich."},{"l":25,"t":"47 · ビニール<ruby>袋<rt>ぶくろ</rt></ruby>に <ruby>入<rt>い</rt></ruby>れたまま","de":"〜たまま — im (unveränderten) Zustand belassen","slots":[{"text":"V<sub>た</sub>","role":"verb","label":"Zustand"},{"text":"まま","role":"actor","label":"so belassen"},{"text":"[Handlung]","role":"plain"}],"gloss":"»Im Zustand von V (belassen) etwas tun« — 入れたまま, つけたまま; そのまま = einfach so.","ex":{"jp":"ビニール<ruby>袋<rt>ぶくろ</rt></ruby>に <ruby>入<rt>い</rt></ruby>れた<b>まま</b>、お<ruby>湯<rt>ゆ</rt></ruby>で ゆでます。","de":"Im Plastikbeutel belassen in heißem Wasser garen."},"simpel":"<b>たまま</b> = »so belassen, wie es ist«.<br><span class='jp'><ruby>袋<rt>ふくろ</rt></ruby>に <ruby>入<rt>い</rt></ruby>れた<b>まま</b> ゆでる</span> = „im Beutel (gelassen) kochen“","rule":"V<sub>た</sub> + まま: der einmal hergestellte Zustand bleibt bestehen, während etwas anderes geschieht. Auch N + の + まま (そのまま »einfach so«)."},{"l":25,"t":"48 · ボウルに <ruby>入<rt>い</rt></ruby>れ、…","de":"連用中止形 — Vマス als Satzverbindung (Schriftstil)","slots":[{"text":"V<sub>マス</sub>、","role":"verb","label":"Schritt 1"},{"text":"V<sub>マス</sub>、","role":"verb","label":"Schritt 2"},{"text":"V","role":"plain","label":"Schritt 3"}],"gloss":"Schriftliche Satzverbindung mit dem ます-Stamm — funktional identisch mit て-Form.","ex":{"jp":"<ruby>材料<rt>ざいりょう</rt></ruby>を ボウルに <ruby>入<rt>い</rt></ruby>れ<b>、</b>よく <ruby>混<rt>ま</rt></ruby>ぜます。","de":"Die Zutaten in eine Schüssel geben und gut vermischen."},"simpel":"Schriftlich verbindet der <b>ます-Stamm</b> Sätze statt て-Form.<br><span class='jp'>ボウルに <ruby>入<rt>い</rt></ruby>れ<b>、</b><ruby>混<rt>ま</rt></ruby>ぜる</span> = „in die Schüssel geben und mischen“","rule":"連用中止形: Statt V<sub>テ</sub> steht in geschriebener Sprache (Rezepte, Berichte, Zeitungen) der ます-Stamm + Komma: 入れ、混ぜ、待つ. Bedeutung = て-Form."},{"l":25,"t":"49 · ふっとうした ところへ","de":"〜たところへ/に — genau dahin/da, wo(hin) gerade …","slots":[{"text":"V<sub>た</sub>","role":"verb","label":"Situation"},{"text":"ところへ","role":"actor","label":"genau dahin/da"},{"text":"[B]","role":"plain"}],"gloss":"»In die gerade entstandene Situation hinein …« — räumlich (Rezept) oder zeitlich (Störung/Zufall).","ex":{"jp":"お<ruby>湯<rt>ゆ</rt></ruby>が ふっとうした<b>ところへ</b>、<ruby>袋<rt>ふくろ</rt></ruby>ごと <ruby>入<rt>い</rt></ruby>れます。","de":"Sobald das Wasser kocht, den ganzen Beutel hineingeben."},"simpel":"<b>たところへ</b> = »genau in dem Moment/dorthin, wo …«.<br><span class='jp'>ふっとうした<b>ところへ</b> <ruby>入<rt>い</rt></ruby>れる</span> = „(genau) ins kochende Wasser geben“","rule":"V<sub>た</sub> + ところへ/に: in die Situation, die gerade entstanden ist, kommt etwas hinzu (räumlich oder zeitlich: »gerade als …, da …«)."},{"l":25,"t":"50 · 2、3<ruby>日<rt>にち</rt></ruby>で <ruby>食<rt>た</rt></ruby>べきって ください","de":"Vマス + きる — restlos / ganz zu Ende …","slots":[{"text":"2、3<ruby>日<rt>にち</rt></ruby>で","role":"time","label":"Frist"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"きって ください","role":"plain","label":"restlos!"}],"gloss":"»Komplett zu Ende V-en« — きる; unschaffbar: きれない (数えきれない unzählbar).","ex":{"jp":"<ruby>保存料<rt>ほぞんりょう</rt></ruby>が ないので、2、3<ruby>日<rt>にち</rt></ruby>で <ruby>食<rt>た</rt></ruby>べ<b>きって</b> ください。","de":"Ohne Konservierungsstoffe — bitte binnen 2–3 Tagen aufessen."},"simpel":"<b>きる</b> = komplett aufbrauchen: »innerhalb von 2–3 Tagen aufessen«.<br><span class='jp'><ruby>食<rt>た</rt></ruby>べ<b>きって</b> ください</span> = „bitte ganz aufessen“","rule":"V<sub>ます</sub>-Stamm + きる = eine Handlung vollständig zu Ende führen (使いきる aufbrauchen, 読みきる durchlesen). Negativ きれない = »nicht ganz schaffen« (食べきれない)."},{"l":26,"t":"51 · <ruby>自然<rt>しぜん</rt></ruby>の おかげで","de":"〜のおかげで — dank … (positives Ergebnis)","slots":[{"text":"N の","role":"subj","label":"Wohltäter"},{"text":"おかげで","role":"actor","label":"dank"},{"text":"[gutes Ergebnis]","role":"verb"}],"gloss":"»Dank N (ist etwas Gutes)« — dankbare Ursache; Gegenteil せいで.","ex":{"jp":"<ruby>豊<rt>ゆた</rt></ruby>かな <ruby>自然<rt>しぜん</rt></ruby>の<b>おかげで</b>、おいしい <ruby>米<rt>こめ</rt></ruby>が <ruby>育<rt>そだ</rt></ruby>ちます。","de":"Dank der reichen Natur gedeiht köstlicher Reis."},"simpel":"<b>おかげで</b> = »dank« (dankbar, gutes Ergebnis).<br><span class='jp'><ruby>自然<rt>しぜん</rt></ruby>の<b>おかげで</b></span> = „dank der Natur“","rule":"N + の + おかげで (Plain + おかげで): nennt dankbar den Grund für ein gutes Ergebnis. Negativ-vorwurfsvoll wäre せいで. Ironisch kann おかげで auch bei Schlechtem stehen."},{"l":26,"t":"52 · <ruby>四季<rt>しき</rt></ruby>を<ruby>通<rt>つう</rt></ruby>じて","de":"〜を通じて — … hindurch (Zeitraum) / über …","slots":[{"text":"<ruby>四季<rt>しき</rt></ruby>","role":"time","label":"Zeitraum"},{"text":"を<ruby>通<rt>つう</rt></ruby>じて","role":"actor","label":"hindurch"},{"text":"[Aussage]","role":"verb"}],"gloss":"»Den ganzen Zeitraum hindurch« — 四季/一年/一日を通じて. Sonst: über N (Mittel).","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>では <ruby>四季<rt>しき</rt></ruby><b>を通じて</b> さまざまな <ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby>が <ruby>見<rt>み</rt></ruby>られます。","de":"Im Satoyama sieht man durch alle Jahreszeiten hindurch vielfältige Lebewesen."},"simpel":"<b>を通じて</b> mit Zeitwort = »den ganzen Zeitraum hindurch«.<br><span class='jp'><ruby>四季<rt>しき</rt></ruby><b>を通じて</b></span> = „durch alle vier Jahreszeiten“","rule":"N(Zeit) + を通じて/を通して = »den Zeitraum hindurch, ohne Unterbrechung«. Mit Nicht-Zeit-N: »über/durch N« (Mittel/Vermittler, Punkt 26). を通じて ist die schriftlichere Form."},{"l":26,"t":"53 · <ruby>守<rt>まも</rt></ruby>りたいと <ruby>思<rt>おも</rt></ruby>いませんか","de":"〜と思いませんか — finden Sie nicht (auch)? (Appell)","slots":[{"text":"V<sub>たい</sub>","role":"cond","label":"Wunsch"},{"text":"と<ruby>思<rt>おも</rt></ruby>いませんか","role":"plain","label":"nicht auch?"}],"gloss":"Zustimmungs-Appell: »Denken/möchten Sie nicht auch …?« — Aufruf-Rhetorik.","ex":{"jp":"この <ruby>美<rt>うつく</rt></ruby>しい <ruby>里山<rt>さとやま</rt></ruby>を <ruby>守<rt>まも</rt></ruby>りたい<b>と 思いませんか</b>。","de":"Möchten Sie dieses schöne Satoyama nicht auch bewahren?"},"simpel":"Rhetorischer Appell: »Möchten Sie nicht auch …?«.<br><span class='jp'><ruby>守<rt>まも</rt></ruby>りたい<b>と 思いませんか</b></span> = „möchten Sie sie nicht auch schützen?“","rule":"[Meinung/Wunsch] + と思いませんか: lädt den Hörer ein, zuzustimmen — typisch für Aufrufe, Werbung, Essays. Mit 〜たい davor: »Haben Sie nicht auch Lust …?«."},{"l":26,"t":"54 · <ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby>というと","de":"〜というと — wenn von … die Rede ist, (dann denkt man) …","slots":[{"text":"N","role":"subj","label":"Stichwort"},{"text":"というと","role":"actor","label":"apropos"},{"text":"[typisches Bild]","role":"plain"}],"gloss":"»Bei N denkt man (sofort) an …« — oft gefolgt von einer Korrektur des Klischees.","ex":{"jp":"<ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby><b>というと</b>、<ruby>手<rt>て</rt></ruby>を つけない ことだと <ruby>思<rt>おも</rt></ruby>われがちだ。","de":"Bei „Naturschutz“ denkt man leicht: bloß nichts anrühren."},"simpel":"<b>というと</b> greift ein Stichwort auf: »apropos Naturschutz …«.<br><span class='jp'><ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby><b>というと</b></span> = „wenn man ‚Naturschutz‘ hört, …“","rule":"N + というと/といえば/といったら: nimmt ein Thema auf und nennt die typische Assoziation oder präzisiert nach. Oft um dann zu korrigieren: »… denkt man an X, aber eigentlich …«."},{"l":26,"t":"55 · そのまま <ruby>残<rt>のこ</rt></ruby>すべきだ","de":"〜べきだ — sollte (unbedingt) … (Überzeugung)","slots":[{"text":"[Meinung]","role":"cond"},{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"べきだ","role":"plain","label":"sollte!"}],"gloss":"Normativ: »So gehört es sich / man sollte.« Verneint べきではない. Vorsicht gegenüber Höhergestellten.","ex":{"jp":"<ruby>自然<rt>しぜん</rt></ruby>は そのまま <ruby>残<rt>のこ</rt></ruby>す<b>べきだ</b>と <ruby>考<rt>かんが</rt></ruby>える <ruby>人<rt>ひと</rt></ruby>も <ruby>多<rt>おお</rt></ruby>い。","de":"Viele meinen, man solle die Natur unangetastet lassen."},"simpel":"<b>べきだ</b> = »man sollte (aus Überzeugung/Pflicht)«.<br><span class='jp'>そのまま <ruby>残<rt>のこ</rt></ruby>す<b>べきだ</b></span> = „man sollte es unangetastet erhalten“","rule":"V<sub>辞書</sub> + べきだ: starke normative Empfehlung (»sollte/gehört sich«). する→すべきだ auch möglich. Verneint べきではない. Für Gesetzes-Pflichten eher なければならない."},{"l":26,"t":"56 · <ruby>人<rt>ひと</rt></ruby>にとって いい <ruby>環境<rt>かんきょう</rt></ruby>","de":"〜にとって — für … / aus Sicht von …","slots":[{"text":"N","role":"subj","label":"Perspektive"},{"text":"にとって","role":"actor","label":"für"},{"text":"[Bewertung]","role":"plain"}],"gloss":"»Für N (ist es gut/wichtig …)« — Standpunkt der Bewertung; ≠ に対して (Adressat).","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>は <ruby>人<rt>ひと</rt></ruby>に<b>とって</b>も <ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby>に<b>とって</b>も いい <ruby>環境<rt>かんきょう</rt></ruby>だ。","de":"Das Satoyama ist ein gutes Umfeld für Menschen wie für Tiere."},"simpel":"<b>にとって</b> = Bewertungs-Standpunkt: »für den Menschen (gut)«.<br><span class='jp'><ruby>人<rt>ひと</rt></ruby><b>にとって</b> いい <ruby>環境<rt>かんきょう</rt></ruby></span>","rule":"N + にとって: aus wessen Sicht eine Bewertung gilt (wichtig/schwer/gut …). Attributiv にとっての + N. Nicht mit に対して (Adressat, Punkt 22) verwechseln."},{"l":26,"t":"57 · <ruby>木<rt>き</rt></ruby>が <ruby>育<rt>そだ</rt></ruby>てば <ruby>育<rt>そだ</rt></ruby>つほど","de":"〜ば〜ほど — je …, desto …","slots":[{"text":"V<sub>ば</sub>","role":"cond","label":"je"},{"text":"V<sub>辞書</sub> ほど","role":"actor","label":"desto"},{"text":"[Folge]","role":"plain"}],"gloss":"»Je mehr A, desto mehr B« — dasselbe Wort in ば-Form + 辞書形 + ほど.","ex":{"jp":"<ruby>木<rt>き</rt></ruby>は <ruby>育<rt>そだ</rt></ruby>てば <ruby>育<rt>そだ</rt></ruby>つ<b>ほど</b>、<ruby>森<rt>もり</rt></ruby>が <ruby>豊<rt>ゆた</rt></ruby>かに なる。","de":"Je mehr die Bäume wachsen, desto reicher wird der Wald."},"simpel":"Dasselbe Wort zweimal: »je mehr die Bäume wachsen, desto …«.<br><span class='jp'><ruby>育<rt>そだ</rt></ruby>てば <ruby>育<rt>そだ</rt></ruby>つ<b>ほど</b></span>","rule":"V<sub>ば</sub> + V<sub>辞書</sub> + ほど (い-Adj ければ〜いほど, な-Adj なら〜なほど): proportionale Kopplung »je …, desto …«."},{"l":26,"t":"58 · <ruby>大雨<rt>おおあめ</rt></ruby>による <ruby>山崩<rt>やまくず</rt></ruby>れ","de":"N による N — durch … verursacht (Ursache)","slots":[{"text":"N₁","role":"subj","label":"Ursache"},{"text":"による","role":"actor","label":"verursacht durch"},{"text":"N₂","role":"obj","label":"Folge"}],"gloss":"»N₂, verursacht durch N₁« — Berichts-Stil; adverbial により/によって.","ex":{"jp":"<ruby>手入<rt>てい</rt></ruby>れを しない <ruby>森<rt>もり</rt></ruby>では、<ruby>大雨<rt>おおあめ</rt></ruby><b>による</b> <ruby>山崩<rt>やまくず</rt></ruby>れが <ruby>起<rt>お</rt></ruby>こりやすい。","de":"In ungepflegten Wäldern kommt es leicht zu Erdrutschen durch Starkregen."},"simpel":"<b>による</b> als Ursache: »Erdrutsche durch Starkregen«.<br><span class='jp'><ruby>大雨<rt>おおあめ</rt></ruby><b>による</b> <ruby>山崩<rt>やまくず</rt></ruby>れ</span>","rule":"N₁ + による + N₂: N₁ ist die Ursache von N₂ (Nachrichten-/Berichtsstil). Adverbial により/によって. Vgl. Punkt 21 (Mittel) — gleiche Form, andere Lesart."},{"l":26,"t":"59 · <ruby>田舎<rt>いなか</rt></ruby>ばかりでなく <ruby>東京<rt>とうきょう</rt></ruby>にも","de":"〜ばかりでなく — nicht nur …, sondern auch …","slots":[{"text":"[A]","role":"cond"},{"text":"ばかりでなく","role":"actor","label":"nicht nur"},{"text":"[B] にも","role":"obj","label":"auch"}],"gloss":"»Nicht nur A, sondern auch B« — B trägt も/にも/まで.","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>は <ruby>田舎<rt>いなか</rt></ruby><b>ばかりでなく</b>、<ruby>東京<rt>とうきょう</rt></ruby>の <ruby>近<rt>ちか</rt></ruby>く<b>にも</b> あります。","de":"Satoyama gibt es nicht nur auf dem Land, sondern auch nahe Tokio."},"simpel":"»Nicht nur auf dem Land — auch in Tokio.«<br><span class='jp'><ruby>田舎<rt>いなか</rt></ruby><b>ばかりでなく</b> <ruby>東京<rt>とうきょう</rt></ruby><b>にも</b></span>","rule":"N/Plain + ばかりでなく、… も/にも/まで: »nicht nur A, sondern auch B«. Etwas schriftlicher als だけでなく; noch stärker: ばかりか."},{"l":26,"t":"60 · <ruby>里山<rt>さとやま</rt></ruby>へ <ruby>行<rt>い</rt></ruby>くたびに","de":"〜たびに — jedes Mal, wenn …","slots":[{"text":"V<sub>辞書</sub> / N の","role":"cond"},{"text":"たびに","role":"actor","label":"jedes Mal"},{"text":"[B]","role":"plain"}],"gloss":"»Jedes Mal, wenn A, (dann) B« — Nomen braucht の.","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>へ <ruby>行<rt>い</rt></ruby>く<b>たびに</b>、<ruby>新<rt>あたら</rt></ruby>しい <ruby>発見<rt>はっけん</rt></ruby>が あります。","de":"Bei jedem Satoyama-Besuch gibt es neue Entdeckungen."},"simpel":"»Jedes Mal, wenn ich hinfahre, …«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>く<b>たびに</b></span> = „bei jedem Besuch“","rule":"V<sub>辞書</sub> / N + の + たびに: bei jeder Wiederholung von A tritt B auf. Oft mit Entdeckungen/Gefühlen: 行くたびに 新しい発見がある."},{"l":26,"t":"61 · すばらしさが わかる はずです","de":"〜さ + 〜はずです — die …-heit / müsste (gewiss) …","slots":[{"text":"Adj + さ","role":"subj","label":"die …-heit"},{"text":"が わかる","role":"verb"},{"text":"はずです","role":"plain","label":"gewiss"}],"gloss":"〜さ-Nomen + はず-Erwartung: »die Großartigkeit wird sich Ihnen gewiss erschließen«.","ex":{"jp":"<ruby>一度<rt>いちど</rt></ruby> <ruby>訪<rt>おとず</rt></ruby>れれば、<ruby>里山<rt>さとやま</rt></ruby>の すばらし<b>さ</b>が わかる<b>はずです</b>。","de":"Wer einmal hinfährt, wird die Großartigkeit des Satoyama gewiss erkennen."},"simpel":"<b>〜さ</b> macht Adjektive zu Nomen; <b>はずです</b> = begründete Erwartung.<br><span class='jp'>すばらし<b>さ</b>が わかる <b>はずです</b></span> = „Sie werden die Großartigkeit gewiss erkennen“","rule":"い-Adj-Stamm/な-Adj + さ nominalisiert (すばらしさ, 大切さ, 便利さ). はずだ/はずです drückt die logisch begründete Erwartung aus: »müsste gewiss …« — hier als überzeugtes Versprechen an den Leser."},{"l":27,"t":"62 · その ご<ruby>予算<rt>よさん</rt></ruby>ですと","de":"〜ですと — wenn (es) … ist, (dann) … (Service-Sprache)","slots":[{"text":"ご<ruby>予算<rt>よさん</rt></ruby>","role":"subj","label":"Bedingung"},{"text":"ですと","role":"actor","label":"wenn/bei"},{"text":"[Konsequenz]","role":"plain"}],"gloss":"Höfliches と-Konditional der Beratungssprache: »bei … (ist die Lage so:) …«.","ex":{"jp":"その ご<ruby>予算<rt>よさん</rt></ruby><b>ですと</b>、<ruby>駅前<rt>えきまえ</rt></ruby>は <ruby>難<rt>むずか</rt></ruby>しいですね。","de":"Bei diesem Budget wird es direkt am Bahnhof schwierig."},"simpel":"Höfliches と-Konditional im Beratungsgespräch.<br><span class='jp'>その ご<ruby>予算<rt>よさん</rt></ruby><b>ですと</b></span> = „bei diesem Budget …“","rule":"N/Aussage + ですと: höfliche Variante des と-Konditionals (»wenn/bei …, dann zwangsläufig …«), typisch für Verkäufer und Berater. Danach folgt die sachliche Konsequenz."},{"l":27,"t":"63 · お<ruby>時間<rt>じかん</rt></ruby>が あるようなら","de":"〜ようなら — falls es (danach) aussieht / falls …","slots":[{"text":"[Anschein]","role":"cond"},{"text":"ようなら","role":"actor","label":"falls"},{"text":"[Vorschlag]","role":"plain"}],"gloss":"Vorsichtiges Konditional aus ようだ + なら: »falls es sich so ergibt, …«.","ex":{"jp":"お<ruby>時間<rt>じかん</rt></ruby>が ある<b>ようなら</b>、<ruby>実際<rt>じっさい</rt></ruby>に <ruby>物件<rt>ぶっけん</rt></ruby>を ご<ruby>案内<rt>あんない</rt></ruby>します。","de":"Falls Sie Zeit haben, zeige ich Ihnen die Objekte gern vor Ort."},"simpel":"<b>ようなら</b> = »falls es so ist/aussieht, dass …«.<br><span class='jp'>お<ruby>時間<rt>じかん</rt></ruby>が ある<b>ようなら</b></span> = „falls Sie Zeit haben (sollten)“","rule":"Plain + ようなら (= ようだったら): vorsichtige Bedingung auf Basis eines Anscheins — »falls es sich so darstellt, dass …«. Höflich-distanziert, gern in Vorschlägen."},{"l":27,"t":"64 · <ruby>人気<rt>にんき</rt></ruby>が <ruby>出<rt>で</rt></ruby>て きたんです","de":"〜てくる — ist (allmählich) … geworden (bis jetzt)","slots":[{"text":"<ruby>人気<rt>にんき</rt></ruby>が","role":"subj"},{"text":"<ruby>出<rt>で</rt></ruby>て","role":"verb"},{"text":"きた(んです)","role":"plain","label":"bis jetzt"}],"gloss":"Veränderung, die bis zum Jetzt herangewachsen ist — てくる; Zukunftsrichtung: ていく.","ex":{"jp":"この <ruby>辺<rt>へん</rt></ruby>は <ruby>最近<rt>さいきん</rt></ruby> <ruby>人気<rt>にんき</rt></ruby>が <ruby>出<rt>で</rt></ruby>て<b>きたんです</b>。","de":"Diese Gegend ist in letzter Zeit nämlich beliebt geworden."},"simpel":"<b>てきた</b> = Entwicklung bis jetzt: »ist beliebt geworden«.<br><span class='jp'><ruby>人気<rt>にんき</rt></ruby>が <ruby>出<rt>で</rt></ruby>て<b>きた</b>んです</span>","rule":"V<sub>テ</sub> + くる: eine Veränderung hat begonnen und reicht bis jetzt (人気が出てきた, 寒くなってきた). Gegenstück ていく = ab jetzt weiter (Punkt 8). +んです erklärt dem Kunden die Lage."},{"l":27,"t":"65 · <ruby>借<rt>か</rt></ruby>りたい <ruby>人<rt>ひと</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えて いる ものですから","de":"〜ものですから — weil nun mal … (höfliche Rechtfertigung)","slots":[{"text":"[Umstand]","role":"cond"},{"text":"ものですから","role":"actor","label":"weil nun mal"},{"text":"[Konsequenz]","role":"plain"}],"gloss":"Höfliche Rechtfertigung: »die Lage ist eben so, daher …«.","ex":{"jp":"<ruby>借<rt>か</rt></ruby>りたい <ruby>方<rt>かた</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えて いる<b>ものですから</b>、<ruby>家賃<rt>やちん</rt></ruby>も <ruby>上<rt>あ</rt></ruby>がって いまして。","de":"Da die Nachfrage nun mal steigt, sind auch die Mieten gestiegen."},"simpel":"Grund als höfliche Entschuldigung: »es ist nun mal so, dass …«.<br><span class='jp'><ruby>増<rt>ふ</rt></ruby>えて いる<b>ものですから</b></span>","rule":"Plain + ものですから (locker もので/もんで): rechtfertigt höflich einen unangenehmen Umstand (»ich kann nichts dafür — es ist eben so«). Kein Befehl im Hauptsatz."},{"l":27,"t":"66 · こちら なんか いかがですか","de":"〜なんか いかがですか — wie wäre es (zum Beispiel) mit …?","slots":[{"text":"こちら","role":"subj","label":"Kandidat"},{"text":"なんか","role":"actor","label":"z. B."},{"text":"いかがですか","role":"plain","label":"wie wäre es?"}],"gloss":"Unverbindlicher Beispiel-Vorschlag: »wie wäre etwa …?« — なんか = など.","ex":{"jp":"こちらの お<ruby>部屋<rt>へや</rt></ruby><b>なんか</b> いかがですか。","de":"Wie wäre es zum Beispiel mit dieser Wohnung?"},"simpel":"Vorschlag mit Beispiel-なんか: »wie wär's etwa mit dem hier?«.<br><span class='jp'>こちら<b>なんか</b> いかがですか</span>","rule":"N + なんか + いかがですか/どうですか: unverbindlicher Vorschlag (»z. B. so etwas wie N«). Dieses なんか ist das Beispiel-なんか (= など), nicht das abwertende."},{"l":27,"t":"67 · <ruby>便利<rt>べんり</rt></ruby>かと <ruby>思<rt>おも</rt></ruby>いますが","de":"〜かと思いますが — ich denke (wohl) …, aber (vorsichtig)","slots":[{"text":"[Einschätzung]","role":"cond"},{"text":"かと<ruby>思<rt>おも</rt></ruby>いますが","role":"plain","label":"dürfte wohl …"}],"gloss":"Vorsichtige Einschätzung: か entschärft, が übergibt das Urteil — typisch Beratung.","ex":{"jp":"<ruby>駅<rt>えき</rt></ruby>にも <ruby>近<rt>ちか</rt></ruby>いですし、<ruby>便利<rt>べんり</rt></ruby><b>かと 思いますが</b>。","de":"Auch bahnhofsnah — dürfte recht praktisch sein, denke ich."},"simpel":"Abgeschwächte Meinung: »dürfte praktisch sein, denke ich«.<br><span class='jp'><ruby>便利<rt>べんり</rt></ruby><b>かと 思いますが</b></span>","rule":"[Meinung] + かと思います: das か macht die Aussage vorsichtig-unaufdringlich (»dürfte wohl«). Das が am Ende überlässt dem Kunden das Urteil. Beratungs-/Geschäftssprache."},{"l":27,"t":"68 · <ruby>住<rt>す</rt></ruby>んで いる うちに <ruby>慣<rt>な</rt></ruby>れますよ","de":"〜うちに — im Laufe von … (unbemerkt) / solange","slots":[{"text":"V<sub>ている</sub>","role":"cond","label":"laufend"},{"text":"うちに","role":"actor","label":"im Laufe"},{"text":"[Veränderung]","role":"plain"}],"gloss":"Unbemerkte Veränderung während einer laufenden Handlung — oder Zeitfenster (solange/bevor).","ex":{"jp":"<ruby>住<rt>す</rt></ruby>んで いる<b>うちに</b>、だんだん <ruby>慣<rt>な</rt></ruby>れますよ。","de":"Beim Wohnen gewöhnen Sie sich nach und nach daran."},"simpel":"<b>ているうちに</b> = »während/im Laufe des …s (passiert von selbst)«.<br><span class='jp'><ruby>住<rt>す</rt></ruby>んで いる<b>うちに</b> <ruby>慣<rt>な</rt></ruby>れます</span>","rule":"V<sub>ている</sub> + うちに: während einer laufenden Handlung tritt unbemerkt eine Veränderung ein (»beim Wohnen gewöhnt man sich«). Auch »solange noch« (明るいうちに) und ないうちに (»bevor«)."},{"l":27,"t":"69 · <ruby>卒業<rt>そつぎょう</rt></ruby>した ばかり なんだから","de":"〜たばかり — gerade erst … (+ なんだから: schließlich)","slots":[{"text":"V<sub>た</sub>","role":"verb"},{"text":"ばかり","role":"actor","label":"gerade erst"},{"text":"なんだから","role":"plain","label":"schließlich"}],"gloss":"»Du hast doch gerade erst … — deshalb (Rat/Trost)«. ばかり = gefühlt frisch.","ex":{"jp":"<ruby>卒業<rt>そつぎょう</rt></ruby>した<b>ばかり</b> なんだから、<ruby>焦<rt>あせ</rt></ruby>らなくて いいよ。","de":"Du hast doch gerade erst den Abschluss gemacht — kein Grund zur Eile."},"simpel":"<b>たばかり</b> = »gerade erst passiert«; <b>なんだから</b> begründet nachdrücklich.<br><span class='jp'><ruby>卒業<rt>そつぎょう</rt></ruby>した<b>ばかり</b> なんだから</span>","rule":"V<sub>た</sub> + ばかり: die Handlung liegt (gefühlt) ganz kurz zurück. なんだから = »schließlich ist es so, dass« — nachdrückliche Begründung, oft vor Rat/Trost."},{"l":27,"t":"70 · <ruby>見<rt>み</rt></ruby>れば いいのに","de":"〜ばいいのに — du solltest doch (einfach) … / schade, dass nicht","slots":[{"text":"V<sub>ば</sub>","role":"verb","label":"wenn du …"},{"text":"いいのに","role":"plain","label":"wäre doch gut!"}],"gloss":"»Es wäre doch gut, wenn du … (warum nicht?)« — Rat mit mildem Vorwurf.","ex":{"jp":"<ruby>迷<rt>まよ</rt></ruby>って いるなら、<ruby>実際<rt>じっさい</rt></ruby>に <ruby>見<rt>み</rt></ruby>れば <b>いいのに</b>。","de":"Wenn du unsicher bist — schau es dir doch einfach an!"},"simpel":"Rat + Bedauern: »schau es dir doch (einfach) an!«.<br><span class='jp'><ruby>見<rt>み</rt></ruby>れば <b>いいのに</b></span>","rule":"V<sub>ば</sub> + いいのに: Empfehlung mit Unterton »warum tust du es nicht?« (leichtes Bedauern/Vorwurf). Ohne のに = neutraler Rat (見ればいい)."},{"l":27,"t":"71 · <ruby>見<rt>み</rt></ruby>せて もらっても いいですか","de":"〜てもらってもいいですか — dürfte ich (Sie bitten) …?","slots":[{"text":"V<sub>テ</sub>","role":"verb","label":"gewünschte Handlung"},{"text":"もらっても","role":"actor","label":"(von Ihnen)"},{"text":"いいですか","role":"plain","label":"wäre das ok?"}],"gloss":"Bitte als Erlaubnisfrage: »wäre es ok, wenn Sie für mich …?« — weich und höflich.","ex":{"jp":"この <ruby>部屋<rt>へや</rt></ruby>、<ruby>中<rt>なか</rt></ruby>を <ruby>見<rt>み</rt></ruby>せて<b>もらっても いいですか</b>。","de":"Dürfte ich mir diese Wohnung von innen ansehen?"},"simpel":"Sehr höfliche Bitte: »dürfte ich es mir zeigen lassen?«.<br><span class='jp'><ruby>見<rt>み</rt></ruby>せて<b>もらっても いいですか</b></span>","rule":"V<sub>テ</sub> + もらってもいいですか: Bitte als Erlaubnisfrage verpackt — weicher als 〜てください. Noch höflicher: 〜ていただいてもいいですか / 〜ていただけますか."},{"l":28,"t":"72 · ご<ruby>紹介<rt>しょうかい</rt></ruby>いただきましたよ","de":"ご/お〜いただく — (ehrerbietig) von jdm. … bekommen","slots":[{"text":"ご/お","role":"actor","label":"Keigo-Präfix"},{"text":"[Handlung]","role":"verb"},{"text":"いただく","role":"plain","label":"ehrerbietig erhalten"}],"gloss":"Bescheidenes てもらう: »wir durften (von Ihnen) …« — Bewerbungs-/Geschäftston.","ex":{"jp":"<ruby>田中<rt>たなか</rt></ruby><ruby>先生<rt>せんせい</rt></ruby>に ご<ruby>紹介<rt>しょうかい</rt></ruby><b>いただきました</b>。","de":"Professor Tanaka hat mich (freundlicherweise) an Sie vermittelt."},"simpel":"謙譲: »wir wurden (freundlicherweise) mit Ihnen bekannt gemacht«.<br><span class='jp'>ご<ruby>紹介<rt>しょうかい</rt></ruby><b>いただきました</b></span>","rule":"お/ご + V<sub>マス/漢語</sub> + いただく: die bescheidene Form von てもらう — »wir durften von Ihnen/über Sie … erhalten«. 漢語-Verben nehmen ご (ご紹介), 和語 nehmen お (お越し)."},{"l":28,"t":"73 · お<ruby>待<rt>ま</rt></ruby>ちして いました","de":"お〜する — bescheiden: ich (er)warte(te) Sie","slots":[{"text":"お","role":"actor","label":"Präfix"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"して いました","role":"plain","label":"(für Sie)"}],"gloss":"Bescheidene Eigenhandlung zugunsten des Gegenübers: お待ちする, ご案内する.","ex":{"jp":"お<b>待<ruby>ま</ruby>ちして いました</b>。どうぞ こちらへ。","de":"Wir haben Sie erwartet — bitte hier entlang."},"simpel":"謙譲-Grundmuster: <b>お + ます-Stamm + する</b>.<br><span class='jp'>お<ruby>待<rt>ま</rt></ruby>ち<b>して いました</b></span> = „wir haben Sie erwartet“","rule":"お + V<sub>マス</sub> + する (漢語: ご〜する): die eigene Handlung bescheiden ausdrücken, wenn sie dem Gegenüber gilt. お待ちする, お送りする, ご案内する."},{"l":28,"t":"74 · <ruby>来日<rt>らいにち</rt></ruby><ruby>前<rt>まえ</rt></ruby>から <ruby>存<rt>ぞん</rt></ruby>じ<ruby>上<rt>あ</rt></ruby>げて おり","de":"〜ており — formelles ていて (+ 存じ上げる: kennen, 謙譲)","slots":[{"text":"<ruby>前<rt>まえ</rt></ruby>から","role":"time"},{"text":"V<sub>テ</sub>","role":"verb"},{"text":"おり、","role":"plain","label":"formell ていて"}],"gloss":"Formelle Verlaufs-/Verbindungsform mit おる; 存じ上げております = »ich kenne (Sie) ehrerbietig«.","ex":{"jp":"<ruby>御社<rt>おんしゃ</rt></ruby>の <ruby>製品<rt>せいひん</rt></ruby>は <ruby>来日<rt>らいにち</rt></ruby><ruby>前<rt>まえ</rt></ruby>から <ruby>存<rt>ぞん</rt></ruby>じて<b>おり</b>、ずっと <ruby>憧<rt>あこが</rt></ruby>れて いました。","de":"Die Produkte Ihres Hauses kannte ich schon vor meiner Ankunft in Japan und habe sie stets bewundert."},"simpel":"<b>ており</b> = schriftlich-formelles ていて; <b>存じ上げる</b> = bescheiden »kennen«.<br><span class='jp'><ruby>存<rt>ぞん</rt></ruby>じ<ruby>上<rt>あ</rt></ruby>げて<b>おり</b></span> = „ich kenne (Sie/es) bereits, und …“","rule":"V<sub>テ</sub> + おり(、) ist die 謙譲/formelle Verbindungsform von ていて (おる statt いる). 存じ上げる = bescheidenes 知っている für Personen/Dinge des Gegenübers."},{"l":28,"t":"75 · <ruby>作品<rt>さくひん</rt></ruby>は お<ruby>持<rt>も</rt></ruby>ちですか","de":"お〜ですか — 尊敬: haben/tun Sie …? (kompakt)","slots":[{"text":"N は","role":"obj"},{"text":"お + V<sub>マス</sub>","role":"verb","label":"尊敬"},{"text":"ですか","role":"plain"}],"gloss":"Kompaktes 尊敬 für Zustände des Gegenübers: お持ちですか = haben Sie dabei?","ex":{"jp":"ポートフォリオ、<ruby>作品<rt>さくひん</rt></ruby>は お<ruby>持<rt>も</rt></ruby>ち<b>ですか</b>。","de":"Haben Sie Ihr Portfolio, Ihre Arbeiten dabei?"},"simpel":"尊敬-Kurzmuster: <b>お + ます-Stamm + ですか</b>.<br><span class='jp'>お<ruby>持<rt>も</rt></ruby>ち<b>ですか</b></span> = „haben Sie (dabei)?“","rule":"お + V<sub>マス</sub> + です: kompakte Respektform für Handlungen/Zustände des Gegenübers (お持ちです = 持っていらっしゃる). Häufig: お持ちですか, おわかりですか, お急ぎですか."},{"l":28,"t":"76 · ご<ruby>覧<rt>らん</rt></ruby>いただけますでしょうか","de":"ご覧いただけますか — dürfte ich Sie bitten, es anzusehen?","slots":[{"text":"こちらを","role":"obj"},{"text":"ご<ruby>覧<rt>らん</rt></ruby>","role":"verb","label":"ansehen (尊敬)"},{"text":"いただけますでしょうか","role":"plain","label":"dürfte ich bitten"}],"gloss":"Superhöfliche Bitte: ご覧 (sehen) + いただける (dürfen wir erhalten) + ますでしょうか.","ex":{"jp":"こちらの <ruby>作品<rt>さくひん</rt></ruby>を ご<ruby>覧<rt>らん</rt></ruby><b>いただけますでしょうか</b>。","de":"Dürfte ich Sie bitten, sich diese Arbeit anzusehen?"},"simpel":"Doppelt höfliche Bitte ums Ansehen.<br><span class='jp'>ご<ruby>覧<rt>らん</rt></ruby><b>いただけますでしょうか</b></span>","rule":"ご覧になる = 尊敬 für 見る. ご覧いただく = »(Sie) sehen es sich für mich an« (謙譲側). Potential + ですか/でしょうか = superweiche Bitte: ご覧いただけますか → いただけますでしょうか."},{"l":28,"t":"77 · ご<ruby>専門<rt>せんもん</rt></ruby>は デザインで いらっしゃいますか","de":"〜でいらっしゃいます — 尊敬-Kopula: Sie sind …","slots":[{"text":"ご<ruby>専門<rt>せんもん</rt></ruby>は","role":"subj","label":"des Gegenübers"},{"text":"N","role":"obj"},{"text":"でいらっしゃいますか","role":"plain","label":"sind Sie?"}],"gloss":"尊敬-Kopula: beschreibt respektvoll das Gegenüber; über sich selbst でございます.","ex":{"jp":"ご<ruby>専門<rt>せんもん</rt></ruby>は グラフィックデザインで<b>いらっしゃいますか</b>。","de":"Ihr Fachgebiet ist Grafikdesign, richtig?"},"simpel":"Die Respekt-Version von です für Personen: <b>でいらっしゃいます</b>.<br><span class='jp'>デザインで<b>いらっしゃいますか</b></span>","rule":"N + でいらっしゃる = 尊敬 von だ/です, wenn das Prädikat die respektierte Person beschreibt (ご専門, お名前, ご出身 …). Über sich selbst: でございます (丁寧)."},{"l":28,"t":"78 · <ruby>始<rt>はじ</rt></ruby>めさせて いただきます","de":"〜させていただく — mit Ihrer Erlaubnis werde ich …","slots":[{"text":"それでは","role":"time","label":"nun denn"},{"text":"V<sub>させて</sub>","role":"verb","label":"mit Erlaubnis"},{"text":"いただきます","role":"plain","label":"(ehrerbietig)"}],"gloss":"»Mit Ihrer (gedachten) Erlaubnis tue ich …« — Präsentations-/Geschäftsformel.","ex":{"jp":"それでは、<ruby>面接<rt>めんせつ</rt></ruby>を <ruby>始<rt>はじ</rt></ruby>め<b>させて いただきます</b>。","de":"Nun denn — ich erlaube mir, mit dem Gespräch zu beginnen."},"simpel":"Maximal bescheiden handeln: »ich erlaube mir, zu beginnen«.<br><span class='jp'><ruby>始<rt>はじ</rt></ruby>め<b>させて いただきます</b></span>","rule":"V<sub>使役て</sub> + いただく: die eigene Handlung als gewährte Erlaubnis darstellen — Standard bei Präsentationen, Anrufen, Absagen. Nicht inflationär verwenden."},{"l":29,"t":"79 · <ruby>花<rt>はな</rt></ruby>が <ruby>咲<rt>さ</rt></ruby>いて からでなければ","de":"〜てからでなければ — erst nachdem …, sonst nicht","slots":[{"text":"V<sub>テ</sub>","role":"verb","label":"erst A"},{"text":"からでなければ","role":"actor","label":"vorher nicht"},{"text":"〜ない","role":"plain","label":"geht B nicht"}],"gloss":"»Solange A nicht erledigt ist, geht B nicht.« て-Form + からでなければ + Verneinung.","ex":{"jp":"<ruby>花<rt>はな</rt></ruby>が <ruby>咲<rt>さ</rt></ruby>いて<b>からでなければ</b>、<ruby>日<rt>ひ</rt></ruby>にちは <ruby>決<rt>き</rt></ruby>められません。","de":"Bevor die Blüten aufgehen, lässt sich kein Termin festlegen."},"simpel":"Erst muss A passieren, sonst geht B nicht.<br><span class='jp'><ruby>咲<rt>さ</rt></ruby>いて<b>からでなければ</b></span> = „erst wenn sie blühen …“","rule":"V<sub>テ</sub> + からでなければ/からでないと + Verneinung: »solange A nicht geschehen ist, ist B unmöglich«. Der Hauptsatz ist immer negativ (できない/わからない/だめ)."},{"l":29,"t":"80 · <ruby>雪<rt>ゆき</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>って いる かのように","de":"〜かのように — (gerade) so, als ob …","slots":[{"text":"まるで","role":"time","label":"gerade so"},{"text":"[irreal<sub>Plain</sub>]","role":"cond"},{"text":"かのように","role":"actor","label":"als ob"}],"gloss":"»So, als ob … (ist es aber nicht)« — irrealer, bildhafter Vergleich.","ex":{"jp":"<ruby>桜<rt>さくら</rt></ruby>の <ruby>花<rt>はな</rt></ruby>びらが、まるで <ruby>雪<rt>ゆき</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>って いる<b>かのように</b> <ruby>舞<rt>ま</rt></ruby>って いた。","de":"Die Kirschblütenblätter tanzten, als ob es schneite."},"simpel":"Irrealer Vergleich: »als ob es schneite«.<br><span class='jp'><ruby>雪<rt>ゆき</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>って いる<b>かのように</b></span>","rule":"Plain + かのようだ/かのように/かのような: Vergleich mit etwas, das NICHT wirklich so ist — oft mit まるで. Literarischer als schlichtes ように."},{"l":29,"t":"81 · <ruby>花<rt>はな</rt></ruby>が <ruby>散<rt>ち</rt></ruby>らない うちに","de":"〜ないうちに — bevor … (das Fenster schließt)","slots":[{"text":"V<sub>ない</sub>","role":"cond","label":"bevor"},{"text":"うちに","role":"actor","label":"im Fenster"},{"text":"[Handlung]","role":"plain"}],"gloss":"»Bevor A eintritt, (schnell) B tun« — Zeitfenster nutzen.","ex":{"jp":"<ruby>花<rt>はな</rt></ruby>が <ruby>散<rt>ち</rt></ruby>らない<b>うちに</b>、お<ruby>花見<rt>はなみ</rt></ruby>に <ruby>行<rt>い</rt></ruby>きましょう。","de":"Gehen wir zum Hanami, bevor die Blüten fallen!"},"simpel":"»Bevor die Blüten fallen (solange sie noch da sind)«.<br><span class='jp'><ruby>散<rt>ち</rt></ruby>らない<b>うちに</b></span>","rule":"V<sub>ない</sub> + うちに: etwas erledigen, BEVOR ein unerwünschter Zustand eintritt. Das positive Gegenstück (solange noch) ist Adj/ている + うちに (Punkt 68)."},{"l":29,"t":"82 · <ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><ruby>向<rt>む</rt></ruby>けに","de":"N 向けに — eigens für … (+Plus: 〜向き)","slots":[{"text":"N","role":"subj","label":"Zielgruppe"},{"text":"<ruby>向<rt>む</rt></ruby>けに","role":"actor","label":"extra für"},{"text":"[Angebot]","role":"obj"}],"gloss":"»Eigens für Zielgruppe N« — 向け (Absicht) vs 向き (natürliche Eignung).","ex":{"jp":"<ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><b>向けに</b>、お<ruby>弁当<rt>べんとう</rt></ruby>が <ruby>売<rt>う</rt></ruby>られて いる。","de":"Für die Hanami-Gäste werden Bentos verkauft."},"simpel":"<b>向け</b> = bewusst für eine Zielgruppe gemacht.<br><span class='jp'><ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><b>向けに</b></span> = „(extra) für Hanami-Gäste“","rule":"N + 向け(に/の): eigens für die Zielgruppe N hergestellt/angeboten. +Plus 向き = »eignet sich (von Natur aus) für« — der Unterschied ist Absicht vs. Eignung."},{"l":29,"t":"83 · <ruby>人<rt>ひと</rt></ruby>によって <ruby>楽<rt>たの</rt></ruby>しみ<ruby>方<rt>かた</rt></ruby>は それぞれだ","de":"〜によって — je nach … (unterschiedlich)","slots":[{"text":"N","role":"subj","label":"Variable"},{"text":"によって","role":"actor","label":"je nach"},{"text":"それぞれだ","role":"plain","label":"jeweils anders"}],"gloss":"»Je nach N unterschiedlich« — Nachsatz mit 違う/それぞれ/さまざま.","ex":{"jp":"お<ruby>花見<rt>はなみ</rt></ruby>の <ruby>楽<rt>たの</rt></ruby>しみ<ruby>方<rt>かた</rt></ruby>は、<ruby>人<rt>ひと</rt></ruby><b>によって</b> それぞれだ。","de":"Wie man Hanami genießt, ist von Person zu Person verschieden."},"simpel":"<b>によって</b> = »je nach« bei Verschiedenheit.<br><span class='jp'><ruby>人<rt>ひと</rt></ruby><b>によって</b> それぞれ</span> = „je nach Person verschieden“","rule":"N + によって + 違う/それぞれだ/さまざまだ: N ist die Variable, nach der sich etwas unterscheidet. Vierte Lesart der による-Familie (vgl. 21 Mittel, 58 Ursache)."},{"l":29,"t":"84 · <ruby>仕事<rt>しごと</rt></ruby>の <ruby>最中<rt>さいちゅう</rt></ruby>に","de":"〜の最中に — mitten in / mittendrin, als …","slots":[{"text":"N の","role":"cond","label":"laufend"},{"text":"<ruby>最中<rt>さいちゅう</rt></ruby>に","role":"actor","label":"mittendrin"},{"text":"[Störung]","role":"plain"}],"gloss":"»Genau mittendrin passiert (störend) …« — intensivste Phase.","ex":{"jp":"<ruby>仕事<rt>しごと</rt></ruby>の<b>最中に</b>、<ruby>花見<rt>はなみ</rt></ruby>の <ruby>誘<rt>さそ</rt></ruby>いの <ruby>電話<rt>でんわ</rt></ruby>が きた。","de":"Mitten in der Arbeit kam der Anruf mit der Hanami-Einladung."},"simpel":"»Mitten in der Arbeit (kam etwas dazwischen)«.<br><span class='jp'><ruby>仕事<rt>しごと</rt></ruby>の<b>最中に</b></span>","rule":"N + の / V<sub>ている</sub> + 最中に: genau in der intensivsten Phase einer laufenden Handlung geschieht (störend) etwas anderes."},{"l":29,"t":"85 · やりかけの <ruby>仕事<rt>しごと</rt></ruby>","de":"〜かけの N — halb erledigt / angefangen (liegen geblieben)","slots":[{"text":"V<sub>マス</sub>","role":"verb"},{"text":"かけの","role":"actor","label":"halb …"},{"text":"N","role":"obj"}],"gloss":"»Angefangen, nicht zu Ende« — かけの + N; als Verb auch »kurz davor/ansetzen«.","ex":{"jp":"やり<b>かけの</b> <ruby>仕事<rt>しごと</rt></ruby>が <ruby>気<rt>き</rt></ruby>に なって、<ruby>楽<rt>たの</rt></ruby>しめない。","de":"Die halb fertige Arbeit geht mir nicht aus dem Kopf — ich kann es nicht genießen."},"simpel":"<b>やりかけ</b> = angefangen und liegen gelassen.<br><span class='jp'>やり<b>かけの</b> <ruby>仕事<rt>しごと</rt></ruby></span> = „die halb fertige Arbeit“","rule":"V<sub>ます</sub>-Stamm + かけ(の N): unvollendet abgebrochen. Verb: 〜かける auch »kurz davor« (死にかける) und »ansetzen« (言いかける)."},{"l":29,"t":"86 · <ruby>行<rt>い</rt></ruby>かずには いられない","de":"〜ずにはいられない — ich kann nicht anders, als … (+Plus: ないではいられない)","slots":[{"text":"V<sub>ず</sub>","role":"verb","label":"nicht-tun"},{"text":"にはいられない","role":"plain","label":"geht nicht"}],"gloss":"»Es nicht zu tun ist unmöglich« = ich muss einfach. Unwillkürlicher Drang.","ex":{"jp":"<ruby>満開<rt>まんかい</rt></ruby>と <ruby>聞<rt>き</rt></ruby>いたら、<ruby>行<rt>い</rt></ruby>か<b>ずには いられない</b>。","de":"Wenn ich „volle Blüte“ höre, muss ich einfach hin."},"simpel":"Unwiderstehlicher Drang: »ich MUSS einfach hin«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>か<b>ずには いられない</b></span>","rule":"V<sub>ない</sub>-Stamm + ずにはいられない (する→せずに): ein innerer Drang lässt sich nicht unterdrücken. +Plus: 〜ないではいられない = gesprochenere Variante."},{"l":30,"t":"87 · できる わけがない","de":"〜わけがない — kann unmöglich … (logisch ausgeschlossen)","slots":[{"text":"[Behauptung]","role":"cond"},{"text":"わけがない","role":"plain","label":"unmöglich!"}],"gloss":"»Ausgeschlossen, dass …« — starke logische Verneinung; Familie: わけではない/わけにはいかない.","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby>で <ruby>食<rt>た</rt></ruby>べて いける? できる<b>わけがない</b>でしょう。","de":"Vom Theater leben? Das kann doch unmöglich klappen."},"simpel":"»Völlig ausgeschlossen, dass das klappt.«<br><span class='jp'>できる<b>わけがない</b></span>","rule":"Plain + わけがない: aus Sicht des Sprechers logisch unmöglich (»wie sollte das gehen?!«). Stärker und emotionaler als はずがない. Nicht mit わけではない (»nicht unbedingt«) verwechseln."},{"l":30,"t":"88 · この <ruby>仕事<rt>しごと</rt></ruby>しか ない","de":"〜しかない — nur … / es bleibt nur …","slots":[{"text":"N","role":"subj"},{"text":"しか","role":"actor","label":"nur"},{"text":"ない","role":"plain","label":"(sonst nichts)"}],"gloss":"しか erzwingt Verneinung: »nur« mit Mangel-Nuance; V+しかない = einzige Option.","ex":{"jp":"<ruby>安定<rt>あんてい</rt></ruby>を <ruby>考<rt>かんが</rt></ruby>えたら、この <ruby>仕事<rt>しごと</rt></ruby><b>しか ない</b>。","de":"Wenn man an Sicherheit denkt, gibt es nur diesen Job."},"simpel":"<b>しか + Verneinung</b> = »nur«; <b>V しかない</b> = »bleibt nichts übrig als«.<br><span class='jp'>この <ruby>仕事<rt>しごと</rt></ruby><b>しか ない</b></span>","rule":"N + しか + Verneinung: »nur N (und sonst nichts)« — mit Mangel-Gefühl. V<sub>辞書</sub> + しかない: »es bleibt nur, zu …« (Resignation/Entschluss)."},{"l":30,"t":"89 · <ruby>心配<rt>しんぱい</rt></ruby>して いる からこそ","de":"〜からこそ — gerade weil …","slots":[{"text":"[Grund]","role":"cond"},{"text":"からこそ","role":"actor","label":"gerade weil"},{"text":"[Handlung] んだ","role":"plain"}],"gloss":"»Gerade weil A — deshalb B.« Grund mit Nachdruck, oft gegen die Erwartung.","ex":{"jp":"あなたを <ruby>心配<rt>しんぱい</rt></ruby>して いる<b>からこそ</b>、<ruby>反対<rt>はんたい</rt></ruby>する んです。","de":"Gerade weil ich mir Sorgen um dich mache, bin ich dagegen."},"simpel":"Betont den wahren Grund: »gerade WEIL ich mir Sorgen mache«.<br><span class='jp'><ruby>心配<rt>しんぱい</rt></ruby>して いる<b>からこそ</b></span>","rule":"Plain + からこそ: hebt den Grund nachdrücklich hervor — oft gegen die Erwartung des Hörers (»nicht obwohl, sondern gerade weil«). Ende gern mit のだ/んだ."},{"l":30,"t":"90 · <ruby>演劇<rt>えんげき</rt></ruby>なんか しても","de":"〜なんか — so etwas wie … (abwertend) + ても","slots":[{"text":"N","role":"subj"},{"text":"なんか","role":"actor","label":"sowas wie (pff)"},{"text":"しても …ない","role":"plain","label":"bringt nichts"}],"gloss":"Herabspielen: »sowas wie N (taugt nichts)« — hier gekoppelt mit ても + Verneinung.","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby><b>なんか</b> して いても、<ruby>食<rt>た</rt></ruby>べては いけないよ。","de":"Mit sowas wie Theater kannst du dich nicht ernähren."},"simpel":"Abwertung + »selbst wenn«: »mit sowas wie Theater …«.<br><span class='jp'><ruby>演劇<rt>えんげき</rt></ruby><b>なんか</b> しても</span>","rule":"N + なんか/なんて: spielt N herunter (abwertend oder bescheiden). Kombiniert mit ても: »selbst wenn man sowas (Unnützes) tut, …«. Vgl. das neutrale Beispiel-なんか (Punkt 66)."},{"l":30,"t":"91 · <ruby>生活<rt>せいかつ</rt></ruby>でき っこない","de":"〜っこない — klappt nie im Leben (salopp)","slots":[{"text":"そんなの","role":"cond","label":"sowas"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"っこない","role":"plain","label":"nie!"}],"gloss":"»Definitiv unmöglich« — ます-Stamm + っこない; formeller: わけがない (87).","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby>だけで <ruby>生活<rt>せいかつ</rt></ruby>でき<b>っこない</b>。","de":"Allein vom Theater kann man nie im Leben leben."},"simpel":"Saloppes »unmöglich«: »davon kann man nie leben«.<br><span class='jp'><ruby>生活<rt>せいかつ</rt></ruby>でき<b>っこない</b></span>","rule":"V<sub>ます</sub>-Stamm + っこない: emphatische Unmöglichkeit in lockerer Sprache (= 絶対に〜ない). Oft mit Potentialform: できっこない, わかりっこない."},{"l":30,"t":"92 · <ruby>大学<rt>だいがく</rt></ruby>を <ruby>出<rt>で</rt></ruby>た からといって","de":"〜からといって — nur weil … (heißt das nicht …)","slots":[{"text":"[A]","role":"cond"},{"text":"からといって","role":"actor","label":"nur weil"},{"text":"[B nicht sicher]","role":"plain"}],"gloss":"»Nur weil A, folgt nicht B« — fast immer mit verneinendem Nachsatz.","ex":{"jp":"<ruby>大学<rt>だいがく</rt></ruby>を <ruby>出<rt>で</rt></ruby>た<b>からといって</b>、いい <ruby>仕事<rt>しごと</rt></ruby>に つける とは <ruby>限<rt>かぎ</rt></ruby>らない。","de":"Nur weil man die Uni abgeschlossen hat, bekommt man nicht unbedingt einen guten Job."},"simpel":"Wehrt den Fehlschluss ab: »nur weil man die Uni abgeschlossen hat …«.<br><span class='jp'><ruby>出<rt>で</rt></ruby>た<b>からといって</b></span>","rule":"Plain + からといって + Verneinung/Einschränkung: »aus A folgt nicht automatisch B«. Standard-Partner: とは限らない (93) oder わけではない. Gesprochen: からって."},{"l":30,"t":"93 · <ruby>就職<rt>しゅうしょく</rt></ruby>できる とは<ruby>限<rt>かぎ</rt></ruby>らない","de":"〜とは限らない — nicht unbedingt / nicht garantiert","slots":[{"text":"(<ruby>必<rt>かなら</rt></ruby>ずしも)","role":"time"},{"text":"[Annahme]","role":"cond"},{"text":"とは<ruby>限<rt>かぎ</rt></ruby>らない","role":"plain","label":"nicht garantiert"}],"gloss":"»Nicht immer/unbedingt so« — es gibt Ausnahmen. Partner von からといって.","ex":{"jp":"<ruby>安定<rt>あんてい</rt></ruby>した <ruby>会社<rt>かいしゃ</rt></ruby>に <ruby>入<rt>はい</rt></ruby>れば <ruby>幸<rt>しあわ</rt></ruby>せだ<b>とは 限らない</b>。","de":"In einer sicheren Firma zu sein macht nicht unbedingt glücklich."},"simpel":"»Es ist nicht garantiert, dass …« — lässt Ausnahmen zu.<br><span class='jp'>できる<b>とは 限らない</b></span>","rule":"Plain + とは限らない: die Allgemein-Annahme gilt nicht immer. Oft mit 必ずしも (»nicht notwendigerweise«) und nach からといって (92)."},{"l":30,"t":"94 · がんこな ことといったら","de":"〜といったら — was … angeht: unglaublich! (Ausruf)","slots":[{"text":"[Eigenschaft]","role":"subj"},{"text":"といったら","role":"actor","label":"…!"},{"text":"(<ruby>言葉<rt>ことば</rt></ruby>に ならない)","role":"plain"}],"gloss":"Ausruf: »Diese …-heit — nicht zu fassen!« — positiv wie negativ.","ex":{"jp":"<ruby>父<rt>ちち</rt></ruby>の がんこな こと<b>といったら</b>、<ruby>誰<rt>だれ</rt></ruby>も <ruby>説得<rt>せっとく</rt></ruby>できない。","de":"Die Sturheit meines Vaters — da beißt sich jeder die Zähne aus."},"simpel":"Emotionaler Ausruf über eine Eigenschaft: »diese Sturheit …!«.<br><span class='jp'>がんこな こと<b>といったら</b></span>","rule":"N/〜こと + といったら: ruft eine Eigenschaft aus, die kaum in Worte zu fassen ist (Bewunderung ODER Genervtsein). Fortsetzung oft 言葉にならない/〜ほど oder offen gelassen."},{"l":30,"t":"95 · <ruby>何<rt>なに</rt></ruby>も <ruby>知<rt>し</rt></ruby>らない くせに","de":"〜くせに — obwohl … (mit Vorwurf)","slots":[{"text":"[A: obwohl]","role":"cond"},{"text":"くせに","role":"actor","label":"Vorwurf"},{"text":"[B: Kritik]","role":"plain"}],"gloss":"»Obwohl A (unverschämt!), B« — immer wertend; neutral = のに.","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby>の こと、<ruby>何<rt>なに</rt></ruby>も <ruby>知<rt>し</rt></ruby>らない<b>くせに</b>!","de":"Dabei hast du doch null Ahnung vom Theater!"},"simpel":"Vorwurfsvolles »obwohl«: »dabei hast du doch keine Ahnung!«.<br><span class='jp'><ruby>知<rt>し</rt></ruby>らない<b>くせに</b></span>","rule":"Plain (な-Adj な / N の) + くせに: »obwohl« mit Kritik/Verachtung — der Widerspruch empört den Sprecher. Meist gleiches Subjekt in beiden Teilen; auch als Satzende (知らないくせに!)."},{"l":30,"t":"96 · <ruby>子<rt>こ</rt></ruby>どもっぽい <ruby>夢<rt>ゆめ</rt></ruby>","de":"〜っぽい — wirkt wie … / -haft (hier: kindisch)","slots":[{"text":"N","role":"subj"},{"text":"っぽい","role":"actor","label":"-haft"},{"text":"N₂","role":"obj"}],"gloss":"Anschein/Neigung, wie い-Adj gebeugt. 子どもっぽい (kindisch, negativ) ≠ 子どもらしい (kindgerecht).","ex":{"jp":"<ruby>役者<rt>やくしゃ</rt></ruby>に なりたい なんて、<ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b> <ruby>夢<rt>ゆめ</rt></ruby>だと <ruby>言<rt>い</rt></ruby>われた。","de":"Schauspielerin werden? Das nannte er einen kindischen Traum."},"simpel":"<b>っぽい</b> macht »-haft«-Adjektive: »ein kindischer Traum«.<br><span class='jp'><ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b> <ruby>夢<rt>ゆめ</rt></ruby></span>","rule":"N/V<sub>ます</sub>/Adj-Stamm + っぽい: »hat den Anschein/die Neigung von« — wird wie ein い-Adjektiv gebeugt. 子どもっぽい ist (anders als 子どもらしい!) meist negativ."},{"l":31,"t":"97 · おじさんの せいですよ","de":"〜のせいだ — wegen … / … ist schuld","slots":[{"text":"N の","role":"subj","label":"Schuldiger"},{"text":"せいだ","role":"plain","label":"ist schuld"}],"gloss":"»N ist schuld (an etwas Schlechtem)« — Gegenstück zu おかげで.","ex":{"jp":"かぜを ひいたのは、<ruby>薄着<rt>うすぎ</rt></ruby>の<b>せいですよ</b>。","de":"Dass du dich erkältet hast, liegt an der dünnen Kleidung."},"simpel":"Schuldzuweisung: »das ist Onkels Schuld«.<br><span class='jp'>おじさんの<b>せいですよ</b></span>","rule":"N + の + せいだ/せいで: nennt vorwurfsvoll die Ursache eines schlechten Ergebnisses. Unsicher: せいか (»vielleicht wegen«); positiv: おかげで (51)."},{"l":31,"t":"98 · ゆきの ことだから","de":"〜のことだから — so wie wir … kennen, bestimmt …","slots":[{"text":"[Person] の","role":"subj","label":"bekannt wie"},{"text":"ことだから","role":"actor","label":"typisch!"},{"text":"[Vermutung]","role":"plain"}],"gloss":"Charakterbasierte Vermutung über eine bekannte Person.","ex":{"jp":"がんばりやの ゆきの <b>ことだから</b>、すぐ <ruby>元気<rt>げんき</rt></ruby>に なるよ。","de":"So eine Kämpferin wie Yuki ist bestimmt schnell wieder auf den Beinen."},"simpel":"Vermutung aus bekanntem Charakter: »typisch Yuki — bestimmt …«.<br><span class='jp'>ゆきの <b>ことだから</b></span>","rule":"[Person] + の + ことだから: aus dem beiden Gesprächspartnern bekannten Charakter wird eine Vermutung abgeleitet. Nachsatz: だろう/はずだ/に違いない."},{"l":31,"t":"99 · <ruby>散歩<rt>さんぽ</rt></ruby>でも したら どう?","de":"N でも + 〜たらどう — wie wär's, wenn du mal …?","slots":[{"text":"N でも","role":"obj","label":"z. B."},{"text":"V<sub>たら</sub>","role":"verb"},{"text":"どう?","role":"plain","label":"wie wär's?"}],"gloss":"Unaufdringlicher Rat: »Wie wäre es, wenn du mal … (oder so)?«","ex":{"jp":"<ruby>気分<rt>きぶん</rt></ruby><ruby>転換<rt>てんかん</rt></ruby>に、<ruby>散歩<rt>さんぽ</rt></ruby><b>でも したら どう</b>?","de":"Wie wär's zur Abwechslung mal mit einem Spaziergang?"},"simpel":"Sanfter Vorschlag: »mach doch mal z. B. einen Spaziergang«.<br><span class='jp'><ruby>散歩<rt>さんぽ</rt></ruby><b>でも したら どう</b>?</span>","rule":"N + でも (»z. B./oder so«) + V<sub>たら</sub> + どう(ですか): unaufdringlicher Ratschlag. でも hält den Vorschlag offen, たらどう fragt nach der Reaktion."},{"l":31,"t":"100 · <ruby>寝<rt>ね</rt></ruby>て ばかりは いられない","de":"〜てばかりはいられない — kann nicht ewig nur …","slots":[{"text":"V<sub>テ</sub>","role":"verb"},{"text":"ばかりは","role":"actor","label":"nur"},{"text":"いられない","role":"plain","label":"geht nicht länger"}],"gloss":"»Es geht nicht an, weiter nur zu …« — Aufbruchssignal.","ex":{"jp":"いつまでも <ruby>寝<rt>ね</rt></ruby>て<b>ばかりは いられない</b>。","de":"Ich kann nicht ewig nur im Bett liegen."},"simpel":"»Ich kann nicht ewig nur im Bett liegen!«<br><span class='jp'><ruby>寝<rt>ね</rt></ruby>て<b>ばかりは いられない</b></span>","rule":"V<sub>テ</sub> + ばかりはいられない (auch ばかりもいられない): man kann/darf nicht länger nur eine Sache tun — Zeit zu handeln. Kombiniert てばかり (41) mit いられない."},{"l":31,"t":"101 · <ruby>生活<rt>せいかつ</rt></ruby>を <ruby>変<rt>か</rt></ruby>える ことにした","de":"〜ことにする — beschließen, zu …","slots":[{"text":"V<sub>辞書</sub>","role":"verb"},{"text":"ことにした","role":"plain","label":"habe beschlossen"}],"gloss":"Eigene Entscheidung; Gewohnheit ことにしている; von außen: ことになった.","ex":{"jp":"これからは <ruby>規則正<rt>きそくただ</rt></ruby>しい <ruby>生活<rt>せいかつ</rt></ruby>を する<b>ことにした</b>。","de":"Ich habe beschlossen, ab jetzt geregelt zu leben."},"simpel":"Eigener Entschluss: »ich habe beschlossen, mein Leben zu ändern«.<br><span class='jp'><ruby>変<rt>か</rt></ruby>える<b>ことにした</b></span>","rule":"V<sub>辞書/ない</sub> + ことにする: bewusste eigene Entscheidung. ことにしている = zur Gewohnheit gemachte Entscheidung. Fremdbestimmt: ことになる (»es wurde beschlossen«)."},{"l":31,"t":"102 · テレビを つけっぱなし","de":"〜っぱなし — (an)gelassen und so belassen","slots":[{"text":"N を","role":"obj"},{"text":"V<sub>マス</sub>","role":"verb"},{"text":"っぱなし","role":"plain","label":"gelassen"}],"gloss":"»Getan und so belassen« (nachlässig) oder »pausenlos« — ます-Stamm + っぱなし.","ex":{"jp":"テレビを つけ<b>っぱなし</b>で <ruby>寝<rt>ね</rt></ruby>て しまった。","de":"Ich bin mit laufendem Fernseher eingeschlafen."},"simpel":"Etwas tun und (nachlässig) so lassen: »Fernseher angelassen«.<br><span class='jp'>つけ<b>っぱなし</b></span>","rule":"V<sub>ます</sub>-Stamm + っぱなし: man tut etwas und lässt es dann so (oft nachlässig: つけっぱなし, 開けっぱなし) — oder ein Zustand dauert ununterbrochen (立ちっぱなし)."},{"l":31,"t":"103 · <ruby>部屋<rt>へや</rt></ruby><ruby>中<rt>じゅう</rt></ruby> ごみだらけ","de":"〜だらけ — voller … (unangenehm)","slots":[{"text":"<ruby>部屋<rt>へや</rt></ruby><ruby>中<rt>じゅう</rt></ruby>","role":"subj","label":"überall"},{"text":"ごみ","role":"obj"},{"text":"だらけ","role":"plain","label":"voller"}],"gloss":"»Übersät mit (Unangenehmem)« — ごみだらけ, 間違いだらけ; fast immer negativ.","ex":{"jp":"<ruby>部屋<rt>へや</rt></ruby><ruby>中<rt>じゅう</rt></ruby> ごみ<b>だらけ</b>じゃない!","de":"Dein ganzes Zimmer ist ja voller Müll!"},"simpel":"Übervoll mit Unangenehmem: »das ganze Zimmer voller Müll«.<br><span class='jp'>ごみ<b>だらけ</b></span>","rule":"N + だらけ: übersät/voll von etwas Negativem (ごみ, ほこり, 間違い, どろ). Mit N中 (»das ganze N«) kombiniert: 部屋中ごみだらけ."},{"l":31,"t":"104 · <ruby>何<rt>なに</rt></ruby>も <ruby>食<rt>た</rt></ruby>べる <ruby>気<rt>き</rt></ruby>が しない","de":"〜気がする/しない — das Gefühl haben (keine Lust verspüren)","slots":[{"text":"<ruby>何<rt>なに</rt></ruby>も","role":"obj"},{"text":"V<sub>辞書</sub> <ruby>気<rt>き</rt></ruby>が","role":"verb","label":"Lust auf"},{"text":"しない","role":"plain","label":"fehlt"}],"gloss":"»Kein innerer Antrieb zu V« bzw. positiv: vage Ahnung (気がする).","ex":{"jp":"<ruby>熱<rt>ねつ</rt></ruby>の せいか、<ruby>何<rt>なに</rt></ruby>も <ruby>食<rt>た</rt></ruby>べる <ruby>気<rt>き</rt></ruby>が <b>しない</b>。","de":"Vielleicht wegen des Fiebers ist mir nach gar nichts zu essen."},"simpel":"»Mir ist nicht nach Essen« — <b>気がしない</b>.<br><span class='jp'><ruby>食<rt>た</rt></ruby>べる <ruby>気<rt>き</rt></ruby>が <b>しない</b></span>","rule":"V<sub>辞書</sub> + 気がする/気がしない: das (unwillkürliche) Gefühl, etwas tun zu wollen — verneint: keinerlei Antrieb. Auch Vermutungs-気がする (»mir ist, als ob«)."},{"l":31,"t":"105 · <ruby>元気<rt>げんき</rt></ruby>に なったりして","de":"〜たりして — am Ende noch … (scherzhafte Vermutung)","slots":[{"text":"[Möglichkeit]","role":"cond"},{"text":"たりして","role":"plain","label":"(haha, oder?)"}],"gloss":"Scherzhafte Spekulation am Satzende — lässt offen, ob man es ernst meint.","ex":{"jp":"<ruby>明日<rt>あした</rt></ruby>に は けろっと <ruby>元気<rt>げんき</rt></ruby>に なっ<b>たりして</b>。","de":"Und morgen bist du am Ende wieder putzmunter … haha."},"simpel":"Halb im Scherz: »und am Ende bist du plötzlich wieder fit …«.<br><span class='jp'><ruby>元気<rt>げんき</rt></ruby>に なっ<b>たりして</b></span>","rule":"V<sub>たり</sub> + して (Satzende): wirft halb scherzhaft eine Möglichkeit in den Raum — »wär ja möglich … haha (oder doch?)«. Reine Gesprächsfloskel."},{"l":31,"t":"106 · ゆきらしくないなあ","de":"〜らしい/らしくない — (un)typisch für …","slots":[{"text":"[Person]","role":"subj"},{"text":"らしくない","role":"plain","label":"untypisch"}],"gloss":"典型-らしい: »(un)typisch für N« — wie い-Adj gebeugt; ≠ っぽい (96, Anschein).","ex":{"jp":"<ruby>弱気<rt>よわき</rt></ruby>な ことを <ruby>言<rt>い</rt></ruby>うなんて、ゆき<b>らしくない</b>なあ。","de":"So kleinlaut — das sieht Yuki gar nicht ähnlich."},"simpel":"»Das sieht Yuki gar nicht ähnlich.«<br><span class='jp'>ゆき<b>らしくない</b>なあ</span>","rule":"N + らしい: »typisch N, wie es sich für N gehört« (positiv). Verneint らしくない: »untypisch, passt nicht zu«. Zweite Lesart: Plain + らしい = »anscheinend« (Hörensagen)."},{"l":31,"t":"107 · お<ruby>母<rt>かあ</rt></ruby>さんかと <ruby>思<rt>おも</rt></ruby>った","de":"〜かと思った — ich dachte (schon), es sei …","slots":[{"text":"N","role":"subj","label":"Verwechslung"},{"text":"かと<ruby>思<rt>おも</rt></ruby>った","role":"plain","label":"dachte ich schon"}],"gloss":"Aufgeklärter Kurz-Irrtum oder Schreck-Übertreibung (死ぬかと思った).","ex":{"jp":"<ruby>声<rt>こえ</rt></ruby>が そっくりで、お<ruby>母<rt>かあ</rt></ruby>さん<b>かと 思った</b>よ。","de":"Die Stimme war so ähnlich — ich dachte schon, es sei deine Mutter."},"simpel":"Kurzer Irrtum: »ich dachte schon, es wäre deine Mutter«.<br><span class='jp'>お<ruby>母<rt>かあ</rt></ruby>さん<b>かと 思った</b></span>","rule":"N/Plain + かと思った: man hielt etwas kurz für etwas anderes — der Irrtum hat sich eben aufgeklärt. Auch erleichtert/erschrocken: 死ぬかと思った »ich dachte, ich sterbe«."},{"l":31,"t":"108 · アイスクリームとか みかんとか","de":"〜とか〜とか — … und … (offene Aufzählung)","slots":[{"text":"N とか","role":"obj","label":"z. B."},{"text":"N とか","role":"obj","label":"und"},{"text":"[Aussage]","role":"plain"}],"gloss":"Lockere, offene Beispiel-Liste — die Auswahl ist nicht abschließend.","ex":{"jp":"アイスクリーム<b>とか</b> みかん<b>とか</b>、<ruby>食<rt>た</rt></ruby>べたい <ruby>物<rt>もの</rt></ruby> ある?","de":"Eis, Mandarinen oder so — hast du auf irgendwas Appetit?"},"simpel":"Lockeres Aufzählen: »Eis, Mandarinen und sowas«.<br><span class='jp'>アイス<b>とか</b> みかん<b>とか</b></span>","rule":"N とか N とか (V<sub>Plain</sub> とか): unvollständige Beispiel-Aufzählung im Gespräch (»zum Beispiel … und …«). Schriftlicher: 〜や〜など."},{"l":31,"t":"109 · <ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>の ついでに","de":"〜のついでに — bei der Gelegenheit von …","slots":[{"text":"N の","role":"cond","label":"Hauptsache"},{"text":"ついでに","role":"actor","label":"nebenbei"},{"text":"[Nebensache]","role":"plain"}],"gloss":"»Wo ich schon dabei bin/war« — Gelegenheits-Anhängsel.","ex":{"jp":"<ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>の<b>ついでに</b>、お<ruby>見舞<rt>みま</rt></ruby>いに <ruby>寄<rt>よ</rt></ruby>って くれたの?","de":"Du hast beim Einkaufen einen Krankenbesuch drangehängt?"},"simpel":"Nebenbei miterledigt: »beim Einkaufen (gleich mit)«.<br><span class='jp'><ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>の<b>ついでに</b></span>","rule":"N + の / V<sub>辞書・た</sub> + ついでに: die Gelegenheit einer Haupthandlung für eine Nebenhandlung nutzen. Haupthandlung zuerst, Nebensache folgt."},{"l":31,"t":"110 · <ruby>何<rt>なに</rt></ruby>か あったに<ruby>違<rt>ちが</rt></ruby>いない","de":"〜に違いない — es muss (ganz sicher) … sein","slots":[{"text":"[Indiz] →","role":"cond"},{"text":"[Schluss]","role":"verb"},{"text":"に<ruby>違<rt>ちが</rt></ruby>いない","role":"plain","label":"muss so sein"}],"gloss":"Sichere Schlussfolgerung aus Indizien — formeller als に決まってる.","ex":{"jp":"<ruby>元気<rt>げんき</rt></ruby>が ない。<ruby>何<rt>なに</rt></ruby>か あった<b>に違いない</b>。","de":"Sie ist so still — da muss etwas vorgefallen sein."},"simpel":"Starke Schlussfolgerung: »da muss etwas passiert sein«.<br><span class='jp'><ruby>何<rt>なに</rt></ruby>か あった<b>に違いない</b></span>","rule":"Plain + に違いない (な-Adj/N ohne だ): der Sprecher ist sich aus Indizien (fast) sicher. Salopp: に決まってる (36)."},{"l":31,"t":"111 · これほど つらい かぜは ひいた ことがない","de":"これほど〜ことがない — noch nie so … (Erfahrungs-Superlativ)","slots":[{"text":"これほど","role":"time","label":"so sehr"},{"text":"[Adj + N]","role":"obj"},{"text":"V<sub>た</sub>ことがない","role":"plain","label":"noch nie"}],"gloss":"Erfahrungs-Superlativ: »noch nie habe ich ein derart …es N erlebt«.","ex":{"jp":"これ<b>ほど</b> つらい かぜは ひいた <b>ことがない</b>よ。","de":"So eine üble Erkältung hatte ich noch nie."},"simpel":"»So eine schlimme Erkältung hatte ich noch nie.«<br><span class='jp'>これ<b>ほど</b> つらい かぜは ひいた <b>ことがない</b></span>","rule":"これほど/こんなに + [Adj+N] + V<sub>た</sub>ことがない: die aktuelle Erfahrung übertrifft alles Bisherige. Kombination aus Grad-ほど (7) und Erfahrungs-たことがある."},{"l":31,"t":"112 · ゆき<ruby>抜<rt>ぬ</rt></ruby>きでは <ruby>始<rt>はじ</rt></ruby>められない","de":"N 抜きで(は) — ohne … (geht es nicht) (+Plus: てしかたがない)","slots":[{"text":"N","role":"subj","label":"das Fehlende"},{"text":"<ruby>抜<rt>ぬ</rt></ruby>きでは","role":"actor","label":"ohne"},{"text":"〜ない","role":"plain","label":"geht nicht"}],"gloss":"»Ohne N (ausgelassen) …« — mit は + Verneinung: unverzichtbar.","ex":{"jp":"<ruby>文化祭<rt>ぶんかさい</rt></ruby>の <ruby>劇<rt>げき</rt></ruby>は、ゆき<b>抜きでは</b> <ruby>始<rt>はじ</rt></ruby>められないよ。","de":"Das Theaterstück beim Schulfest können wir ohne Yuki nicht anfangen."},"simpel":"<b>抜きで</b> = »ohne (das sonst Übliche)«.<br><span class='jp'>ゆき<b>抜きでは</b> <ruby>始<rt>はじ</rt></ruby>められない</span> = „ohne Yuki können wir nicht anfangen“","rule":"N + 抜きで(は/に): unter Weglassung von N — 抜きでは + Verneinung: »ohne N geht es nicht«. Auch wörtlich: わさび抜きで »ohne Wasabi«. +Plus: 〜てしかたがない (= てしょうがない, 113)."},{"l":31,"t":"113 · <ruby>練習<rt>れんしゅう</rt></ruby>したくて しょうがない","de":"〜てしょうがない — unerträglich … / kann es kaum erwarten","slots":[{"text":"V<sub>たくて</sub>","role":"cond","label":"will so sehr"},{"text":"しょうがない","role":"plain","label":"kaum auszuhalten"}],"gloss":"Unbändigbares Gefühl — müde/heiß/sehnsüchtig/wollen + てしょうがない.","ex":{"jp":"<ruby>早<rt>はや</rt></ruby>く みんなと <ruby>練習<rt>れんしゅう</rt></ruby>したくて<b>しょうがない</b>。","de":"Ich kann es kaum erwarten, wieder mit allen zu proben."},"simpel":"Übermächtiges Gefühl: »ich will unbedingt wieder proben!«.<br><span class='jp'>したくて<b>しょうがない</b></span>","rule":"Gefühls-て-Form + しょうがない/しかたがない/たまらない: das Gefühl ist nicht zu bändigen. Mit 〜たくて: brennendes Wollen. Das große Finale des Buchs 😊."}];
